-- Poems batch 457
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-58','玩半開花贈皇甫郎中','白居易','唐','御定全唐诗','yuding','','[]','勿訝春來晚，無嫌花發遲。人憐全盛日，我愛半開時。',168,'御定全唐詩/json/454.json','["勿訝春來晚，無嫌花發遲。人憐全盛日，我愛半開時。", "紫蠟黏為蒂，紅蘇點作蕤。成都新夾纈，梁漢碎胭脂。", "樹杪真珠顆，牆頭小女兒。淺深妝駁落，高下火參差。", "蝶戲爭香朵，鶯啼選穩枝。好教郎作伴，合共酒相隨。", "醉玩無勝此，狂嘲更讓誰。猶殘少年興，不似老人詩。", "西日憑輕照，東風莫殺吹。明朝應爛漫，後夜更離披。", "林下遙相憶，尊前暗有期。銜杯嚼蕊思，唯我與君知。"]'),
('yuding-59','池邊','白居易','唐','御定全唐诗','yuding','','[]','柳老香絲宛，荷新鈿扇圓。殘春深樹裏，斜日小樓前。',48,'御定全唐詩/json/454.json','["柳老香絲宛，荷新鈿扇圓。殘春深樹裏，斜日小樓前。", "醉遣收杯杓，閑聽理管弦。池邊更無事，看補採蓮船。"]'),
('yuding-60','家釀新熟每嘗輒醉妻侄等勸令少飲因成長句以諭之','白居易','唐','御定全唐诗','yuding','','[]','君應怪我朝朝飲，不說向君君不知。身上幸無疼痛處，',40,'御定全唐詩/json/454.json','["君應怪我朝朝飲，不說向君君不知。身上幸無疼痛處，", "六十三翁頭雪白，假如醒黠欲何為。"]'),
('yuding-61','送常秀才下第東歸','白居易','唐','御定全唐诗','yuding','','[]','東歸多旅恨，西上少知音。寒食看花眼，春風落日心。',48,'御定全唐詩/json/454.json','["東歸多旅恨，西上少知音。寒食看花眼，春風落日心。", "百憂當二月，一醉直千金。到處公卿席，無辭酒醆深。"]'),
('yuding-62','且遊','白居易','唐','御定全唐诗','yuding','','[]','手裏一杯滿，心中百事休。春應唯仰醉，老更不禁愁。',48,'御定全唐詩/json/454.json','["手裏一杯滿，心中百事休。春應唯仰醉，老更不禁愁。", "弄水回船尾，尋花信馬頭。眼看筋力減，遊得且須遊。"]'),
('yuding-63','題王家莊臨水柳亭','白居易','唐','御定全唐诗','yuding','','[]','弱柳緣堤種，虛亭壓水開。條疑逐風去，波欲上階來。',48,'御定全唐詩/json/454.json','["弱柳緣堤種，虛亭壓水開。條疑逐風去，波欲上階來。", "翠羽偷魚入，紅腰學舞回。春愁正無緒，爭不盡殘杯。"]'),
('yuding-64','題令狐家木蘭花','白居易','唐','御定全唐诗','yuding','','[]','膩如玉指塗朱粉，光似金刀剪紫霞。',32,'御定全唐詩/json/454.json','["膩如玉指塗朱粉，光似金刀剪紫霞。", "從此時時春夢裏，應添一樹女郎花。"]'),
('yuding-65','拜表回閒遊','白居易','唐','御定全唐诗','yuding','','[]','玉佩金章紫花綬，紵衫藤帶白綸巾。晨興拜表稱朝士，',48,'御定全唐詩/json/454.json','["玉佩金章紫花綬，紵衫藤帶白綸巾。晨興拜表稱朝士，", "八關淨戒齋銷日，一曲狂歌醉送春。酒肆法堂方丈室，"]'),
('yuding-66','西街渠中，種蓮壘石，頗有幽致，偶題小樓','白居易','唐','御定全唐诗','yuding','','[]','朱檻低牆上，清流小閣前。雇人栽菡萏，買石造潺湲。',72,'御定全唐詩/json/454.json','["朱檻低牆上，清流小閣前。雇人栽菡萏，買石造潺湲。", "影落江心月，聲移穀口泉。閑看捲簾坐，醉聽掩窗眠。", "路笑淘官水，家愁費料錢。是非君莫問，一對一翛然。"]'),
('yuding-67','晚春閒居楊工部寄詩、楊常州寄茶同到因以長句答之','白居易','唐','御定全唐诗','yuding','','[]','宿酲寂寞眠初起，春意闌珊日又斜。勸我加餐因早筍，',40,'御定全唐詩/json/454.json','["宿酲寂寞眠初起，春意闌珊日又斜。勸我加餐因早筍，", "兄弟東西官職冷，門前車馬向誰家。"]'),
('yuding-68','玉泉寺南三裏澗下多深紅躑躅繁豔殊常感惜題詩以示遊者','白居易','唐','御定全唐诗','yuding','','[]','玉泉南澗花奇怪，不似花叢似火堆。今日多情唯我到，',40,'御定全唐詩/json/454.json','["玉泉南澗花奇怪，不似花叢似火堆。今日多情唯我到，", "猶有一般辜負事，不將歌舞管弦來。"]'),
('yuding-69','早服雲母散','白居易','唐','御定全唐诗','yuding','','[]','曉服雲英漱井華，寥然身若在煙霞。藥銷日晏三匙飯，',40,'御定全唐詩/json/454.json','["曉服雲英漱井華，寥然身若在煙霞。藥銷日晏三匙飯，", "淨名事理人難解，身不出家心出家。"]'),
('yuding-70','三月晦日晚聞鳥聲','白居易','唐','御定全唐诗','yuding','','[]','晚來林鳥語殷勤，似惜風光說向人。遣脫破袍勞報暖，',24,'御定全唐詩/json/454.json','["晚來林鳥語殷勤，似惜風光說向人。遣脫破袍勞報暖，"]'),
('yuding-71','早夏游平原回','白居易','唐','御定全唐诗','yuding','','[]','夏早日初長，南風草木香。肩輿頗平穩，澗路甚清涼。',48,'御定全唐詩/json/454.json','["夏早日初長，南風草木香。肩輿頗平穩，澗路甚清涼。", "紫蕨行看采，青梅旋摘嘗。療饑兼解渴，一醆冷雲漿。"]'),
('yuding-72','宿天竺寺回','白居易','唐','御定全唐诗','yuding','','[]','野寺經三宿，都城複一還。家仍念婚嫁，身尚系官班。',48,'御定全唐詩/json/454.json','["野寺經三宿，都城複一還。家仍念婚嫁，身尚系官班。", "蕭灑秋臨水，沉吟晚下山。長閑猶未得，逐日且偷閒。"]'),
('yuding-73','侍中晉公欲到東洛先蒙書問期宿龍門思往感今輒獻長句','白居易','唐','御定全唐诗','yuding','','[]','昔蒙興化池頭送，今許龍門潭上期。聚散但慚長見念，',40,'御定全唐詩/json/454.json','["昔蒙興化池頭送，今許龍門潭上期。聚散但慚長見念，", "聞說風情筋力在，只如初破蔡州時。"]'),
('yuding-74','奉和晉公侍中蒙除留守行及洛師感悅發中斐然成詠之作','白居易','唐','御定全唐诗','yuding','','[]','鸞鳳翱翔在寥廓，貂蟬蕭灑出埃塵。致成堯舜升平代，',40,'御定全唐詩/json/454.json','["鸞鳳翱翔在寥廓，貂蟬蕭灑出埃塵。致成堯舜升平代，", "商山老皓雖休去，終是留侯門下人。"]'),
('yuding-75','送劉五司馬赴任硤州兼寄崔使君','白居易','唐','御定全唐诗','yuding','','[]','位下才高多怨天，劉兄道勝獨恬然。貧於揚子兩三倍，',40,'御定全唐詩/json/454.json','["位下才高多怨天，劉兄道勝獨恬然。貧於揚子兩三倍，", "郡丞自合當優禮，何況夷陵太守賢。"]'),
('yuding-76','菩提寺上方晚眺','白居易','唐','御定全唐诗','yuding','','[]','樓閣高低樹淺深，山光水色暝沉沉。嵩煙半卷青綃幕，',40,'御定全唐詩/json/454.json','["樓閣高低樹淺深，山光水色暝沉沉。嵩煙半卷青綃幕，", "誰知不離簪纓內，長得逍遙自在心。"]'),
('yuding-77','楊柳枝詞八首','白居易','唐','御定全唐诗','yuding','','[]','六麼水調家家唱，白雪梅花處處吹。',256,'御定全唐詩/json/454.json','["六麼水調家家唱，白雪梅花處處吹。", "古歌舊曲君休聽，聽取新翻楊柳枝。", "陶令門前四五樹，亞夫營裏百千條。", "何似東都正二月，黃金枝映洛陽橋。", "依依褭褭複青青，句引春風無限情。", "白雪花繁空撲地，綠絲條弱不勝鶯。", "紅板江橋青酒旗，館娃宮暖日斜時。", "可憐雨歇東風定，萬樹千條各自垂。", "蘇州楊柳任君誇，更有錢唐勝館娃。", "若解多情尋小小，綠楊深處是蘇家。", "蘇家小女舊知名，楊柳風前別有情。", "剝條盤作銀環樣，卷葉吹為玉笛聲。", "葉含濃露如啼眼，枝嫋輕風似舞腰。", "小樹不禁攀折苦，乞君留取兩三條。", "人言柳葉似愁眉，更有愁腸似柳絲。", "柳絲挽斷腸牽斷，彼此應無續得期。"]'),
('yuding-0','讀老子','白居易','唐','御定全唐诗','yuding','','[]','言者不如知者默，此語吾聞於老君。',32,'御定全唐詩/json/455.json','["言者不如知者默，此語吾聞於老君。", "若道老君是知者，緣何自著五千文。"]'),
('yuding-1','讀莊子','白居易','唐','御定全唐诗','yuding','','[]','莊生齊物同歸一，我道同中有不同。',32,'御定全唐詩/json/455.json','["莊生齊物同歸一，我道同中有不同。", "遂性逍遙雖一致，鸞凰終校勝蛇蟲。"]'),
('yuding-2','讀禪經','白居易','唐','御定全唐诗','yuding','','[]','須知諸相皆非相，若住無餘卻有餘。言下忘言一時了，',40,'御定全唐詩/json/455.json','["須知諸相皆非相，若住無餘卻有餘。言下忘言一時了，", "攝動是禪禪是動，不禪不動即如如。"]'),
('yuding-3','感興二首','白居易','唐','御定全唐诗','yuding','','[]','吉凶禍福有來由，但要深知不要憂。只見火光燒潤屋，',80,'御定全唐詩/json/455.json','["吉凶禍福有來由，但要深知不要憂。只見火光燒潤屋，", "雖異匏瓜難不食，大都食足早宜休。", "魚能深入寧憂釣，鳥解高飛豈觸羅。熱處先爭炙手去，", "我有一言君記取，世間自取苦人多。"]'),
('yuding-4','問鶴','白居易','唐','御定全唐诗','yuding','','[]','烏鳶爭食雀爭窠，獨立池邊風雪多。',32,'御定全唐詩/json/455.json','["烏鳶爭食雀爭窠，獨立池邊風雪多。", "盡日蹋冰翹一足，不鳴不動意如何。"]'),
('yuding-5','代鶴答','白居易','唐','御定全唐诗','yuding','','[]','鷹爪攫雞雞肋折，鶻拳蹴雁雁頭垂。',32,'御定全唐詩/json/455.json','["鷹爪攫雞雞肋折，鶻拳蹴雁雁頭垂。", "何如斂翅水邊立，飛上雲松棲穩枝。"]'),
('yuding-6','閑臥有所思二首','白居易','唐','御定全唐诗','yuding','','[]','向夕搴簾臥枕琴，微涼入戶起開襟。偶因明月清風夜，',80,'御定全唐詩/json/455.json','["向夕搴簾臥枕琴，微涼入戶起開襟。偶因明月清風夜，", "始知洛下分司坐，一日安閒直萬金。", "權門要路是身災，散地閒居少禍胎。今日憐君嶺南去，", "大抵吉凶多自致，李斯一去二疏回。"]'),
('yuding-7','喜閑','白居易','唐','御定全唐诗','yuding','','[]','蕭灑伊嵩下，優遊黃綺間。未曾一日悶，已得六年閑。',72,'御定全唐詩/json/455.json','["蕭灑伊嵩下，優遊黃綺間。未曾一日悶，已得六年閑。", "魚鳥為徒侶，煙霞是往還。伴僧禪閉目，迎客笑開顏。", "興發宵遊寺，慵時晝掩關。夜來風月好，悔不宿香山。"]'),
('yuding-8','詩酒琴人例多薄命予酷好三事雅當此科而所得已多為幸斯甚偶成狂詠聊寫愧懷','白居易','唐','御定全唐诗','yuding','','[]','愛琴愛酒愛詩客，多賤多窮多苦辛。中散步兵終不貴，',48,'御定全唐詩/json/455.json','["愛琴愛酒愛詩客，多賤多窮多苦辛。中散步兵終不貴，", "只合飄零隨草木，誰教淩厲出風塵。榮名厚祿二千石，"]'),
('yuding-9','寄明州于駙馬使君三絕句','白居易','唐','御定全唐诗','yuding','','[]','有花有酒有笙歌，其奈難逢親故何。',96,'御定全唐詩/json/455.json','["有花有酒有笙歌，其奈難逢親故何。", "近海饒風春足雨，白須太守悶時多。", "平陽音樂隨都尉，留滯三年在浙東。", "吳越聲邪無法用，莫教偷入管弦中。", "何郎小妓歌喉好，嚴老呼為一串珠。", "海味腥鹹損聲氣，聽看猶得斷腸無。"]'),
('yuding-10','閑臥','白居易','唐','御定全唐诗','yuding','','[]','薄食當齋戒，散班同隱淪。佛容為弟子，天許作閒人。',48,'御定全唐詩/json/455.json','["薄食當齋戒，散班同隱淪。佛容為弟子，天許作閒人。", "唯置床臨水，都無物近身。清風散發臥，兼不要紗巾。"]'),
('yuding-11','春早秋初，因時即事，兼寄浙東李侍郎','白居易','唐','御定全唐诗','yuding','','[]','春早秋初晝夜長，可憐天氣好年光。和風細動簾帷暖，',48,'御定全唐詩/json/455.json','["春早秋初晝夜長，可憐天氣好年光。和風細動簾帷暖，", "閑從蕙草侵階綠，靜任槐花滿地黃。理曲管弦聞後院，"]'),
('yuding-12','新秋喜涼','白居易','唐','御定全唐诗','yuding','','[]','過得炎蒸月，尤宜老病身。衣裳朝不潤，枕簟夜相親。',48,'御定全唐詩/json/455.json','["過得炎蒸月，尤宜老病身。衣裳朝不潤，枕簟夜相親。", "樓月纖纖早，波風嫋嫋新。光陰與時節，先感是詩人。"]'),
('yuding-13','初夏閑吟，兼呈韋賓客','白居易','唐','御定全唐诗','yuding','','[]','孟夏清和月，東都閒散官。體中無病痛，眼下未饑寒。',72,'御定全唐詩/json/455.json','["孟夏清和月，東都閒散官。體中無病痛，眼下未饑寒。", "世事聞常悶，交遊見即歡。杯觴留客切，妓樂取人寬。", "雪鬢隨身老，雲心著處安。此中殊有味，試說向君看。"]'),
('yuding-14','哭崔二十四常侍','白居易','唐','御定全唐诗','yuding','','[]','貂冠初別九重門，馬鬣新封四尺墳。薤露歌詞非白雪，',40,'御定全唐詩/json/455.json','["貂冠初別九重門，馬鬣新封四尺墳。薤露歌詞非白雪，", "莫道高風無繼者，一千年內有崔君。"]'),
('yuding-15','奉酬侍中夏中雨後游城南莊見示八韻','白居易','唐','御定全唐诗','yuding','','[]','島樹間林巒，雲收雨氣殘。四山嵐色重，五月水聲寒。',96,'御定全唐詩/json/455.json','["島樹間林巒，雲收雨氣殘。四山嵐色重，五月水聲寒。", "老鶴兩三隻，新篁千萬竿。化成天竺寺，移得子陵灘。", "心覺閑彌貴，身緣健更歡。帝將風後待，人作謝公看。", "甪裏年雖老，高陽興未闌。佳辰不見召，爭免趁杯盤。"]'),
('yuding-16','送兗州崔大夫駙馬赴鎮','白居易','唐','御定全唐诗','yuding','','[]','戚裏誇為賢駙馬，儒家認作好詩人。',32,'御定全唐詩/json/455.json','["戚裏誇為賢駙馬，儒家認作好詩人。", "魯侯不得辜風景，沂水年年有暮春。"]'),
('yuding-17','少年問','白居易','唐','御定全唐诗','yuding','','[]','少年怪我問如何，何事朝朝醉複歌。',32,'御定全唐詩/json/455.json','["少年怪我問如何，何事朝朝醉複歌。", "號作樂天應不錯，憂愁時少樂時多。"]'),
('yuding-18','問少年','白居易','唐','御定全唐诗','yuding','','[]','千首詩堆青玉案，十分酒寫白金盂。',32,'御定全唐詩/json/455.json','["千首詩堆青玉案，十分酒寫白金盂。", "回頭卻問諸年少，作個狂夫得了無。"]'),
('yuding-19','代琵琶弟子謝女師曹供奉寄新調弄譜','白居易','唐','御定全唐诗','yuding','','[]','琵琶師在九重城，忽得書來喜且驚。一紙展看非舊譜，',40,'御定全唐詩/json/455.json','["琵琶師在九重城，忽得書來喜且驚。一紙展看非舊譜，", "珠顆淚沾金捍撥，紅妝弟子不勝情。"]'),
('yuding-20','代林園戲贈','白居易','唐','御定全唐诗','yuding','','[]','南院今秋遊宴少，西坊近日往來頻。',32,'御定全唐詩/json/455.json','["南院今秋遊宴少，西坊近日往來頻。", "假如宰相池亭好，作客何如作主人。"]'),
('yuding-21','戲答林園','白居易','唐','御定全唐诗','yuding','','[]','豈獨西坊來往頻，偷閒處處作遊人。',32,'御定全唐詩/json/455.json','["豈獨西坊來往頻，偷閒處處作遊人。", "衡門雖是棲遲地，不可終朝鎖老身。"]'),
('yuding-22','重戲贈','白居易','唐','御定全唐诗','yuding','','[]','集賢池館從他盛，履道林亭勿自輕。',32,'御定全唐詩/json/455.json','["集賢池館從他盛，履道林亭勿自輕。", "往往歸來嫌窄小，年年為主莫無情。"]'),
('yuding-23','重戲答','白居易','唐','御定全唐诗','yuding','','[]','小水低亭自可親，大池高館不關身。',32,'御定全唐詩/json/455.json','["小水低亭自可親，大池高館不關身。", "林園莫妒裴家好，憎故憐新豈是人。"]'),
('yuding-24','早秋登天宮寺閣贈諸客','白居易','唐','御定全唐诗','yuding','','[]','天宮閣上醉蕭辰，絲管閑聽酒慢巡。',32,'御定全唐詩/json/455.json','["天宮閣上醉蕭辰，絲管閑聽酒慢巡。", "為向涼風清景道，今朝屬我兩三人。"]'),
('yuding-25','曉上天津橋閑望偶逢盧郎中、張員外攜酒同傾','白居易','唐','御定全唐诗','yuding','','[]','上陽宮裏曉鐘後，天津橋頭殘月前。空闊境疑非下界，',40,'御定全唐詩/json/455.json','["上陽宮裏曉鐘後，天津橋頭殘月前。空闊境疑非下界，", "此處相逢傾一醆，始知地上有神仙。"]'),
('yuding-26','八月十五日夜同諸客玩月','白居易','唐','御定全唐诗','yuding','','[]','月好共傳唯此夜，境閑皆道是東都。嵩山表裏千重雪，',40,'御定全唐詩/json/455.json','["月好共傳唯此夜，境閑皆道是東都。嵩山表裏千重雪，", "誠知亦有來年會，保得晴明強健無。"]'),
('yuding-27','對晚開夜合花贈皇甫郎中','白居易','唐','御定全唐诗','yuding','','[]','移晚校一月，花遲過半年。紅開杪秋日，翠合欲昏天。',48,'御定全唐詩/json/455.json','["移晚校一月，花遲過半年。紅開杪秋日，翠合欲昏天。", "白露滴未死，涼風吹更鮮。後時誰肯顧，唯我與君憐。"]'),
('yuding-28','醉游平泉','白居易','唐','御定全唐诗','yuding','','[]','狂歌箕踞酒尊前，眼不看人面向天。',32,'御定全唐詩/json/455.json','["狂歌箕踞酒尊前，眼不看人面向天。", "洛客最閑唯有我，一年四度到平泉。"]'),
('yuding-29','題贈平泉韋征君拾遺','白居易','唐','御定全唐诗','yuding','','[]','箕潁千年後，唯君得古風。位留丹陛上，身入白雲中。',48,'御定全唐詩/json/455.json','["箕潁千年後，唯君得古風。位留丹陛上，身入白雲中。", "躁靜心相背，高低跡不同。籠雞與梁燕，不信有冥鴻。"]'),
('yuding-30','酬皇甫郎中對新菊花見憶','白居易','唐','御定全唐诗','yuding','','[]','愛菊高人吟逸韻，悲秋病客感衰懷。黃花助興方攜酒，',40,'御定全唐詩/json/455.json','["愛菊高人吟逸韻，悲秋病客感衰懷。黃花助興方攜酒，", "愧君相憶東籬下，擬廢重陽一日齋。"]'),
('yuding-31','夜宴醉後留獻裴侍中','白居易','唐','御定全唐诗','yuding','','[]','九燭臺前十二姝，主人留醉任歡娛。翩翻舞袖雙飛蝶，',40,'御定全唐詩/json/455.json','["九燭臺前十二姝，主人留醉任歡娛。翩翻舞袖雙飛蝶，", "南山賓客東山妓，此會人間曾有無。"]'),
('yuding-32','和韋庶子遠坊赴宴未夜先歸之作兼呈裴員外','白居易','唐','御定全唐诗','yuding','','[]','促席留歡日未曛，遠坊歸思已紛紛。無妨按轡行乘月，',40,'御定全唐詩/json/455.json','["促席留歡日未曛，遠坊歸思已紛紛。無妨按轡行乘月，", "到時常晚歸時早，笑樂三分校一分。"]'),
('yuding-33','集賢池答侍中問','白居易','唐','御定全唐诗','yuding','','[]','主人晚入皇城宿，問客裴回何所須。',32,'御定全唐詩/json/455.json','["主人晚入皇城宿，問客裴回何所須。", "池月幸閑無用處，今宵能借客遊無。"]'),
('yuding-34','楊柳枝二十韻','白居易','唐','御定全唐诗','yuding','','[]','小妓攜桃葉，新聲蹋柳枝。妝成剪燭後，醉起拂衫時。',240,'御定全唐詩/json/455.json','["小妓攜桃葉，新聲蹋柳枝。妝成剪燭後，醉起拂衫時。", "繡履嬌行緩，花筵笑上遲。身輕委回雪，羅薄透凝脂。", "笙引簧頻暖，箏催柱數移。樂童翻怨調，才子與妍詞。", "便想人如樹，先將發比絲。風條搖兩帶，煙葉貼雙眉。", "口動櫻桃破，鬟低翡翠垂。枝柔腰嫋娜，荑嫩手葳蕤。", "唳鶴晴呼侶，哀猿夜叫兒。玉敲音歷歷，珠貫字累累。", "袖為收聲點，釵因赴節遺。重重遍頭別，一一拍心知。", "塞北愁攀折，江南苦別離。黃遮金穀岸，綠映杏園池。", "春惜芳華好，秋憐顏色衰。取來歌裏唱，勝向笛中吹。", "曲罷那能別，情多不自持。纏頭無別物，一首斷腸詩。"]'),
('yuding-35','答皇甫十郎中秋深酒熟見憶','白居易','唐','御定全唐诗','yuding','','[]','煙景冷蒼茫，秋深夜夜霜。為思池上酌，先覺甕頭香。',72,'御定全唐詩/json/455.json','["煙景冷蒼茫，秋深夜夜霜。為思池上酌，先覺甕頭香。", "未暇傾巾漉，還應染指嘗。醍醐慚氣味，琥珀讓晶光。", "若許陪歌席，須容散道場。月終齋戒畢，猶及菊花黃。"]'),
('yuding-36','老去','白居易','唐','御定全唐诗','yuding','','[]','老去愧妻兒，冬來有勸詞。暖寒從飲酒，沖冷少吟詩。',48,'御定全唐詩/json/455.json','["老去愧妻兒，冬來有勸詞。暖寒從飲酒，沖冷少吟詩。", "戰勝心還壯，齋勤體校羸。由來世間法，損益合相隨。"]'),
('yuding-37','送宗實上人遊江南','白居易','唐','御定全唐诗','yuding','','[]','忽辭洛下緣何事，擬向江南住幾時。',32,'御定全唐詩/json/455.json','["忽辭洛下緣何事，擬向江南住幾時。", "每過渡頭應問法，無妨菩薩是船師。"]'),
('yuding-38','和同州楊侍郎誇柘枝見寄','白居易','唐','御定全唐诗','yuding','','[]','細吟馮翊使君詩，憶作餘杭太守時。',32,'御定全唐詩/json/455.json','["細吟馮翊使君詩，憶作餘杭太守時。", "君有一般輸我事，柘枝看校十年遲。"]'),
('yuding-39','冬初酒熟二首','白居易','唐','御定全唐诗','yuding','','[]','霜繁脆庭柳，風利剪池荷。月色曉彌苦，鳥聲寒更多。',96,'御定全唐詩/json/455.json','["霜繁脆庭柳，風利剪池荷。月色曉彌苦，鳥聲寒更多。", "秋懷久寥落，冬計又如何。一甕新醅酒，萍浮春水波。", "酒熟無來客，因成獨酌謠。人間老黃綺，地上散松喬。", "忽忽醒還醉，悠悠暮複朝。殘年多少在，盡付此中銷。"]'),
('yuding-40','送姚杭州赴任，因思舊遊二首','白居易','唐','御定全唐诗','yuding','','[]','與君細話杭州事，為我留心莫等閒。閭裏固宜勤撫恤，',80,'御定全唐詩/json/455.json','["與君細話杭州事，為我留心莫等閒。閭裏固宜勤撫恤，", "且喜詩人重管領，遙飛一醆賀江山。", "渺渺錢唐路幾千，想君到後事依然。靜逢竺寺猿偷橘，", "舍人雖健無多興，老校當時八九年。"]'),
('yuding-41','寄李相公','白居易','唐','御定全唐诗','yuding','','[]','漸老只謀歡，雖貧不要官。唯求造化力，試為駐春看。',24,'御定全唐詩/json/455.json','["漸老只謀歡，雖貧不要官。唯求造化力，試為駐春看。"]'),
('yuding-42','冬日平泉路晚歸','白居易','唐','御定全唐诗','yuding','','[]','山路難行日易斜，煙村霜樹欲棲鴉。',32,'御定全唐詩/json/455.json','["山路難行日易斜，煙村霜樹欲棲鴉。", "夜歸不到應閒事，熱飲三杯即是家。"]'),
('yuding-43','利仁北街作','白居易','唐','御定全唐诗','yuding','','[]','草色斑斑春雨晴，利仁坊北面西行。',32,'御定全唐詩/json/455.json','["草色斑斑春雨晴，利仁坊北面西行。", "踟躕立馬緣何事，認得張家歌吹聲。"]'),
('yuding-44','洛陽堰閑行','白居易','唐','御定全唐诗','yuding','','[]','洛陽堰上新晴日，長夏門前欲暮春。',32,'御定全唐詩/json/455.json','["洛陽堰上新晴日，長夏門前欲暮春。", "遇酒即沽逢樹歇，七年此地作閒人。"]'),
('yuding-45','過永寧','白居易','唐','御定全唐诗','yuding','','[]','村杏野桃繁似雪，行人不醉為誰開。',32,'御定全唐詩/json/455.json','["村杏野桃繁似雪，行人不醉為誰開。", "賴逢山縣盧明府，引我花前勸一杯。"]'),
('yuding-46','往年稠桑曾喪白馬題詩廳壁今來尚存又複感懷更題絕句','白居易','唐','御定全唐诗','yuding','','[]','路傍埋骨蒿草合，壁上題詩塵蘚生。',32,'御定全唐詩/json/455.json','["路傍埋骨蒿草合，壁上題詩塵蘚生。", "馬死七年猶悵望，自知無乃太多情。"]'),
('yuding-47','羅敷水','白居易','唐','御定全唐诗','yuding','','[]','野店東頭花落處，一條流水號羅敷。',32,'御定全唐詩/json/455.json','["野店東頭花落處，一條流水號羅敷。", "芳魂豔骨知何處，春草茫茫墓亦無。"]'),
('yuding-48','路逢青州王大夫赴鎮，立馬贈別','白居易','唐','御定全唐诗','yuding','','[]','大旆擁金羈，書生得者稀。何勞問官職，豈不見光輝。',48,'御定全唐詩/json/455.json','["大旆擁金羈，書生得者稀。何勞問官職，豈不見光輝。", "赫赫人爭看，翩翩馬欲飛。不期前歲尹，駐節語依依。"]'),
('yuding-49','和楊同州寒食幹坑會後聞楊工部欲到知予與工部有宿酲','白居易','唐','御定全唐诗','yuding','','[]','夜飲歸常晚，朝眠起更遲。舉頭中酒後，引手索茶時。',49,'御定全唐詩/json/455.json','["夜飲歸常晚，朝眠起更遲。舉頭中酒後，引手索茶時。", "拂枕青長袖，欹簪白接z5。宿酲無興味，先是肺神知。"]'),
('yuding-50','和劉汝州酬侍中見寄長句因書集賢坊勝事戲而問之','白居易','唐','御定全唐诗','yuding','','[]','洛川汝海封畿接，履道集賢來往頻。一複時程雖不遠，',40,'御定全唐詩/json/455.json','["洛川汝海封畿接，履道集賢來往頻。一複時程雖不遠，", "聞道郡齋還有酒，花前月下對何人。"]'),
('yuding-51','池上二絕','白居易','唐','御定全唐诗','yuding','','[]','山僧對棋坐，局上竹陰清。映竹無人見，時聞下子聲。',48,'御定全唐詩/json/455.json','["山僧對棋坐，局上竹陰清。映竹無人見，時聞下子聲。", "小娃撐小艇，偷采白蓮回。不解藏蹤跡，浮萍一道開。"]'),
('yuding-52','白羽扇','白居易','唐','御定全唐诗','yuding','','[]','素是自然色，圓因裁制功。颯如松起籟，飄似鶴翻空。',72,'御定全唐詩/json/455.json','["素是自然色，圓因裁制功。颯如松起籟，飄似鶴翻空。", "盛夏不銷雪，終年無盡風。引秋生手裏，藏月入懷中。", "麈尾斑非疋，蒲葵陋不同。何人稱相對，清瘦白須翁。"]'),
('yuding-53','五月齋戒罷宴徹樂聞韋賓客皇甫郎中飲會亦稀又知欲攜酒饌出齋先以長句呈謝','白居易','唐','御定全唐诗','yuding','','[]','妓房匣鏡滿紅埃，酒庫封瓶生綠苔。居士爾時緣護戒，',40,'御定全唐詩/json/455.json','["妓房匣鏡滿紅埃，酒庫封瓶生綠苔。居士爾時緣護戒，", "隨意往還君莫怪，坐禪僧去飲徒來。"]'),
('yuding-54','閑園獨賞','白居易','唐','御定全唐诗','yuding','','[]','午後郊園靜，晴來景物新。雨添山氣色，風借水精神。',96,'御定全唐詩/json/455.json','["午後郊園靜，晴來景物新。雨添山氣色，風借水精神。", "永日若為度，獨游何所親。仙禽狎君子，芳樹倚佳人。", "蟻鬥王爭肉，蝸移舍逐身。蝶雙知伉儷，蜂分見君臣。", "蠢蠕形雖小，逍遙性即均。不知鵬與鷃，相去幾微塵。"]'),
('yuding-55','種柳三詠','白居易','唐','御定全唐诗','yuding','','[]','白頭種松桂，早晚見成林。不及栽楊柳，明年便有陰。',108,'御定全唐詩/json/455.json','["白頭種松桂，早晚見成林。不及栽楊柳，明年便有陰。", "春風為催促，副取老人心。", "從君種楊柳，夾水意如何。准擬三年後，青絲拂綠波。", "仍教小樓上，對唱柳枝歌。", "更想五年後，千千條麹塵。路傍深映月，樓上暗藏春。", "愁殺閒遊客，聞歌不見人。"]'),
('yuding-56','偶吟','白居易','唐','御定全唐诗','yuding','','[]','好官病免曾三度，散地歸休已七年。老自退閑非世棄，',40,'御定全唐詩/json/455.json','["好官病免曾三度，散地歸休已七年。老自退閑非世棄，", "便得一年生計足，與君美食複甘眠。"]'),
('yuding-57','池上即事','白居易','唐','御定全唐诗','yuding','','[]','移床避日依松竹，解帶當風掛薜蘿。鈿砌池心綠蘋合，',40,'御定全唐詩/json/455.json','["移床避日依松竹，解帶當風掛薜蘿。鈿砌池心綠蘋合，", "家醞瓶空人客絕，今宵爭奈月明何。"]'),
('yuding-58','南塘暝興','白居易','唐','御定全唐诗','yuding','','[]','水色昏猶白，霞光暗漸無。風荷搖破扇，波月動連珠。',48,'御定全唐詩/json/455.json','["水色昏猶白，霞光暗漸無。風荷搖破扇，波月動連珠。", "蟋蟀啼相應，鴛鴦宿不孤。小僮頻報夜，歸步尚踟躕。"]'),
('yuding-59','小宅','白居易','唐','御定全唐诗','yuding','','[]','小宅裏閭接，疏籬雞犬通。渠分南巷水，窗借北家風。',48,'御定全唐詩/json/455.json','["小宅裏閭接，疏籬雞犬通。渠分南巷水，窗借北家風。", "庾信園殊小，陶潛屋不豐。何勞問寬窄，寬窄在心中。"]'),
('yuding-60','諭親友','白居易','唐','御定全唐诗','yuding','','[]','適情處處皆安樂，大抵園林勝市朝。煩鬧榮華猶易過，',40,'御定全唐詩/json/455.json','["適情處處皆安樂，大抵園林勝市朝。煩鬧榮華猶易過，", "終日相逢不相見，兩心相去一何遙。"]'),
('yuding-61','龍門送別皇甫澤州赴任、韋山人南遊','白居易','唐','御定全唐诗','yuding','','[]','隼旟歸洛知何日，鶴駕還嵩莫過春。',32,'御定全唐詩/json/455.json','["隼旟歸洛知何日，鶴駕還嵩莫過春。", "惆悵香山雲水冷，明朝便是獨遊人。"]'),
('yuding-62','劉蘇州寄釀酒糯米李浙東寄楊柳枝舞衫偶因嘗酒試衫輒成長句寄謝之','白居易','唐','御定全唐诗','yuding','','[]','柳枝謾蹋試雙袖，桑落初香嘗一杯。金屑醅濃吳米釀，',40,'御定全唐詩/json/455.json','["柳枝謾蹋試雙袖，桑落初香嘗一杯。金屑醅濃吳米釀，", "慚愧故人憐寂寞，三千裏外寄歡來。"]'),
('yuding-63','詔授同州刺史，病不赴任，因詠所懷','白居易','唐','御定全唐诗','yuding','','[]','同州慵不去，此意複誰知。誠愛俸錢厚，其如身力衰。',96,'御定全唐詩/json/455.json','["同州慵不去，此意複誰知。誠愛俸錢厚，其如身力衰。", "可憐病判案，何似醉吟詩。勞逸懸相遠，行藏決不疑。", "徒煩人勸諫，只合自尋思。白髮來無限，青山去有期。", "野心惟怕鬧，家口莫愁饑。賣卻新昌宅，聊充送老資。"]'),
('yuding-64','寄楊六侍郎','白居易','唐','御定全唐诗','yuding','','[]','西戶最榮君好去，左馮雖穩我慵來。',32,'御定全唐詩/json/455.json','["西戶最榮君好去，左馮雖穩我慵來。", "秋風一箸鱸魚鱠，張翰搖頭喚不回。"]'),
('yuding-65','韋七自太子賓客再除秘書監，以長句賀而餞之','白居易','唐','御定全唐诗','yuding','','[]','離筵莫愴且同歡，共賀新恩拜舊官。屈就商山伴麋鹿，',40,'御定全唐詩/json/455.json','["離筵莫愴且同歡，共賀新恩拜舊官。屈就商山伴麋鹿，", "老監姓名應在壁，相思試為拂塵看。"]'),
('yuding-66','酒熟憶皇甫十','白居易','唐','御定全唐诗','yuding','','[]','新酒此時熟，故人何日來。自從金穀別，不見玉山頹。',48,'御定全唐詩/json/455.json','["新酒此時熟，故人何日來。自從金穀別，不見玉山頹。", "疏索柳花碗，寂寥荷葉杯。今冬問氈帳，雪裏為誰開。"]'),
('yuding-67','九年十一月二十一日感事而作','白居易','唐','御定全唐诗','yuding','','[]','禍福茫茫不可期，大都早退似先知。當君白首同歸日，',40,'御定全唐詩/json/455.json','["禍福茫茫不可期，大都早退似先知。當君白首同歸日，", "麒麟作脯龍為醢，何似泥中曳尾龜。"]'),
('yuding-68','即事重題','白居易','唐','御定全唐诗','yuding','','[]','重裘暖帽寬氈履，小閣低窗深地爐。',32,'御定全唐詩/json/455.json','["重裘暖帽寬氈履，小閣低窗深地爐。", "身穩心安眠未起，西京朝士得知無。"]'),
('yuding-69','將歸渭村先寄舍弟','白居易','唐','御定全唐诗','yuding','','[]','一年年覺此身衰，一日日知前事非。詠月嘲風先要減，',40,'御定全唐詩/json/455.json','["一年年覺此身衰，一日日知前事非。詠月嘲風先要減，", "為報阿連寒食下，與吾釀酒掃柴扉。"]'),
('yuding-70','看嵩洛有歎','白居易','唐','御定全唐诗','yuding','','[]','今日看嵩洛，回頭歎世間。榮華急如水，憂患大於山。',48,'御定全唐詩/json/455.json','["今日看嵩洛，回頭歎世間。榮華急如水，憂患大於山。", "見苦方知樂，經忙始愛閑。未聞籠裏鳥，飛出肯飛還。"]'),
('yuding-71','詠懷','白居易','唐','御定全唐诗','yuding','','[]','隨緣逐處便安閒，不入朝廷不住山。心似虛舟浮水上，',40,'御定全唐詩/json/455.json','["隨緣逐處便安閒，不入朝廷不住山。心似虛舟浮水上，", "處分貧家殘活計，匹如身後莫相關。"]'),
('yuding-72','詠老贈夢得','白居易','唐','御定全唐诗','yuding','','[]','與君俱老也，自問老何如。眼澀夜先臥，頭慵朝未梳。',72,'御定全唐詩/json/455.json','["與君俱老也，自問老何如。眼澀夜先臥，頭慵朝未梳。", "有時扶杖出，盡日閉門居。懶照新磨鏡，休看小字書。", "情于故人重，跡共少年疏。唯是閒談興，相逢尚有餘。"]'),
('yuding-0','從同州刺史改授太子少傅分司','白居易','唐','御定全唐诗','yuding','','[]','承華東署三分務，履道西池七過春。歌酒優遊聊卒歲，',40,'御定全唐詩/json/456.json','["承華東署三分務，履道西池七過春。歌酒優遊聊卒歲，", "月俸百千官二品，朝廷雇我作閒人。"]'),
('yuding-1','奉和裴令公新成午橋莊綠野堂即事','白居易','唐','御定全唐诗','yuding','','[]','舊徑開桃李，新池鑿鳳凰。只添丞相閣，不改午橋莊。',120,'御定全唐詩/json/456.json','["舊徑開桃李，新池鑿鳳凰。只添丞相閣，不改午橋莊。", "遠處塵埃少，閑中日月長。青山為外屏，綠野是前堂。", "引水多隨勢，栽松不趁行。年華玩風景，春事看農桑。", "花妒謝家妓，蘭偷荀令香。遊絲飄酒席，瀑布濺琴床。", "巢許終身穩，蕭曹到老忙。千年落公便，進退處中央。"]'),
('yuding-2','自題小草亭','白居易','唐','御定全唐诗','yuding','','[]','新結一茅茨，規模儉且卑。土階全壘塊，山木半留皮。',144,'御定全唐詩/json/456.json','["新結一茅茨，規模儉且卑。土階全壘塊，山木半留皮。", "陰合連藤架，叢香近菊籬。壁宜藜杖倚，門稱荻簾垂。", "窗裏風清夜，簷間月好時。留連嘗酒客，句引坐禪師。", "伴宿雙棲鶴，扶行一侍兒。綠醅量醆飲，紅稻約升炊。", "齷齪豪家笑，酸寒富室欺。陶廬閑自愛，顏巷陋誰知。", "螻蟻謀深穴，鷦鷯占小枝。各隨其分足，焉用有餘為。"]'),
('yuding-3','自詠','白居易','唐','御定全唐诗','yuding','','[]','細故隨緣盡，衰形具體微。鬥閑僧尚鬧，較瘦鶴猶肥。',72,'御定全唐詩/json/456.json','["細故隨緣盡，衰形具體微。鬥閑僧尚鬧，較瘦鶴猶肥。", "老遣寬裁襪，寒教厚絮衣。馬從銜草展，雞任啄籠飛。", "只要天和在，無令物性違。自餘君莫問，何是複何非。"]'),
('yuding-4','新亭病後獨坐，招李侍郎公垂','白居易','唐','御定全唐诗','yuding','','[]','新亭未有客，竟日獨何為。趁暖泥茶灶，防寒夾竹籬。',60,'御定全唐詩/json/456.json','["新亭未有客，竟日獨何為。趁暖泥茶灶，防寒夾竹籬。", "頭風初定後，眼暗欲明時。淺把三分酒，閑題數句詩。", "應須置兩榻，一榻待公垂。"]'),
('yuding-5','閑臥寄劉同州','白居易','唐','御定全唐诗','yuding','','[]','軟褥短屏風，昏昏醉臥翁。鼻香茶熟後，腰暖日陽中。',48,'御定全唐詩/json/456.json','["軟褥短屏風，昏昏醉臥翁。鼻香茶熟後，腰暖日陽中。", "伴老琴長在，迎春酒不空。可憐閒氣味，唯欠與君同。"]'),
('yuding-6','殘酌晚餐','白居易','唐','御定全唐诗','yuding','','[]','閑傾殘酒後，暖擁小爐時。舞看新翻曲，歌聽自作詞。',48,'御定全唐詩/json/456.json','["閑傾殘酒後，暖擁小爐時。舞看新翻曲，歌聽自作詞。", "魚香肥潑火，飯細滑流匙。除卻慵饞外，其餘盡不知。"]'),
('yuding-7','喜見劉同州夢得','白居易','唐','御定全唐诗','yuding','','[]','紫綬白髭須，同年二老夫。論心共牢落，見面且歡娛。',48,'御定全唐詩/json/456.json','["紫綬白髭須，同年二老夫。論心共牢落，見面且歡娛。", "酒好攜來否，詩多記得無。應須為春草，五馬少踟躕。"]'),
('yuding-8','裴令公席上贈別夢得','白居易','唐','御定全唐诗','yuding','','[]','年老官高多別離，轉難相見轉相思。',32,'御定全唐詩/json/456.json','["年老官高多別離，轉難相見轉相思。", "雪銷酒盡梁王起，便是鄒枚分散時。"]'),
('yuding-9','尋春題諸家園林','白居易','唐','御定全唐诗','yuding','','[]','聞健朝朝出，乘春處處尋。天供閑日月，人借好園林。',48,'御定全唐詩/json/456.json','["聞健朝朝出，乘春處處尋。天供閑日月，人借好園林。", "漸以狂為態，都無悶到心。平生身得所，未省似而今。"]'),
('yuding-10','又題一絕','白居易','唐','御定全唐诗','yuding','','[]','貌隨年老欲何如，興遇春牽尚有餘。',32,'御定全唐詩/json/456.json','["貌隨年老欲何如，興遇春牽尚有餘。", "遙見人家花便入，不論貴賤與親疏。"]'),
('yuding-11','家園三絕','白居易','唐','御定全唐诗','yuding','','[]','滄浪峽水子陵灘，路遠江深欲去難。',96,'御定全唐詩/json/456.json','["滄浪峽水子陵灘，路遠江深欲去難。", "何似家池通小院，臥房階下插魚竿。", "籬下先生時得醉，甕間吏部暫偷閒。", "何如家醞雙魚榼，雪夜花時長在前。", "鴛鴦怕捉竟難親，鸚鵡雖籠不著人。", "何似家禽雙白鶴，閑行一步亦隨身。"]'),
('yuding-12','老來生計','白居易','唐','御定全唐诗','yuding','','[]','老來生計君看取，白日遊行夜醉吟。陶令有田唯種黍，',40,'御定全唐詩/json/456.json','["老來生計君看取，白日遊行夜醉吟。陶令有田唯種黍，", "煩慮漸消虛白長，一年心勝一年心。"]'),
('yuding-13','早春題少室東岩','白居易','唐','御定全唐诗','yuding','','[]','三十六峰晴，雪銷嵐翠生。月留三夜宿，春引四山行。',48,'御定全唐詩/json/456.json','["三十六峰晴，雪銷嵐翠生。月留三夜宿，春引四山行。", "遠草初含色，寒禽未變聲。東岩最高石，唯我有題名。"]'),
('yuding-14','早春即事','白居易','唐','御定全唐诗','yuding','','[]','眼重朝眠足，頭輕宿酒醒。陽光滿前戶，雪水半中庭。',72,'御定全唐詩/json/456.json','["眼重朝眠足，頭輕宿酒醒。陽光滿前戶，雪水半中庭。", "物變隨天氣，春生逐地形。北簷梅晚白，東岸柳先青。", "蔥壟抽羊角，松巢墮鶴翎。老來詩更拙，吟罷少人聽。"]'),
('yuding-15','歎春風兼贈李二十侍郎二絕','白居易','唐','御定全唐诗','yuding','','[]','樹根雪盡催花發，池岸冰消放草生。',64,'御定全唐詩/json/456.json','["樹根雪盡催花發，池岸冰消放草生。", "唯有須霜依舊白，春風於我獨無情。", "道場齋戒今初畢，酒伴歡娛久不同。", "不把一杯來勸我，無情亦得似春風。"]'),
('yuding-16','春來頻與李二賓客郭外同遊，因贈長句','白居易','唐','御定全唐诗','yuding','','[]','風光引步酒開顏，送老消春嵩洛間。朝蹋落花相伴出，',40,'御定全唐詩/json/456.json','["風光引步酒開顏，送老消春嵩洛間。朝蹋落花相伴出，", "可惜濟時心力在，放教臨水複登山。"]'),
('yuding-17','二月二日','白居易','唐','御定全唐诗','yuding','','[]','二月二日新雨晴，草芽菜甲一時生。',32,'御定全唐詩/json/456.json','["二月二日新雨晴，草芽菜甲一時生。", "輕衫細馬春年少，十字津頭一字行。"]'),
('yuding-18','奉和令公綠野堂種花','白居易','唐','御定全唐诗','yuding','','[]','綠野堂開占物華，路人指道令公家。',32,'御定全唐詩/json/456.json','["綠野堂開占物華，路人指道令公家。", "令公桃李滿天下，何用堂前更種花。"]'),
('yuding-19','清明日登老君閣望洛城，贈韓道士','白居易','唐','御定全唐诗','yuding','','[]','風光煙火清明日，歌哭悲歡城市間。何事不隨東洛水，',40,'御定全唐詩/json/456.json','["風光煙火清明日，歌哭悲歡城市間。何事不隨東洛水，", "塚墓累累人擾擾，遼東悵望鶴飛還。"]'),
('yuding-20','三月三日','白居易','唐','御定全唐诗','yuding','','[]','畫堂三月初三日，絮撲窗紗燕拂簷。蓮子數杯嘗冷酒，',40,'御定全唐詩/json/456.json','["畫堂三月初三日，絮撲窗紗燕拂簷。蓮子數杯嘗冷酒，", "指點樓南玩新月，玉鉤素手兩纖纖。"]'),
('yuding-21','雨中聽琴者彈別鶴操','白居易','唐','御定全唐诗','yuding','','[]','雙鶴分離一何苦，連陰雨夜不堪聞。',33,'御定全唐詩/json/456.json','["雙鶴分離一何苦，連陰雨夜不堪聞。", "莫教遷客孀妻聽，嗟歎悲啼eW殺君。"]'),
('yuding-22','酬鄭二司錄與李六郎中寒食日相過，同宴見贈','白居易','唐','御定全唐诗','yuding','','[]','偶因冷節會嘉賓，況是平生心所親。迎接須矜疏傅老，',40,'御定全唐詩/json/456.json','["偶因冷節會嘉賓，況是平生心所親。迎接須矜疏傅老，", "相對喜歡還悵望，同年只有此三人。"]'),
('yuding-23','喜楊六侍禦同宿','白居易','唐','御定全唐诗','yuding','','[]','岸幘靜言明月夜，匡床閑臥落花朝。二三月裏饒春睡，',40,'御定全唐詩/json/456.json','["岸幘靜言明月夜，匡床閑臥落花朝。二三月裏饒春睡，", "眼看又上青雲去，更蔔同衾一兩宵。"]'),
('yuding-24','殘春詠懷，贈楊慕巢侍郎','白居易','唐','御定全唐诗','yuding','','[]','位逾三品日，年過六旬時。不道官班下，其如筋力衰。',96,'御定全唐詩/json/456.json','["位逾三品日，年過六旬時。不道官班下，其如筋力衰。", "猶憐好風景，轉重舊親知。少壯難重得，歡娛且強為。", "興來池上酌，醉出袖中詩。靜話開襟久，閑吟放醆遲。", "落花無限雪，殘鬢幾多絲。莫說傷心事，春翁易酒悲。"]'),
('yuding-25','閒居春盡','白居易','唐','御定全唐诗','yuding','','[]','閑泊池舟靜掩扉，老身慵出客來稀。愁應暮雨留教住，',40,'御定全唐詩/json/456.json','["閑泊池舟靜掩扉，老身慵出客來稀。愁應暮雨留教住，", "冬裘夏葛相催促，垂老光陰速似飛。"]'),
('yuding-26','春盡日天津橋醉吟偶呈李尹侍郎','白居易','唐','御定全唐诗','yuding','','[]','宿雨洗天津，無泥未有塵。初晴迎早夏，落照送殘春。',72,'御定全唐詩/json/456.json','["宿雨洗天津，無泥未有塵。初晴迎早夏，落照送殘春。", "興發詩隨口，狂來酒寄身。水邊行嵬峨，橋上立逡巡。", "疏傅心情老，吳公政化新。三川徒有主，風景屬閒人。"]'),
('yuding-27','池上逐涼二首','白居易','唐','御定全唐诗','yuding','','[]','青苔地上消殘暑，綠樹陰前逐晚涼。輕屐單衫薄紗帽，',80,'御定全唐詩/json/456.json','["青苔地上消殘暑，綠樹陰前逐晚涼。輕屐單衫薄紗帽，", "遍問交親為老計，多言宜靜不宜忙。", "窗間睡足休高枕，水畔閑來上小船。棹遣禿頭奴子撥，", "誰信好風清簟上，更無一事但翛然。"]'),
('yuding-28','香山避暑二絕','白居易','唐','御定全唐诗','yuding','','[]','六月灘聲如猛雨，香山樓北暢師房。',64,'御定全唐詩/json/456.json','["六月灘聲如猛雨，香山樓北暢師房。", "夜深起憑闌幹立，滿耳潺湲滿面涼。", "紗巾草履竹疏衣，晚下香山蹋翠微。", "一路涼風十八裏，臥乘籃輿睡中歸。"]'),
('yuding-29','老夫','白居易','唐','御定全唐诗','yuding','','[]','七八年來遊洛都，三分遊伴二分無。風前月下花園裏，',40,'御定全唐詩/json/456.json','["七八年來遊洛都，三分遊伴二分無。風前月下花園裏，", "誰能逐我來閑坐，時共酣歌傾一壺。"]'),
('yuding-30','香山下卜居','白居易','唐','御定全唐诗','yuding','','[]','老須為老計，老計在抽簪。山下初投足，人間久息心。',48,'御定全唐詩/json/456.json','["老須為老計，老計在抽簪。山下初投足，人間久息心。", "亂藤遮石壁，絕澗護雲林。若要深藏處，無如此處深。"]'),
('yuding-31','無長物','白居易','唐','御定全唐诗','yuding','','[]','莫訝家居窄，無嫌活計貧。只緣無長物，始得作閒人。',48,'御定全唐詩/json/456.json','["莫訝家居窄，無嫌活計貧。只緣無長物，始得作閒人。", "青竹單床簟，烏紗獨幅巾。其餘皆稱是，亦足奉吾身。"]'),
('yuding-32','宿香山寺酬廣陵牛相公見寄','白居易','唐','御定全唐诗','yuding','','[]','手劄八行詩一篇，無由相見但依然。君匡聖主方行道，',40,'御定全唐詩/json/456.json','["手劄八行詩一篇，無由相見但依然。君匡聖主方行道，", "應須且為蒼生住，猶去懸車十四年。"]'),
('yuding-33','以詩代書，寄戶部楊侍郎，勸買東鄰王家宅','白居易','唐','御定全唐诗','yuding','','[]','勸君買取東鄰宅，與我衡門相並開。雲映嵩峰當戶牖，',40,'御定全唐詩/json/456.json','["勸君買取東鄰宅，與我衡門相並開。雲映嵩峰當戶牖，", "莫學因循白賓客，欲年六十始歸來。"]'),
('yuding-34','贈談客','白居易','唐','御定全唐诗','yuding','','[]','上客清談何亹亹，幽人閑思自寥寥。',32,'御定全唐詩/json/456.json','["上客清談何亹亹，幽人閑思自寥寥。", "請君休說長安事，膝上風清琴正調。"]'),
('yuding-35','初入香山院對月','白居易','唐','御定全唐诗','yuding','','[]','老住香山初到夜，秋逢白月正圓時。',32,'御定全唐詩/json/456.json','["老住香山初到夜，秋逢白月正圓時。", "從今便是家山月，試問清光知不知。"]'),
('yuding-36','題龍門堰西澗','白居易','唐','御定全唐诗','yuding','','[]','東岸菊叢西岸柳，柳陰煙合菊花開。一條秋水琉璃色，',24,'御定全唐詩/json/456.json','["東岸菊叢西岸柳，柳陰煙合菊花開。一條秋水琉璃色，"]'),
('yuding-37','秋霖中奉裴令公見招早出赴會馬上先寄六韻','白居易','唐','御定全唐诗','yuding','','[]','雨暗三秋日，泥深一尺時。老人平旦出，自問欲何之。',72,'御定全唐詩/json/456.json','["雨暗三秋日，泥深一尺時。老人平旦出，自問欲何之。", "不是尋醫藥，非幹送別離。素書傳好語，絳帳赴佳期。", "續借桃花馬，催迎楊柳姬。只愁張錄事，罰我怪來遲。"]'),
('yuding-38','嘗酒聽歌招客','白居易','唐','御定全唐诗','yuding','','[]','一甕香醪新插芻，雙鬟小妓薄能謳。管弦漸好新教得，',40,'御定全唐詩/json/456.json','["一甕香醪新插芻，雙鬟小妓薄能謳。管弦漸好新教得，", "不知此事君知否，君若知時從我遊。"]'),
('yuding-39','八月三日夜作','白居易','唐','御定全唐诗','yuding','','[]','露白月微明，天涼景物清。草頭珠顆冷，樓角玉鉤生。',96,'御定全唐詩/json/456.json','["露白月微明，天涼景物清。草頭珠顆冷，樓角玉鉤生。", "氣爽衣裳健，風疏砧杵鳴。夜衾香有思，秋簟冷無情。", "夢短眠頻覺，宵長起暫行。燭凝臨曉影，蟲怨欲寒聲。", "槿老花先盡，蓮凋子始成。四時無了日，何用歎衰榮。"]'),
('yuding-40','病中贈南鄰覓酒','白居易','唐','御定全唐诗','yuding','','[]','頭痛牙疼三日臥，妻看煎藥婢來扶。',32,'御定全唐詩/json/456.json','["頭痛牙疼三日臥，妻看煎藥婢來扶。", "今朝似校抬頭語，先問南鄰有酒無。"]'),
('yuding-41','曉眠後寄楊戶部','白居易','唐','御定全唐诗','yuding','','[]','軟綾腰褥薄綿被，涼冷秋天穩暖身。',32,'御定全唐詩/json/456.json','["軟綾腰褥薄綿被，涼冷秋天穩暖身。", "一覺曉眠殊有味，無因寄與早朝人。"]'),
('yuding-42','秋雨夜眠','白居易','唐','御定全唐诗','yuding','','[]','涼冷三秋夜，安閒一老翁。臥遲燈滅後，睡美雨聲中。',48,'御定全唐詩/json/456.json','["涼冷三秋夜，安閒一老翁。臥遲燈滅後，睡美雨聲中。", "灰宿溫瓶火，香添暖被籠。曉晴寒未起，霜葉滿階紅。"]'),
('yuding-43','喜夢得自馮翊歸洛，兼呈令公','白居易','唐','御定全唐诗','yuding','','[]','上客新從左輔回，高陽興助洛陽才。已將四海聲名去，',40,'御定全唐詩/json/456.json','["上客新從左輔回，高陽興助洛陽才。已將四海聲名去，", "鄒枚未用爭詩酒，且飲梁王賀喜杯。"]'),
('yuding-44','齋戒滿夜，戲招夢得','白居易','唐','御定全唐诗','yuding','','[]','紗籠燈下道場前，白日持齋夜坐禪。無複更思身外事，',40,'御定全唐詩/json/456.json','["紗籠燈下道場前，白日持齋夜坐禪。無複更思身外事，", "方丈若能來問疾，不妨兼有散花天。"]'),
('yuding-45','和令公問劉賓客歸來稱意無之作','白居易','唐','御定全唐诗','yuding','','[]','水南秋一半，風景未蕭條。皂蓋回沙苑，藍輿上洛橋。',48,'御定全唐詩/json/456.json','["水南秋一半，風景未蕭條。皂蓋回沙苑，藍輿上洛橋。", "閑嘗黃菊酒，醉唱紫芝謠。稱意那勞問，請錢不早朝。"]'),
('yuding-46','酬夢得窮秋夜坐，即事見寄','白居易','唐','御定全唐诗','yuding','','[]','焰細燈將盡，聲遙漏正長。老人秋向火，小女夜縫裳。',48,'御定全唐詩/json/456.json','["焰細燈將盡，聲遙漏正長。老人秋向火，小女夜縫裳。", "菊悴籬經雨，萍銷水得霜。今冬暖寒酒，先擬共君嘗。"]'),
('yuding-47','偶于維揚牛相公處覓得箏箏未到先寄詩來走筆戲答','白居易','唐','御定全唐诗','yuding','','[]','楚匠饒巧思，秦箏多好音。如能惠一面，何啻直雙金。',48,'御定全唐詩/json/456.json','["楚匠饒巧思，秦箏多好音。如能惠一面，何啻直雙金。", "玉柱調須品，朱弦染要深。會教魔女弄，不動是禪心。"]'),
('yuding-48','答夢得秋庭獨坐見贈','白居易','唐','御定全唐诗','yuding','','[]','林梢隱映夕陽殘，庭際蕭疏夜氣寒。霜草欲枯蟲思急，',40,'御定全唐詩/json/456.json','["林梢隱映夕陽殘，庭際蕭疏夜氣寒。霜草欲枯蟲思急，", "應是天教相暖熱，一時垂老與閑官。"]'),
('yuding-49','長齋月滿攜酒先與夢得對酌醉中同赴令公之宴戲贈夢得','白居易','唐','御定全唐诗','yuding','','[]','齋宮前日滿三旬，酒榼今朝一拂塵。乘興還同訪戴客，',40,'御定全唐詩/json/456.json','["齋宮前日滿三旬，酒榼今朝一拂塵。乘興還同訪戴客，", "若怕平原怪先醉，知君未慣吐車茵。"]'),
('yuding-50','奉酬淮南牛相公思黯見寄二十四韻','白居易','唐','御定全唐诗','yuding','','[]','白老忘機客，牛公濟世賢。鷗棲心戀水，鵬舉翅摩天。',288,'御定全唐詩/json/456.json','["白老忘機客，牛公濟世賢。鷗棲心戀水，鵬舉翅摩天。", "累就優閑秩，連操造化權。貧司甚蕭灑，榮路自喧闐。", "望苑三千日，臺階十五年。是人皆棄忘，何物不陶甄。", "籃輿遊嵩嶺，油幢鎮海壖。竹篙撐釣艇，金甲擁樓船。", "雪夜尋僧舍，春朝列妓筵。長齋儼香火，密宴簇花鈿。", "自覺閑勝鬧，遙知醉笑禪。是非分未定，會合杳無緣。", "我正思揚府，君應望洛川。西來風嫋嫋，南去雁連連。", "日落龍門外，潮生瓜步前。秋同一時盡，月共兩鄉圓。", "舊眷交歡在，新文氣調全。慚無白雪曲，難答碧雲篇。", "金穀詩誰賞，蕪城賦眾傳。珠應哂魚目，鉛未伏龍泉。", "遠訊驚魔物，深情寄酒錢。霜紈一百匹，玉柱十三弦。", "楚醴來尊裏，秦聲送耳邊。何時紅燭下，相對一陶然。"]'),
('yuding-51','吳祕監每有美酒獨酌獨醉但蒙詩報不以飲招輒此戲酬兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','蓬山仙客下煙霄，對酒唯吟獨酌謠。不怕道狂揮玉爵，',40,'御定全唐詩/json/456.json','["蓬山仙客下煙霄，對酒唯吟獨酌謠。不怕道狂揮玉爵，", "賴有伯倫為醉伴，何愁不解傲松喬。"]'),
('yuding-52','酬夢得霜夜對月見懷','白居易','唐','御定全唐诗','yuding','','[]','淒清冬夜景，搖落長年情。月帶新霜色，砧和遠雁聲。',48,'御定全唐詩/json/456.json','["淒清冬夜景，搖落長年情。月帶新霜色，砧和遠雁聲。", "暖憐爐火近，寒覺被衣輕。枕上酬佳句，詩成夢不成。"]'),
('yuding-53','初冬月夜得皇甫澤州手劄並詩數篇因遣報書偶題長句','白居易','唐','御定全唐诗','yuding','','[]','清泠玉韻兩三章，落箔銀鉤七八行。心逐報書懸雁足，',40,'御定全唐詩/json/456.json','["清泠玉韻兩三章，落箔銀鉤七八行。心逐報書懸雁足，", "最恨潑醅新熟酒，迎冬不得共君嘗。"]'),
('yuding-54','雪中酒熟，欲攜訪吳監，先寄此詩','白居易','唐','御定全唐诗','yuding','','[]','新雪對新酒，憶同傾一杯。自然須訪戴，不必待延枚。',48,'御定全唐詩/json/456.json','["新雪對新酒，憶同傾一杯。自然須訪戴，不必待延枚。", "陳榻無辭解，袁門莫懶開。笙歌與談笑，隨事自將來。"]'),
('yuding-55','酬令公雪中見贈，訝不與夢得同相訪','白居易','唐','御定全唐诗','yuding','','[]','雪似鵝毛飛散亂，人披鶴氅立裴回。',32,'御定全唐詩/json/456.json','["雪似鵝毛飛散亂，人披鶴氅立裴回。", "鄒生枚叟非無興，唯待梁王召即來。"]'),
('yuding-56','題酒甕呈夢得','白居易','唐','御定全唐诗','yuding','','[]','若無清酒兩三甕，爭向白須千萬莖。麹糵銷愁真得力，',40,'御定全唐詩/json/456.json','["若無清酒兩三甕，爭向白須千萬莖。麹糵銷愁真得力，", "更擬共君何處去，且來同作醉先生。"]'),
('yuding-57','迂叟','白居易','唐','御定全唐诗','yuding','','[]','一辭魏闕就商賓，散地閒居八九春。初時被目為迂叟，',40,'御定全唐詩/json/456.json','["一辭魏闕就商賓，散地閒居八九春。初時被目為迂叟，", "應須繩墨機關外，安置疏愚鈍滯身。"]'),
('yuding-58','洛下閒居，寄山南令狐相公','白居易','唐','御定全唐诗','yuding','','[]','已收身向園林下，猶寄名於祿仕間。不鍛嵇康彌懶靜，',40,'御定全唐詩/json/456.json','["已收身向園林下，猶寄名於祿仕間。不鍛嵇康彌懶靜，", "唯是相君忘未得，時思漢水夢巴山。"]'),
('yuding-59','惜春贈李尹','白居易','唐','御定全唐诗','yuding','','[]','春色有時盡，公門終日忙。兩衙但不闕，一醉亦何妨。',48,'御定全唐詩/json/456.json','["春色有時盡，公門終日忙。兩衙但不闕，一醉亦何妨。", "芳樹花團雪，衰翁鬢撲霜。知君倚年少，未苦惜風光。"]'),
('yuding-60','對酒勸令公開春遊宴','白居易','唐','御定全唐诗','yuding','','[]','時泰歲豐無事日，功成名遂自由身。前頭更有忘憂日，',40,'御定全唐詩/json/456.json','["時泰歲豐無事日，功成名遂自由身。前頭更有忘憂日，", "宜須數數謀歡會，好作開成第二春。"]'),
('yuding-61','與夢得偶同到敦詩宅，感而題壁','白居易','唐','御定全唐诗','yuding','','[]','山東才副蒼生願，川上俄驚逝水波。履道淒涼新第宅，',40,'御定全唐詩/json/456.json','["山東才副蒼生願，川上俄驚逝水波。履道淒涼新第宅，", "今日相逢偶同到，傷心不是故經過。"]'),
('yuding-62','楊六尚書新授東川節度使，代妻戲賀兄嫂二絕','白居易','唐','御定全唐诗','yuding','','[]','劉綱與婦共升仙，弄玉隨夫亦上天。',64,'御定全唐詩/json/456.json','["劉綱與婦共升仙，弄玉隨夫亦上天。", "何似沙哥領崔嫂，碧油幢引向東川。", "金花銀碗饒君用，罨畫羅衣盡嫂裁。", "覓得黔婁為妹婿，可能空寄蜀茶來。"]'),
('yuding-63','閒遊即事','白居易','唐','御定全唐诗','yuding','','[]','郊野遊行熟，村園次第過。驀山尋浥澗，蹋水渡伊河。',72,'御定全唐詩/json/456.json','["郊野遊行熟，村園次第過。驀山尋浥澗，蹋水渡伊河。", "寒食青青草，春風瑟瑟波。逢人共杯酒，隨馬有笙歌。", "勝事經非少，芳辰過亦多。還須自知分，不老擬如何。"]'),
('yuding-64','六十六','白居易','唐','御定全唐诗','yuding','','[]','七十欠四歲，此生那足論。每因悲物故，還且喜身存。',72,'御定全唐詩/json/456.json','["七十欠四歲，此生那足論。每因悲物故，還且喜身存。", "安得頭長黑，爭教眼不昏。交遊成拱木，婢僕見曾孫。", "瘦覺腰金重，衰憐鬢雪繁。將何理老病，應付與空門。"]'),
('yuding-65','池上早春，即事招夢得','白居易','唐','御定全唐诗','yuding','','[]','老更驚年改，閑先覺日長。晴熏榆莢黑，春染柳梢黃。',96,'御定全唐詩/json/456.json','["老更驚年改，閑先覺日長。晴熏榆莢黑，春染柳梢黃。", "雲破山呈色，冰融水放光。低平穩船舫，輕暖好衣裳。", "白角三升榼，紅茵六尺床。偶遊難得伴，獨醉不成狂。", "我有中心樂，君無外事忙。經過莫慵懶，相去兩三坊。"]'),
('yuding-66','因夢得題公垂所寄蠟燭，因寄公垂','白居易','唐','御定全唐诗','yuding','','[]','照梁初日光相似，出水新蓮豔不如。',32,'御定全唐詩/json/456.json','["照梁初日光相似，出水新蓮豔不如。", "卻寄兩條君令取，明年雙引入中書。"]'),
('yuding-67','令公南莊花柳正盛，欲偷一賞，先寄二篇','白居易','唐','御定全唐诗','yuding','','[]','最憶樓花千萬朵，偏憐堤柳兩三株。',64,'御定全唐詩/json/456.json','["最憶樓花千萬朵，偏憐堤柳兩三株。", "擬提社酒攜村妓，擅入朱門莫怪無。", "可惜亭台閑度日，欲偷風景暫遊春。", "只愁花裏鶯饒舌，飛入宮城報主人。"]'),
('yuding-68','春夜宴席上戲贈裴淄川','白居易','唐','御定全唐诗','yuding','','[]','九十不衰真地仙，六旬猶健亦天憐。今年相遇鶯花月，',40,'御定全唐詩/json/456.json','["九十不衰真地仙，六旬猶健亦天憐。今年相遇鶯花月，", "留君到曉無他意，圖向君前作少年。"]'),
('yuding-69','贈夢得','白居易','唐','御定全唐诗','yuding','','[]','年顏老少與君同，眼未全昏耳未聾。放醉臥為春日伴，',40,'御定全唐詩/json/456.json','["年顏老少與君同，眼未全昏耳未聾。放醉臥為春日伴，", "聞道洛城人盡怪，呼為劉白二狂翁。"]'),
('yuding-70','晚春欲攜酒尋沈四著作，先以六韻寄之','白居易','唐','御定全唐诗','yuding','','[]','病容衰慘澹，芳景晚蹉跎。無計留春得，爭能奈老何。',72,'御定全唐詩/json/456.json','["病容衰慘澹，芳景晚蹉跎。無計留春得，爭能奈老何。", "篇章慵報答，杯宴喜經過。顧我酒狂久，負君詩債多。", "敢辭攜綠蟻，只願見青娥。最憶陽關唱，真珠一串歌。"]'),
('yuding-71','三月三日祓禊洛濱','白居易','唐','御定全唐诗','yuding','','[]','三月草萋萋，黃鶯歇又啼。柳橋晴有絮，沙路潤無泥。',144,'御定全唐詩/json/456.json','["三月草萋萋，黃鶯歇又啼。柳橋晴有絮，沙路潤無泥。", "禊事修初半，遊人到欲齊。金鈿耀桃李，絲管駭鳧鷖。", "轉岸回船尾，臨流簇馬蹄。鬧翻揚子渡，蹋破魏王堤。", "妓接謝公宴，詩陪荀令題。舟同李膺泛，醴為穆生攜。", "水引春心蕩，花牽醉眼迷。塵街從鼓動，煙樹任鴉棲。", "舞急紅腰軟，歌遲翠黛低。夜歸何用燭，新月鳳樓西。"]'),
('yuding-72','同夢得暮春寄賀東西川二楊尚書','白居易','唐','御定全唐诗','yuding','','[]','龍節對持真可愛，雁行相接更堪誇。兩川風景同三月，',40,'御定全唐詩/json/456.json','["龍節對持真可愛，雁行相接更堪誇。兩川風景同三月，", "應憐洛下分司伴，冷宴閒遊老看花。"]'),
('yuding-73','喜小樓西新柳抽條','白居易','唐','御定全唐诗','yuding','','[]','一行弱柳前年種，數尺柔條今日新。漸欲拂他騎馬客，',40,'御定全唐詩/json/456.json','["一行弱柳前年種，數尺柔條今日新。漸欲拂他騎馬客，", "為報金堤千萬樹，饒伊未敢苦爭春。"]'),
('yuding-74','晚春酒醒尋夢得','白居易','唐','御定全唐诗','yuding','','[]','料合同惆悵，花殘酒亦殘。醉心忘老易，醒眼別春難。',48,'御定全唐詩/json/456.json','["料合同惆悵，花殘酒亦殘。醉心忘老易，醒眼別春難。", "獨出雖慵懶，相逢定喜歡。還攜小蠻去，試覓老劉看。"]'),
('yuding-75','感事','白居易','唐','御定全唐诗','yuding','','[]','服氣崔常侍，燒丹鄭舍人。常期生羽翼，那忽化灰塵。',72,'御定全唐詩/json/456.json','["服氣崔常侍，燒丹鄭舍人。常期生羽翼，那忽化灰塵。", "每遇淒涼事，還思潦倒身。唯知趁杯酒，不解煉金銀。", "睡適三屍性，慵安五藏神。無憂亦無喜，六十六年春。"]'),
('yuding-76','和裴令公南莊絕句','白居易','唐','御定全唐诗','yuding','','[]','陶廬僻陋那堪比，謝墅幽微不足攀。',32,'御定全唐詩/json/456.json','["陶廬僻陋那堪比，謝墅幽微不足攀。", "何似嵩峰三十六，長隨申甫作家山。"]'),
('yuding-77','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句','白居易','唐','御定全唐诗','yuding','','[]','伊水分來不自由，無人解愛為誰流。',160,'御定全唐詩/json/456.json','["伊水分來不自由，無人解愛為誰流。", "家家拋向牆根底，唯我栽蓮越小樓。", "水色波文何所似，麹塵羅帶一條斜。", "莫言羅帶春無主，自置樓來屬白家。", "日灩水光搖素壁，風飄樹影拂朱欄。", "皆言此處宜弦管，試奏霓裳一曲看。", "霓裳奏罷唱梁州，紅袖斜翻翠黛愁。", "應是遙聞勝近聽，行人欲過盡回頭。", "獨醉還須得歌舞，自娛何必要親賓。", "當時一部清商樂，亦不長將樂外人。"]'),
('yuding-78','偶作','白居易','唐','御定全唐诗','yuding','','[]','籃舁出即忘歸舍，柴戶昏猶未掩關。聞客病時慚體健，',40,'御定全唐詩/json/456.json','["籃舁出即忘歸舍，柴戶昏猶未掩關。聞客病時慚體健，", "木雁一篇須記取，致身才與不才間。"]'),
('yuding-79','因夢得酬牛相公初到洛中小飲見贈','白居易','唐','御定全唐诗','yuding','','[]','淮南揮手拋紅旆，洛下回頭向白雲。政事堂中老丞相，',40,'御定全唐詩/json/456.json','["淮南揮手拋紅旆，洛下回頭向白雲。政事堂中老丞相，", "詩酒放狂猶得在，莫欺白叟與劉君。"]'),
('yuding-80','幽居早秋閑詠','白居易','唐','御定全唐诗','yuding','','[]','幽僻囂塵外，清涼水木間。臥風秋拂簟，步月夜開關。',72,'御定全唐詩/json/456.json','["幽僻囂塵外，清涼水木間。臥風秋拂簟，步月夜開關。", "且得身安泰，從他世險艱。但休爭要路，不必入深山。", "軒鶴留何用，泉魚放不還。誰人知此味，臨老十年閑。"]'),
('yuding-81','和令狐僕射小飲聽阮咸','白居易','唐','御定全唐诗','yuding','','[]','掩抑複淒清，非琴不是箏。還彈樂府曲，別占阮家名。',72,'御定全唐詩/json/456.json','["掩抑複淒清，非琴不是箏。還彈樂府曲，別占阮家名。", "古調何人識，初聞滿座驚。落盤珠歷歷，搖佩玉琤琤。", "似勸杯中物，如含林下情。時移音律改，豈是昔時聲。"]'),
('yuding-82','燒藥不成命酒獨醉','白居易','唐','御定全唐诗','yuding','','[]','白髮逢秋王，丹砂見火空。不能留姹女，爭免作衰翁。',48,'御定全唐詩/json/456.json','["白髮逢秋王，丹砂見火空。不能留姹女，爭免作衰翁。", "賴有杯中綠，能為面上紅。少年心不遠，只在半酣中。"]'),
('yuding-83','送盧郎中赴河東裴令公幕','白居易','唐','御定全唐诗','yuding','','[]','別時暮雨洛橋岸，到日涼風汾水波。',32,'御定全唐詩/json/456.json','["別時暮雨洛橋岸，到日涼風汾水波。", "荀令見君應問我，為言秋草閉門多。"]'),
('yuding-84','送李滁州','白居易','唐','御定全唐诗','yuding','','[]','君于覺路深留意，我亦禪門薄致功。未悟病時須去病，',40,'御定全唐詩/json/456.json','["君于覺路深留意，我亦禪門薄致功。未悟病時須去病，", "誰道三年千里別，兩心同在道場中。"]'),
('yuding-85','長齋月滿寄思黯','白居易','唐','御定全唐诗','yuding','','[]','一日不見如三月，一月相思如七年。似隔山河千里地，',24,'御定全唐詩/json/456.json','["一日不見如三月，一月相思如七年。似隔山河千里地，"]'),
('yuding-86','冬夜對酒寄皇甫十','白居易','唐','御定全唐诗','yuding','','[]','霜殺中庭草，冰生後院池。有風空動樹，無葉可辭枝。',48,'御定全唐詩/json/456.json','["霜殺中庭草，冰生後院池。有風空動樹，無葉可辭枝。", "十月苦長夜，百年強半時。新開一瓶酒，那得不相思。"]'),
('yuding-87','歲除夜對酒','白居易','唐','御定全唐诗','yuding','','[]','衰翁歲除夜，對酒思悠然。草白經霜地，雲黃欲雪天。',48,'御定全唐詩/json/456.json','["衰翁歲除夜，對酒思悠然。草白經霜地，雲黃欲雪天。", "醉依香枕坐，慵傍暖爐眠。洛下閑來久，明朝是十年。"]'),
('yuding-0','寄獻北都留守裴令公','白居易','唐','御定全唐诗','yuding','','[]','天上中台正，人間一品高。休明值堯舜，勳業過蕭曹。',480,'御定全唐詩/json/457.json','["天上中台正，人間一品高。休明值堯舜，勳業過蕭曹。", "始擅文三捷，終兼武六韜。動人名赫赫，憂國意忉忉。", "蕩蔡擒封豕，平齊斬巨鼇。兩河收土宇，四海定波濤。", "寵重移宮龠，恩新換閫旄。保厘東宅靜，守護北門牢。", "晉國封疆闊，並州士馬豪。胡兵驚赤幟，邊雁避烏號。", "令下流如水，仁沾澤似膏。路喧歌五袴，軍醉感單醪。", "將校森貔武，賓僚儼雋髦。客無煩夜柝，吏不犯秋毫。", "神在台駘助，魂亡獫狁逃。德星銷彗孛，霖雨滅腥臊。", "烽戍高臨代，關河遠控洮。汾雲晴漠漠，朔吹冷颾颾。", "豹尾交牙戟，虯須捧佩刀。通天白犀帶，照地紫麟袍。", "羌管吹楊柳，燕姬酌蒲萄。銀含鑿落盞，金屑琵琶槽。", "遙想從軍樂，應忘報國勞。紫微留北闕，綠野寄東皋。", "忽憶前時會，多慚下客叨。清宵陪宴話，美景從遊遨。", "花月還同賞，琴詩雅自操。朱弦拂宮征，洪筆振風騷。", "近竹開方丈，依林架桔槔。春池八九曲，畫舫兩三艘。", "徑滑苔黏屐，潭深水沒篙。綠絲縈岸柳，紅粉映樓桃。", "為穆先陳醴，招劉共藉糟。舞鬟金翡翠，歌頸玉蠐螬。", "盛德終難過，明時豈易遭。公雖慕張範，帝未舍伊皋。", "眷戀心方結，踟躕首已搔。鸞皇上寥廓，燕雀任蓬蒿。", "欲獻文狂簡，徒煩思郁陶。可憐四百字，輕重抵鴻毛。"]'),
('yuding-1','和東川楊慕巢尚書府中獨坐感戚在懷見寄十四韻','白居易','唐','御定全唐诗','yuding','','[]','我是知君者，君今意若何。窮通時不定，苦樂事相和。',168,'御定全唐詩/json/457.json','["我是知君者，君今意若何。窮通時不定，苦樂事相和。", "東蜀歡殊渥，西江歎逝波。只緣榮貴極，翻使感傷多。", "行斷風驚雁，年侵日下坡。片心休慘戚，雙鬢已蹉跎。", "紫綬黃金印，青幢白玉珂。老將榮補貼，愁用道銷磨。", "外府饒杯酒，中堂有綺羅。應須引滿飲，何不放狂歌。", "錦水通巴峽，香山對洛河。將軍馳鐵馬，少傅步銅駝。", "深契憐松竹，高情憶薜蘿。懸車年甚遠，未敢故相過。"]'),
('yuding-2','分司洛中多暇數與諸客宴遊醉後狂吟偶成十韻因招夢得賓客兼呈思黯奇章公','白居易','唐','御定全唐诗','yuding','','[]','性與時相遠，身將世兩忘。寄名朝士籍，寓興少年場。',120,'御定全唐詩/json/457.json','["性與時相遠，身將世兩忘。寄名朝士籍，寓興少年場。", "老豈無談笑，貧猶有酒漿。隨時來伴侶，逐日用風光。", "數數游何爽，些些病未妨。天教榮啟樂，人恕接輿狂。", "改業為逋客，移家住醉鄉。不論招夢得，兼擬誘奇章。", "要路風波險，權門市井忙。世間無可戀，不是不思量。"]'),
('yuding-3','小歲日喜談氏外孫女孩滿月','白居易','唐','御定全唐诗','yuding','','[]','今旦夫妻喜，他人豈得知。自嗟生女晚，敢訝見孫遲。',72,'御定全唐詩/json/457.json','["今旦夫妻喜，他人豈得知。自嗟生女晚，敢訝見孫遲。", "物以稀為貴，情因老更慈。新年逢吉日，滿月乞名時。", "桂燎熏花果，蘭湯洗玉肌。懷中有可抱，何必是男兒。"]'),
('yuding-4','閑吟贈皇甫郎中親家翁','白居易','唐','御定全唐诗','yuding','','[]','誰能嗟歎光陰暮，豈複憂愁活計貧。忽忽不知頭上事，',40,'御定全唐詩/json/457.json','["誰能嗟歎光陰暮，豈複憂愁活計貧。忽忽不知頭上事，", "最喜兩家婚嫁畢，一時抽得尚平身。"]'),
('yuding-5','夢得臥病，攜酒相尋，先以此寄','白居易','唐','御定全唐诗','yuding','','[]','病來知少客，誰可以為娛。日晏開門未，秋寒有酒無。',48,'御定全唐詩/json/457.json','["病來知少客，誰可以為娛。日晏開門未，秋寒有酒無。", "自宜相慰問，何必待招呼。小疾無妨飲，還須挈一壺。"]'),
('yuding-6','酬思黯戲贈同用狂字','白居易','唐','御定全唐诗','yuding','','[]','鐘乳三千兩，金釵十二行。妒他心似火，欺我鬢如霜。',48,'御定全唐詩/json/457.json','["鐘乳三千兩，金釵十二行。妒他心似火，欺我鬢如霜。", "慰老資歌笑，銷愁仰酒漿。眼看狂不得，狂得且須狂。"]'),
('yuding-7','又戲答絕句','白居易','唐','御定全唐诗','yuding','','[]','狂夫與我兩相忘，故態些些亦不妨。',32,'御定全唐詩/json/457.json','["狂夫與我兩相忘，故態些些亦不妨。", "縱酒放歌聊自樂，接輿爭解教人狂。"]'),
('yuding-8','令狐相公與夢得交情素深眷予分亦不淺一聞薨逝相顧泫然旋有使來得前月未歿之前數日書及詩寄贈夢得哀吟悲歎寄情于詩詩成示予感而繼和','白居易','唐','御定全唐诗','yuding','','[]','緘題重疊語殷勤，存沒交親自此分。前月使來猶理命，',40,'御定全唐詩/json/457.json','["緘題重疊語殷勤，存沒交親自此分。前月使來猶理命，", "最感一行絕筆字，尚言千萬樂天君。"]'),
('yuding-9','洛下雪中頻與劉李二賓客宴集，因寄汴州李尚書','白居易','唐','御定全唐诗','yuding','','[]','水南水北雪紛紛，雪裏歡游莫厭頻。日日暗來唯老病，',40,'御定全唐詩/json/457.json','["水南水北雪紛紛，雪裏歡游莫厭頻。日日暗來唯老病，", "今日鄒枚俱在洛，梁園置酒召何人。"]'),
('yuding-10','看夢得題答李侍郎詩詩中有文星之句因戲和之','白居易','唐','御定全唐诗','yuding','','[]','看題錦繡報瓊瑰，俱是人天第一才。',32,'御定全唐詩/json/457.json','["看題錦繡報瓊瑰，俱是人天第一才。", "好遣文星守躔次，亦須防有客星來。"]'),
('yuding-11','閒適','白居易','唐','御定全唐诗','yuding','','[]','祿俸優饒官不卑，就中閒適是分司。風光暖助遊行處，',40,'御定全唐詩/json/457.json','["祿俸優饒官不卑，就中閒適是分司。風光暖助遊行處，", "微躬所要今皆得，只是蹉跎得校遲。"]'),
('yuding-12','戲答思黯','白居易','唐','御定全唐诗','yuding','','[]','何時得見十三弦，待取無雲有月天。',32,'御定全唐詩/json/457.json','["何時得見十三弦，待取無雲有月天。", "願得金波明似鏡，鏡中照出月中仙。"]'),
('yuding-13','酬裴令公贈馬相戲','白居易','唐','御定全唐诗','yuding','','[]','安石風流無奈何，欲將赤驥換青娥。',32,'御定全唐詩/json/457.json','["安石風流無奈何，欲將赤驥換青娥。", "不辭便送東山去，臨老何人與唱歌。"]'),
('yuding-14','新歲贈夢得','白居易','唐','御定全唐诗','yuding','','[]','暮齒忽將及，同心私自憐。漸衰宜減食，已喜更加年。',48,'御定全唐詩/json/457.json','["暮齒忽將及，同心私自憐。漸衰宜減食，已喜更加年。", "紫綬行連袂，籃輿出比肩。與君同甲子，歲酒合誰先。"]'),
('yuding-15','早春持齋，答皇甫十見贈','白居易','唐','御定全唐诗','yuding','','[]','正月晴和風氣新，紛紛已有醉遊人。',32,'御定全唐詩/json/457.json','["正月晴和風氣新，紛紛已有醉遊人。", "帝城花笑長齋客，三十年來負早春。"]'),
('yuding-16','戲贈夢得，兼呈思黯','白居易','唐','御定全唐诗','yuding','','[]','霜鬢莫欺今老矣，一杯莫笑便陶然。陳郎中處為高戶，',40,'御定全唐詩/json/457.json','["霜鬢莫欺今老矣，一杯莫笑便陶然。陳郎中處為高戶，", "月終齋滿誰開素，須擬奇章置一筵。"]'),
('yuding-17','早春憶游思黯南莊，因寄長句','白居易','唐','御定全唐诗','yuding','','[]','南莊勝處心常憶，借問軒車早晚遊。美景難忘竹廊下，',40,'御定全唐詩/json/457.json','["南莊勝處心常憶，借問軒車早晚遊。美景難忘竹廊下，", "若待春深始同賞，鶯殘花落卻堪愁。"]'),
('yuding-18','酬皇甫十早春對雪見贈','白居易','唐','御定全唐诗','yuding','','[]','漠漠複雰雰，東風散玉塵。明催竹窗曉，寒退柳園春。',48,'御定全唐詩/json/457.json','["漠漠複雰雰，東風散玉塵。明催竹窗曉，寒退柳園春。", "綠醞香堪憶，紅爐暖可親。忍心三兩日，莫作破齋人。"]'),
('yuding-19','奉和思黯自題南莊見示兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','謝家別墅最新奇，山展屏風花夾籬。曉月漸沉橋腳底，',40,'御定全唐詩/json/457.json','["謝家別墅最新奇，山展屏風花夾籬。曉月漸沉橋腳底，", "除卻吟詩兩閑客，此中情狀更誰知。"]'),
('yuding-20','送蘄春李十九使君赴郡','白居易','唐','御定全唐诗','yuding','','[]','可憐官職好文詞，五十專城未是遲。曉日鏡前無白髮，',40,'御定全唐詩/json/457.json','["可憐官職好文詞，五十專城未是遲。曉日鏡前無白髮，", "唯共交親開口笑，知君不及洛陽時。"]'),
('yuding-21','自題酒庫','白居易','唐','御定全唐诗','yuding','','[]','野鶴一辭籠，虛舟長任風。送愁還鬧處，移老入閑中。',48,'御定全唐詩/json/457.json','["野鶴一辭籠，虛舟長任風。送愁還鬧處，移老入閑中。", "身更求何事，天將富此翁。此翁何處當，酒庫不曾空。"]'),
('yuding-22','寒食日寄楊東川','白居易','唐','御定全唐诗','yuding','','[]','不知楊六逢寒食，作底歡娛過此辰。兜率寺高宜望月，',40,'御定全唐詩/json/457.json','["不知楊六逢寒食，作底歡娛過此辰。兜率寺高宜望月，", "不使黔婁夫婦看，誇張富貴向何人。"]'),
('yuding-23','醉後聽唱桂華曲','白居易','唐','御定全唐诗','yuding','','[]','桂華詞意苦丁寧，唱到常娥醉便醒。',32,'御定全唐詩/json/457.json','["桂華詞意苦丁寧，唱到常娥醉便醒。", "此是人間腸斷曲，莫教不得意人聽。"]'),
('yuding-24','酬夢得以予五月長齋延僧徒絕賓友見戲十韻','白居易','唐','御定全唐诗','yuding','','[]','賓客懶逢迎，翛然池館清。簷閒空燕語，林靜未蟬鳴。',120,'御定全唐詩/json/457.json','["賓客懶逢迎，翛然池館清。簷閒空燕語，林靜未蟬鳴。", "葷血還休食，杯觴亦罷傾。三春多放逸，五月暫修行。", "香印朝煙細，紗燈夕焰明。交遊諸長老，師事古先生。", "禪後心彌寂，齋來體更輕。不唯忘肉味，兼擬滅風情。", "蒙以聲聞待，難將戲論爭。虛空若有佛，靈運恐先成。"]'),
('yuding-25','奉和裴令公三月上巳日游太原龍泉憶去歲禊洛見示之作','白居易','唐','御定全唐诗','yuding','','[]','去歲暮春上巳，共泛洛水中流。今歲暮春上巳，',43,'御定全唐詩/json/457.json','["去歲暮春上巳，共泛洛水中流。今歲暮春上巳，", "丞相府歸晉國，太行山礙並州。鵬背負天龜曳尾，"]'),
('yuding-26','又和令公新開龍泉晉水二池','白居易','唐','御定全唐诗','yuding','','[]','舊有潢汙泊，今為白水塘。笙歌聞四面，樓閣在中央。',48,'御定全唐詩/json/457.json','["舊有潢汙泊，今為白水塘。笙歌聞四面，樓閣在中央。", "春變煙波色，晴添樹木光。龍泉信為美，莫忘午橋莊。"]'),
('yuding-27','早夏曉興贈夢得','白居易','唐','御定全唐诗','yuding','','[]','窗明簾薄透朝光，臥整巾簪起下床。背壁燈殘經宿焰，',40,'御定全唐詩/json/457.json','["窗明簾薄透朝光，臥整巾簪起下床。背壁燈殘經宿焰，", "一部清商一壺酒，與君明日暖新堂。"]'),
('yuding-28','春日題幹元寺上方最高峰亭','白居易','唐','御定全唐诗','yuding','','[]','危亭絕頂四無鄰，見盡三千世界春。但覺虛空無障礙，',48,'御定全唐詩/json/457.json','["危亭絕頂四無鄰，見盡三千世界春。但覺虛空無障礙，", "賓客暫遊無半日，王侯不到便終身。始知天造空閒境，"]'),
('yuding-29','奉和思黯相公以李蘇州所寄太湖石奇狀絕倫因題二十韻見示兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','錯落複崔嵬，蒼然玉一堆。峰駢仙掌出，罅坼劍門開。',240,'御定全唐詩/json/457.json','["錯落複崔嵬，蒼然玉一堆。峰駢仙掌出，罅坼劍門開。", "峭頂高危矣，盤根下壯哉。精神欺竹樹，氣色壓亭台。", "隱起磷磷狀，凝成瑟瑟胚。廉棱露鋒刃，清越扣瓊瑰。", "岌嶪形將動，巍峨勢欲摧。奇應潛鬼怪，靈合蓄雲雷。", "黛潤沾新雨，斑明點古苔。未曾棲鳥雀，不肯染塵埃。", "尖削琅玕筍，窪剜瑪瑙罍。海神移碣石，畫障簇天臺。", "在世為尤物，如人負逸才。渡江一葦載，入洛五丁推。", "出處雖無意，升沉亦有媒。拔從水府底，置向相庭隈。", "對稱吟詩句，看宜把酒杯。終隨金礪用，不學玉山頹。", "疏傅心偏愛，園公眼屢回。共嗟無此分，虛管太湖來。"]'),
('yuding-30','奉和思黯相公雨後林園四韻見示','白居易','唐','御定全唐诗','yuding','','[]','新晴夏景好，複此池邊地。煙樹綠含滋，水風清有味。',48,'御定全唐詩/json/457.json','["新晴夏景好，複此池邊地。煙樹綠含滋，水風清有味。", "便成林下隱，都忘門前事。騎吏引歸軒，始知身富貴。"]'),
('yuding-31','晚夏閒居，絕無賓客，欲尋夢得，先寄此詩','白居易','唐','御定全唐诗','yuding','','[]','魚筍朝餐飽，蕉紗暑服輕。欲為窗下寢，先傍水邊行。',72,'御定全唐詩/json/457.json','["魚筍朝餐飽，蕉紗暑服輕。欲為窗下寢，先傍水邊行。", "晴引鶴雙舞，秋生蟬一聲。無人解相訪，有酒共誰傾。", "老更諳時事，閑多見物情。只應劉與白，二叟自相迎。"]'),
('yuding-32','寄李蘄州','白居易','唐','御定全唐诗','yuding','','[]','下車書奏龔黃課，動筆詩傳鮑謝風。江郡謳謠誇杜母，',40,'御定全唐詩/json/457.json','["下車書奏龔黃課，動筆詩傳鮑謝風。江郡謳謠誇杜母，", "不道蘄州歌酒少，使君難稱與誰同。"]'),
('yuding-33','酬思黯相公晚夏雨後感秋見贈','白居易','唐','御定全唐诗','yuding','','[]','暮去朝來無歇期，炎涼暗向雨中移。夜長只合愁人覺，',40,'御定全唐詩/json/457.json','["暮去朝來無歇期，炎涼暗向雨中移。夜長只合愁人覺，", "無憂無病身榮貴，何故沉吟亦感時。"]'),
('yuding-34','久雨閑悶，對酒偶吟','白居易','唐','御定全唐诗','yuding','','[]','淒淒苦雨暗銅駝，嫋嫋涼風起漕河。自夏及秋晴日少，',40,'御定全唐詩/json/457.json','["淒淒苦雨暗銅駝，嫋嫋涼風起漕河。自夏及秋晴日少，", "賴有杯中神聖物，百憂無奈十分何。"]'),
('yuding-35','雨後秋涼','白居易','唐','御定全唐诗','yuding','','[]','夜來秋雨後，秋氣颯然新。團扇先辭手，生衣不著身。',48,'御定全唐詩/json/457.json','["夜來秋雨後，秋氣颯然新。團扇先辭手，生衣不著身。", "更添砧引思，難與簟相親。此境誰偏覺，貧閑老瘦人。"]'),
('yuding-36','酬夢得早秋夜對月見寄','白居易','唐','御定全唐诗','yuding','','[]','吾衰寡情趣，君病懶經過。其奈西樓上，新秋明月何。',48,'御定全唐詩/json/457.json','["吾衰寡情趣，君病懶經過。其奈西樓上，新秋明月何。", "庭蕪淒白露，池色澹金波。況是初長夜，東城砧杵多。"]'),
('yuding-37','題謝公東山障子','白居易','唐','御定全唐诗','yuding','','[]','賢愚共在浮生內，貴賤同趨群動間。多見忙時已衰病，',40,'御定全唐詩/json/457.json','["賢愚共在浮生內，貴賤同趨群動間。多見忙時已衰病，", "唯有風流謝安石，拂衣攜妓入東山。"]'),
('yuding-38','謝楊東川寄衣服','白居易','唐','御定全唐诗','yuding','','[]','年年衰老交遊少，處處蕭條書信稀。',32,'御定全唐詩/json/457.json','["年年衰老交遊少，處處蕭條書信稀。", "唯有巢兄不相忘，春茶未斷寄秋衣。"]'),
('yuding-39','詠懷寄皇甫朗之','白居易','唐','御定全唐诗','yuding','','[]','老大多情足往還，招僧待客夜開關。學調氣後衰中健，',40,'御定全唐詩/json/457.json','["老大多情足往還，招僧待客夜開關。學調氣後衰中健，", "與君別有相知分，同置身於木雁間。"]'),
('yuding-40','東城晚歸','白居易','唐','御定全唐诗','yuding','','[]','一條邛杖懸龜榼，雙角吳童控馬銜。',32,'御定全唐詩/json/457.json','["一條邛杖懸龜榼，雙角吳童控馬銜。", "晚入東城誰識我，短靴低帽白蕉衫。"]'),
('yuding-41','與夢得沽酒閑飲，且約後期','白居易','唐','御定全唐诗','yuding','','[]','少時猶不憂生計，老後誰能惜酒錢。共把十千沽一鬥，',40,'御定全唐詩/json/457.json','["少時猶不憂生計，老後誰能惜酒錢。共把十千沽一鬥，", "更待菊黃家醞熟，共君一醉一陶然。"]'),
('yuding-42','與牛家妓樂雨後合宴','白居易','唐','御定全唐诗','yuding','','[]','玉管清弦聲旖旎，翠釵紅袖坐參差。兩家合奏洞房夜，',40,'御定全唐詩/json/457.json','["玉管清弦聲旖旎，翠釵紅袖坐參差。兩家合奏洞房夜，", "人間歡樂無過此，上界西方即不知。"]'),
('yuding-43','和楊六尚書喜兩弟漢公轉吳興魯士賜章服命賓開宴用慶恩榮賦長句見示','白居易','唐','御定全唐诗','yuding','','[]','華筵賀客日紛紛，劍外歡娛洛下聞。朱紱寵光新照地，',40,'御定全唐詩/json/457.json','["華筵賀客日紛紛，劍外歡娛洛下聞。朱紱寵光新照地，", "感羨料應知我意，今生此事不如君。"]'),
('yuding-44','自詠','白居易','唐','御定全唐诗','yuding','','[]','須白麵微紅，醺醺半醉中。百年隨手過，萬事轉頭空。',48,'御定全唐詩/json/457.json','["須白麵微紅，醺醺半醉中。百年隨手過，萬事轉頭空。", "臥疾瘦居士，行歌狂老翁。仍聞好事者，將我畫屏風。"]'),
('yuding-45','夢得相過援琴命酒因彈秋思偶詠所懷兼寄繼之待價二相府','白居易','唐','御定全唐诗','yuding','','[]','閒居靜侶偶相招，小飲初酣琴欲調。我正風前弄秋思，',40,'御定全唐詩/json/457.json','["閒居靜侶偶相招，小飲初酣琴欲調。我正風前弄秋思，", "雙鳳棲梧魚在藻，飛沈隨分各逍遙。"]'),
('yuding-46','九月八日酬皇甫十見贈','白居易','唐','御定全唐诗','yuding','','[]','君方對酒綴詩章，我正持齋坐道場。處處追遊雖不去，',40,'御定全唐詩/json/457.json','["君方對酒綴詩章，我正持齋坐道場。處處追遊雖不去，", "惆悵東籬不同醉，陶家明日是重陽。"]'),
('yuding-47','慕巢尚書書云室人欲為置一歌者非所安也以詩相報因而和之','白居易','唐','御定全唐诗','yuding','','[]','東川已過二三春，南國須求一兩人。富貴大都多老大，',40,'御定全唐詩/json/457.json','["東川已過二三春，南國須求一兩人。富貴大都多老大，", "他日相逢一杯酒，尊前還要落梁塵。"]'),
('yuding-48','杪秋獨夜','白居易','唐','御定全唐诗','yuding','','[]','無限少年非我伴，可憐清夜與誰同。歡娛牢落中心少，',40,'御定全唐詩/json/457.json','["無限少年非我伴，可憐清夜與誰同。歡娛牢落中心少，", "前頭更有蕭條物，老菊衰蘭三兩叢。"]'),
('yuding-49','憑李睦州訪徐凝山人','白居易','唐','御定全唐诗','yuding','','[]','郡守輕詩客，鄉人薄釣翁。解憐徐處士，唯有李郎中。',24,'御定全唐詩/json/457.json','["郡守輕詩客，鄉人薄釣翁。解憐徐處士，唯有李郎中。"]'),
('yuding-50','蘇州故吏','白居易','唐','御定全唐诗','yuding','','[]','江南故吏別來久，今日池邊識我無。',32,'御定全唐詩/json/457.json','["江南故吏別來久，今日池邊識我無。", "不獨使君頭似雪，華亭鶴死白蓮枯。"]'),
('yuding-51','得楊湖州書頗誇撫民接賓縱酒題詩因以絕句戲之','白居易','唐','御定全唐诗','yuding','','[]','豈獨愛民兼愛客，不唯能飲又能文。',32,'御定全唐詩/json/457.json','["豈獨愛民兼愛客，不唯能飲又能文。", "白蘋洲上春傳語，柳使君輸楊使君。"]'),
('yuding-52','天宮閣秋晴晚望','白居易','唐','御定全唐诗','yuding','','[]','洛城秋霽後，梵閣暮登時。此日風煙好，今秋節候遲。',48,'御定全唐詩/json/457.json','["洛城秋霽後，梵閣暮登時。此日風煙好，今秋節候遲。", "霞光紅泛豔，樹影碧參差。莫慮言歸晚，牛家有宿期。"]'),
('yuding-53','酬夢得暮秋晴夜對月相憶','白居易','唐','御定全唐诗','yuding','','[]','霽月光如練，盈庭複滿池。秋深無熱後，夜淺未寒時。',48,'御定全唐詩/json/457.json','["霽月光如練，盈庭複滿池。秋深無熱後，夜淺未寒時。", "露葉團荒菊，風枝落病梨。相思懶相訪，應是各年衰。"]'),
('yuding-54','同夢得和思黯見贈來詩中先敘三人同讌之歡次有歎鬢髮漸衰嫌孫子催老之意因酬妍唱兼吟鄙懷','白居易','唐','御定全唐诗','yuding','','[]','醉伴騰騰白與劉，何朝何夕不同遊。留連燈下明猶飲，',40,'御定全唐詩/json/457.json','["醉伴騰騰白與劉，何朝何夕不同遊。留連燈下明猶飲，", "教他伯道爭存活，無子無孫亦白頭。"]'),
('yuding-55','聽歌','白居易','唐','御定全唐诗','yuding','','[]','管妙弦清歌入雲，老人合眼醉醺醺。',32,'御定全唐詩/json/457.json','["管妙弦清歌入雲，老人合眼醉醺醺。", "誠知不及當年聽，猶覺聞時勝不聞。"]'),
('yuding-56','三年冬隨事鋪設小堂寢處稍似穩暖因念衰病偶吟所懷','白居易','唐','御定全唐诗','yuding','','[]','小宅非全陋，中堂不甚卑。聊堪會親族，足以貯妻兒。',96,'御定全唐詩/json/457.json','["小宅非全陋，中堂不甚卑。聊堪會親族，足以貯妻兒。", "暖帳迎冬設，溫爐向夜施。裘新青兔褐，褥軟白猿皮。", "似鹿眠深草，如雞宿穩枝。逐身安枕席，隨事有屏帷。", "病致衰殘早，貧營活計遲。由來蠶老後，方是繭成時。"]'),
('yuding-57','初冬即事呈夢得','白居易','唐','御定全唐诗','yuding','','[]','青氈帳暖喜微雪，紅地爐深宜早寒。走筆小詩能和否，',40,'御定全唐詩/json/457.json','["青氈帳暖喜微雪，紅地爐深宜早寒。走筆小詩能和否，", "臨老交親零落盡，希君恕我取人寬。"]'),
('yuding-58','自罷河南已換七尹每一入府悵然舊遊因宿內廳偶題西壁兼呈韋尹常侍','白居易','唐','御定全唐诗','yuding','','[]','每日河南府，依然似到家。杯嘗七尹酒，樹看十年花。',72,'御定全唐詩/json/457.json','["每日河南府，依然似到家。杯嘗七尹酒，樹看十年花。", "且健須歡喜，雖衰莫歎嗟。迎門無故吏，侍坐有新娃。", "暖閣謀宵宴，寒庭放晚衙。主人留宿定，一任夕陽斜。"]'),
('yuding-59','天寒晚起引酌詠懷寄許州王尚書、汝州李常侍','白居易','唐','御定全唐诗','yuding','','[]','葉覆冰池雪滿山，日高慵起未開關。寒來更亦無過醉，',40,'御定全唐詩/json/457.json','["葉覆冰池雪滿山，日高慵起未開關。寒來更亦無過醉，", "相思莫忘櫻桃會，一放狂歌一破顏。"]'),
('yuding-60','四年春','白居易','唐','御定全唐诗','yuding','','[]','柳梢黃嫩草芽新，又入開成第四春。近日放慵多不出，',40,'御定全唐詩/json/457.json','["柳梢黃嫩草芽新，又入開成第四春。近日放慵多不出，", "時輩推遷年事到，往還多是白頭人。"]'),
('yuding-61','白髮','白居易','唐','御定全唐诗','yuding','','[]','白髮生來三十年，而今須鬢盡皤然。歌吟終日如狂叟，',40,'御定全唐詩/json/457.json','["白髮生來三十年，而今須鬢盡皤然。歌吟終日如狂叟，", "其餘便被春收拾，不作閒遊即醉眠。"]'),
('yuding-62','追歡偶作','白居易','唐','御定全唐诗','yuding','','[]','追歡逐樂少閒時，補貼平生得事遲。何處花開曾後看，',48,'御定全唐詩/json/457.json','["追歡逐樂少閒時，補貼平生得事遲。何處花開曾後看，", "十聽春啼變鶯舌，三嫌老醜換蛾眉。樂天一過難知分，"]'),
('yuding-63','公垂尚書以白馬見寄，光潔穩善，以詩謝之','白居易','唐','御定全唐诗','yuding','','[]','翩翩白馬稱金羈，領綴銀花尾曳絲。毛色鮮明人盡愛，',40,'御定全唐詩/json/457.json','["翩翩白馬稱金羈，領綴銀花尾曳絲。毛色鮮明人盡愛，", "不蹶不驚行步穩，最宜山簡醉中騎。"]'),
('yuding-64','西樓獨立','白居易','唐','御定全唐诗','yuding','','[]','身著白衣頭似雪，時時醉立小樓中。',32,'御定全唐詩/json/457.json','["身著白衣頭似雪，時時醉立小樓中。", "路人回顧應相怪，十一年來見此翁。"]'),
('yuding-65','書事詠懷','白居易','唐','御定全唐诗','yuding','','[]','官俸將生計，雖貧豈敢嫌。金多輸陸賈，酒足勝陶潛。',72,'御定全唐詩/json/457.json','["官俸將生計，雖貧豈敢嫌。金多輸陸賈，酒足勝陶潛。", "床暖僧敷坐，樓晴妓捲簾。日遭齋破用，春賴閏加添。", "老向歡彌切，狂于飲不廉。十年閑未足，亦恐涉無厭。"]'),
('yuding-66','酬夢得比萱草見贈','白居易','唐','御定全唐诗','yuding','','[]','杜康能散悶，萱草解忘憂。借問萱逢杜，何如白見劉。',48,'御定全唐詩/json/457.json','["杜康能散悶，萱草解忘憂。借問萱逢杜，何如白見劉。", "老衰勝少夭，閑樂笑忙愁。試問同年內，何人得白頭。"]'),
('yuding-67','問皇甫十','白居易','唐','御定全唐诗','yuding','','[]','苦樂心由我，窮通命任他。坐傾張翰酒，行唱接輿歌。',48,'御定全唐詩/json/457.json','["苦樂心由我，窮通命任他。坐傾張翰酒，行唱接輿歌。", "榮盛傍看好，優閑自適多。知君能斷事，勝負兩如何。"]'),
('yuding-68','早春獨登天宮閣','白居易','唐','御定全唐诗','yuding','','[]','天宮日暖閣門開，獨上迎春飲一杯。',32,'御定全唐詩/json/457.json','["天宮日暖閣門開，獨上迎春飲一杯。", "無限遊人遙怪我，緣何最老最先來。"]'),
('yuding-69','送蘇州李使君赴郡二絕句','白居易','唐','御定全唐诗','yuding','','[]','憶拋印綬辭吳郡，衰病當時已有餘。',64,'御定全唐詩/json/457.json','["憶拋印綬辭吳郡，衰病當時已有餘。", "今日賀君兼自喜，八回看換舊銅魚。", "館娃宮深春日長，烏鵲橋高秋夜涼。", "風月不知人世變，奉君直似奉吳王。"]'),
('yuding-70','長洲曲新詞','白居易','唐','御定全唐诗','yuding','','[]','茂苑綺羅佳麗地，女湖桃李豔陽時。',32,'御定全唐詩/json/457.json','["茂苑綺羅佳麗地，女湖桃李豔陽時。", "心奴已死胡容老，後輩風流是阿誰。"]'),
('yuding-71','《憶江南詞三首','白居易','唐','御定全唐诗','yuding','','[]','江南好，風景舊曾諳。日出江花紅勝火，春來江水綠如藍。',96,'御定全唐詩/json/457.json','["江南好，風景舊曾諳。日出江花紅勝火，春來江水綠如藍。", "能不憶江南？", "江南憶，最憶是杭州。山寺月中尋桂子，郡亭枕上看潮頭。", "何日更重遊？", "江南憶，其次憶吳宮。吳酒一杯春竹葉，吳娃雙舞醉芙蓉。", "早晚複相逢。"]'),
('yuding-0','病中詩十五首：初病風','白居易','唐','御定全唐诗','yuding','','[]','六十八衰翁，乘衰百疾攻。朽株難免蠹，空穴易來風。',48,'御定全唐詩/json/458.json','["六十八衰翁，乘衰百疾攻。朽株難免蠹，空穴易來風。", "肘痹宜生柳，頭旋劇轉蓬。恬然不動處，虛白在胸中。"]'),
('yuding-1','病中詩十五首：枕上作','白居易','唐','御定全唐诗','yuding','','[]','風疾侵淩臨老頭，血凝筋滯不調柔。甘從此後支離臥，',48,'御定全唐詩/json/458.json','["風疾侵淩臨老頭，血凝筋滯不調柔。甘從此後支離臥，", "浩氣自能充靜室，驚飆何必蕩虛舟。腹空先進松花酒，"]'),
('yuding-2','病中詩十五首：答閑上人來問因何風疾','白居易','唐','御定全唐诗','yuding','','[]','一床方丈向陽開，勞動文殊問疾來。',32,'御定全唐詩/json/458.json','["一床方丈向陽開，勞動文殊問疾來。", "欲界凡夫何足道，四禪天始免風災。"]'),
('yuding-3','病中詩十五首：病中五絕句','白居易','唐','御定全唐诗','yuding','','[]','世間生老病相隨，此事心中久自知。',160,'御定全唐詩/json/458.json','["世間生老病相隨，此事心中久自知。", "今日行年將七十，猶須慚愧病來遲。", "方寸成灰鬢作絲，假如強健亦何為。", "家無憂累身無事，正是安閒好病時。", "李君墓上松應拱，元相池頭竹盡枯。", "多幸樂天今始病，不知合要苦治無。", "目昏思寢即安眠，足軟妨行便坐禪。", "身作醫王心是藥，不勞和扁到門前。", "交親不要苦相憂，亦擬時時強出遊。", "但有心情何用腳，陸乘肩輿水乘舟。"]'),
('yuding-4','病中詩十五首：送嵩客','白居易','唐','御定全唐诗','yuding','','[]','登山臨水分無期，泉石煙霞今屬誰。',32,'御定全唐詩/json/458.json','["登山臨水分無期，泉石煙霞今屬誰。", "君到嵩陽吟此句，與教二十六峰知。"]'),
('yuding-5','病中詩十五首：罷灸','白居易','唐','御定全唐诗','yuding','','[]','病身佛說將何喻，變滅須臾豈不聞。',32,'御定全唐詩/json/458.json','["病身佛說將何喻，變滅須臾豈不聞。", "莫遣淨名知我笑，休將火艾灸浮雲。"]'),
('yuding-6','病中詩十五首：賣駱馬','白居易','唐','御定全唐诗','yuding','','[]','五年花下醉騎行，臨賣回頭嘶一聲。',32,'御定全唐詩/json/458.json','["五年花下醉騎行，臨賣回頭嘶一聲。", "項籍顧騅猶解歎，樂天別駱豈無情。"]'),
('yuding-7','病中詩十五首：別柳枝','白居易','唐','御定全唐诗','yuding','','[]','兩枝楊柳小樓中，嫋嫋多年伴醉翁。',32,'御定全唐詩/json/458.json','["兩枝楊柳小樓中，嫋嫋多年伴醉翁。", "明日放歸歸去後，世間應不要春風。"]'),
('yuding-8','病中詩十五首：就暖偶酌戲諸詩酒舊侶','白居易','唐','御定全唐诗','yuding','','[]','低屏軟褥臥藤床，舁向前軒就日陽。一足任他為外物，',40,'御定全唐詩/json/458.json','["低屏軟褥臥藤床，舁向前軒就日陽。一足任他為外物，", "細酌徐吟猶得在，舊遊未必便相忘。"]'),
('yuding-9','病中詩十五首：歲暮呈思黯相公、皇甫朗之及夢得尚書','白居易','唐','御定全唐诗','yuding','','[]','歲暮皤然一老夫，十分流輩九分無。',32,'御定全唐詩/json/458.json','["歲暮皤然一老夫，十分流輩九分無。", "莫嫌身病人扶侍，猶勝無身可遣扶。"]'),
('yuding-10','病中詩十五首：自解','白居易','唐','御定全唐诗','yuding','','[]','房傳往世為禪客，王道前生應畫師。我亦定中觀宿命，',24,'御定全唐詩/json/458.json','["房傳往世為禪客，王道前生應畫師。我亦定中觀宿命，"]'),
('yuding-11','歲暮病懷贈夢得','白居易','唐','御定全唐诗','yuding','','[]','十年四海故交親，零落唯殘兩病身。共遣數奇從是命，',40,'御定全唐詩/json/458.json','["十年四海故交親，零落唯殘兩病身。共遣數奇從是命，", "新樂堂前舊池上，相過亦不要他人。"]'),
('yuding-12','雪後過集賢裴令公舊宅有感','白居易','唐','御定全唐诗','yuding','','[]','梁王捐館後，枚叟過門時。有淚人還泣，無情雪不知。',48,'御定全唐詩/json/458.json','["梁王捐館後，枚叟過門時。有淚人還泣，無情雪不知。", "台亭留盡在，賓客散何之。唯有蕭條雁，時來下故池。"]'),
('yuding-13','酬夢得貧居詠懷見贈','白居易','唐','御定全唐诗','yuding','','[]','歲陰生計兩蹉跎，相顧悠悠醉且歌。廚冷難留烏止屋，',40,'御定全唐詩/json/458.json','["歲陰生計兩蹉跎，相顧悠悠醉且歌。廚冷難留烏止屋，", "日望揮金賀新命，俸錢依舊又如何。"]'),
('yuding-14','酬夢得見喜疾瘳','白居易','唐','御定全唐诗','yuding','','[]','暖臥摩綿褥，晨傾藥酒螺。昏昏布裘底，病醉睡相和。',48,'御定全唐詩/json/458.json','["暖臥摩綿褥，晨傾藥酒螺。昏昏布裘底，病醉睡相和。", "末疾徒云爾，餘年有幾何。須知差與否，相去校無多。"]'),
('yuding-15','夜聞箏中彈瀟湘送神曲感舊','白居易','唐','御定全唐诗','yuding','','[]','縹緲巫山女，歸來七八年。殷勤湘水曲，留在十三弦。',48,'御定全唐詩/json/458.json','["縹緲巫山女，歸來七八年。殷勤湘水曲，留在十三弦。", "苦調吟還出，深情咽不傳。萬重雲水思，今夜月明前。"]'),
('yuding-16','感蘇州舊舫','白居易','唐','御定全唐诗','yuding','','[]','畫梁朽折紅窗破，獨立池邊盡日看。',32,'御定全唐詩/json/458.json','["畫梁朽折紅窗破，獨立池邊盡日看。", "守得蘇州船舫爛，此身爭合不衰殘。"]'),
('yuding-17','感舊石上字','白居易','唐','御定全唐诗','yuding','','[]','閑撥船行尋舊池，幽情往事複誰知。',32,'御定全唐詩/json/458.json','["閑撥船行尋舊池，幽情往事複誰知。", "太湖石上鐫三字，十五年前陳結之。"]'),
('yuding-18','見敏中初到邠寧秋日登城樓詩詩中頗多鄉思因以寄和','白居易','唐','御定全唐诗','yuding','','[]','想爾到邊頭，蕭條正值秋。二年貧禦史，八月古邠州。',48,'御定全唐詩/json/458.json','["想爾到邊頭，蕭條正值秋。二年貧禦史，八月古邠州。", "絲管聞雖樂，風沙見亦愁。望鄉心若苦，不用數登樓。"]'),
('yuding-19','齋戒','白居易','唐','御定全唐诗','yuding','','[]','每因齋戒斷葷腥，漸覺塵勞染愛輕。六賊定知無氣色，',40,'御定全唐詩/json/458.json','["每因齋戒斷葷腥，漸覺塵勞染愛輕。六賊定知無氣色，", "從此始堪為弟子，竺幹師是古先生。"]'),
('yuding-20','戲禮經老僧','白居易','唐','御定全唐诗','yuding','','[]','香火一爐燈一盞，白頭夜禮佛名經。',32,'御定全唐詩/json/458.json','["香火一爐燈一盞，白頭夜禮佛名經。", "何年飲著聲聞酒，直到如今醉未醒。"]'),
('yuding-21','近見慕巢尚書詩中屢有歎老思退之意又於洛下新置郊居然寵寄方深歸心大速因以長句戲而諭之','白居易','唐','御定全唐诗','yuding','','[]','近見詩中歎白髮，遙知閫外憶東都。煙霞偷眼窺來久，',40,'御定全唐詩/json/458.json','["近見詩中歎白髮，遙知閫外憶東都。煙霞偷眼窺來久，", "應須待到懸車歲，然後東歸伴老夫。"]'),
('yuding-22','對鏡偶吟，贈張道士抱元','白居易','唐','御定全唐诗','yuding','','[]','閑來對鏡自思量，年貌衰殘分所當。白髮萬莖何所怪，',40,'御定全唐詩/json/458.json','["閑來對鏡自思量，年貌衰殘分所當。白髮萬莖何所怪，", "今日逢師雖已晚，枕中治老有何方。"]'),
('yuding-23','病入新正','白居易','唐','御定全唐诗','yuding','','[]','枕上驚新歲，花前念舊歡。是身老所逼，非意病相干。',48,'御定全唐詩/json/458.json','["枕上驚新歲，花前念舊歡。是身老所逼，非意病相干。", "風月情猶在，杯觴興漸闌。便休心未伏，更試一春看。"]'),
('yuding-24','臥疾來早晚','白居易','唐','御定全唐诗','yuding','','[]','臥疾來早晚，懸懸將十旬。婢能尋本草，犬不吠醫人。',48,'御定全唐詩/json/458.json','["臥疾來早晚，懸懸將十旬。婢能尋本草，犬不吠醫人。", "酒甕全生醭，歌筵半委塵。風光還欲好，爭向枕前春。"]'),
('yuding-25','強起迎春，戲寄思黯','白居易','唐','御定全唐诗','yuding','','[]','杖策人扶廢病身，晴和強起一迎春。',32,'御定全唐詩/json/458.json','["杖策人扶廢病身，晴和強起一迎春。", "他時蹇跛縱行得，笑殺平原樓上人。"]'),
('yuding-26','夢得前所酬篇有鍊盡美少年之句因思往事兼詠今懷重以長句答之','白居易','唐','御定全唐诗','yuding','','[]','煉盡少年成白首，憶初相識到今朝。昔饒春桂長先折，',40,'御定全唐詩/json/458.json','["煉盡少年成白首，憶初相識到今朝。昔饒春桂長先折，", "聲華寵命人皆得，若個如君曆七朝。"]'),
('yuding-27','病後寒食','白居易','唐','御定全唐诗','yuding','','[]','故紗絳帳舊青氈，藥酒醺醺引醉眠。鬥擻弊袍春晚後，',40,'御定全唐詩/json/458.json','["故紗絳帳舊青氈，藥酒醺醺引醉眠。鬥擻弊袍春晚後，", "拋擲風光負寒食，曾來未省似今年。"]'),
('yuding-28','老病相仍以詩自解','白居易','唐','御定全唐诗','yuding','','[]','榮枯憂喜與彭殤，都是人間戲一場。蟲臂鼠肝猶不怪，',40,'御定全唐詩/json/458.json','["榮枯憂喜與彭殤，都是人間戲一場。蟲臂鼠肝猶不怪，", "還似遠行裝束了，遲回且住亦何妨。"]'),
('yuding-29','皇甫郎中親家翁赴任絳州，宴送出城贈別','白居易','唐','御定全唐诗','yuding','','[]','慕賢入室交先定，結援通家好複成。新婦不嫌貧活計，',40,'御定全唐詩/json/458.json','["慕賢入室交先定，結援通家好複成。新婦不嫌貧活計，", "欲識離群相戀意，為君扶病出都城。"]'),
('yuding-30','春暖','白居易','唐','御定全唐诗','yuding','','[]','風痹宜和暖，春來腳較輕。鶯留花下立，鶴引水邊行。',48,'御定全唐詩/json/458.json','["風痹宜和暖，春來腳較輕。鶯留花下立，鶴引水邊行。", "發少嫌巾重，顏衰訝鏡明。不論親與故，自亦昧平生。"]'),
('yuding-31','殘春晚起，伴客笑談','白居易','唐','御定全唐诗','yuding','','[]','掩戶下簾朝睡足，一聲黃鳥報殘春。披衣岸幘日高起，',40,'御定全唐詩/json/458.json','["掩戶下簾朝睡足，一聲黃鳥報殘春。披衣岸幘日高起，", "莫言病後妨談笑，猶恐多於不病人。"]'),
('yuding-32','送唐州崔使君侍親赴任','白居易','唐','御定全唐诗','yuding','','[]','連持使節曆專城，獨賀崔侯最慶榮。烏府一拋霜簡去，',40,'御定全唐詩/json/458.json','["連持使節曆專城，獨賀崔侯最慶榮。烏府一拋霜簡去，", "唯慮郡齋賓友少，數杯春酒共誰傾。"]'),
('yuding-33','春晚詠懷贈皇甫朗之','白居易','唐','御定全唐诗','yuding','','[]','豔陽時節又蹉跎，遲暮光陰複若何。一歲平分春日少，',40,'御定全唐詩/json/458.json','["豔陽時節又蹉跎，遲暮光陰複若何。一歲平分春日少，", "賴有銷憂治悶藥，君家濃酎我狂歌。"]'),
('yuding-34','春盡日宴罷，感事獨吟','白居易','唐','御定全唐诗','yuding','','[]','五年三月今朝盡，客散筵空獨掩扉。病共樂天相伴住，',40,'御定全唐詩/json/458.json','["五年三月今朝盡，客散筵空獨掩扉。病共樂天相伴住，", "金帶縋腰衫委地，年年衰瘦不勝衣。"]'),
('yuding-35','病中辱崔宣城長句見寄兼有觥綺之贈因以四韻總而酬之','白居易','唐','御定全唐诗','yuding','','[]','劉楨病發經春臥，謝脁詩來盡日吟。三道舊誇收片玉，',40,'御定全唐詩/json/458.json','["劉楨病發經春臥，謝脁詩來盡日吟。三道舊誇收片玉，", "科第門生滿霄漢，歲寒少得似君心。"]'),
('yuding-36','前有別楊柳枝絕句夢得繼和云春盡絮飛留不得隨風好去落誰家又復戲答','白居易','唐','御定全唐诗','yuding','','[]','柳老春深日又斜，任他飛向別人家。',32,'御定全唐詩/json/458.json','["柳老春深日又斜，任他飛向別人家。", "誰能更學孩童戲，尋逐春風捉柳花。"]'),
('yuding-37','池上早夏','白居易','唐','御定全唐诗','yuding','','[]','水積春塘晚，陰交夏木繁。舟船如野渡，籬落似江村。',48,'御定全唐詩/json/458.json','["水積春塘晚，陰交夏木繁。舟船如野渡，籬落似江村。", "靜拂琴床席，香開酒庫門。慵閑無一事，時弄小嬌孫。"]'),
('yuding-38','談氏外孫生三日喜是男偶吟成篇兼戲呈夢得','白居易','唐','御定全唐诗','yuding','','[]','玉芽珠顆小男兒，羅薦蘭湯浴罷時。芣苡春來盈女手，',40,'御定全唐詩/json/458.json','["玉芽珠顆小男兒，羅薦蘭湯浴罷時。芣苡春來盈女手，", "明日貧翁具雞黍，應須酬賽引雛詩。"]'),
('yuding-39','開成大行皇帝挽歌詞四首，奉敕撰進','白居易','唐','御定全唐诗','yuding','','[]','禦宇恢皇化，傳家葉至公。華夷臣妾內，堯舜弟兄中。',184,'御定全唐詩/json/458.json','["禦宇恢皇化，傳家葉至公。華夷臣妾內，堯舜弟兄中。", "制度移民俗，文章變國風。開成與貞觀，實錄事多同。", "晏駕辭雙闕，靈儀出九衢。上雲歸碧落，下席葬蒼梧。", "蓂晚餘堯曆，龜新啟夏圖。三朝聯棣萼，從古帝王無。", "嚴恭七月禮，哀慟萬人心。地感勝秋氣，天愁結夕陰。", "鼎湖龍漸遠，蒙汜日初沈。唯有雲韶樂，長留治世音。", "化成同軌表清平，恩結連枝感聖明。帝與九齡雖吉夢，", "老病龍髯攀不及，東周退傅最傷情。"]'),
('yuding-40','時熱少客，因詠所懷','白居易','唐','御定全唐诗','yuding','','[]','冠櫛心多懶，逢迎興漸微。況當時熱甚，幸遇客來稀。',72,'御定全唐詩/json/458.json','["冠櫛心多懶，逢迎興漸微。況當時熱甚，幸遇客來稀。", "濕灑池邊地，涼開竹下扉。露床青篾簟，風架白蕉衣。", "院靜留僧宿，樓空放妓歸。衰殘強歡宴，此事久知非。"]'),
('yuding-41','宣州崔大夫閤老忽以近詩數十首見示吟諷之下竊有所喜因成長句寄題郡齋','白居易','唐','御定全唐诗','yuding','','[]','謝玄暉歿吟聲寢，郡閣寥寥筆硯閑。無複新詩題壁上，',40,'御定全唐詩/json/458.json','["謝玄暉歿吟聲寢，郡閣寥寥筆硯閑。無複新詩題壁上，", "再喜宣城章句動，飛觴遙賀敬亭山。"]'),
('yuding-42','足疾','白居易','唐','御定全唐诗','yuding','','[]','足疾無加亦不瘳，綿春曆夏複經秋。開顏且酌尊中酒，',40,'御定全唐詩/json/458.json','["足疾無加亦不瘳，綿春曆夏複經秋。開顏且酌尊中酒，", "應須學取陶彭澤，但委心形任去留。"]'),
('yuding-43','晚池泛舟，遇景成詠，贈呂處士','白居易','唐','御定全唐诗','yuding','','[]','岸淺橋平池面寬，飄然輕棹泛澄瀾。風宜扇引開懷入，',40,'御定全唐詩/json/458.json','["岸淺橋平池面寬，飄然輕棹泛澄瀾。風宜扇引開懷入，", "唯憐呂叟時相伴，同把磻溪舊釣竿。"]'),
('yuding-44','夢微之','白居易','唐','御定全唐诗','yuding','','[]','夜來攜手夢同遊，晨起盈巾淚莫收。漳浦老身三度病，',40,'御定全唐詩/json/458.json','["夜來攜手夢同遊，晨起盈巾淚莫收。漳浦老身三度病，", "阿衛韓郎相次去，夜台茫昧得知不。"]'),
('yuding-45','感秋詠意','白居易','唐','御定全唐诗','yuding','','[]','炎涼遷次速如飛，又脫生衣著熟衣。繞壁暗蛩無限思，',40,'御定全唐詩/json/458.json','["炎涼遷次速如飛，又脫生衣著熟衣。繞壁暗蛩無限思，", "舊語相傳聊自慰，世間七十老人稀。"]'),
('yuding-46','老病幽獨，偶吟所懷','白居易','唐','御定全唐诗','yuding','','[]','眼漸昏昏耳漸聾，滿頭霜雪半身風。已將身出浮雲外，',40,'御定全唐詩/json/458.json','["眼漸昏昏耳漸聾，滿頭霜雪半身風。已將身出浮雲外，", "世緣俗念消除盡，別是人間清淨翁。"]'),
('yuding-47','和楊尚書罷相後夏日游永安水亭兼招本曹楊侍郎同行','白居易','唐','御定全唐诗','yuding','','[]','道行無喜退無憂，舒卷如雲得自由。良冶動時為哲匠，',40,'御定全唐詩/json/458.json','["道行無喜退無憂，舒卷如雲得自由。良冶動時為哲匠，", "遙愛翩翩雙紫鳳，入同官署出同遊。"]'),
('yuding-48','在家出家','白居易','唐','御定全唐诗','yuding','','[]','衣食支吾婚嫁畢，從今家事不相仍。夜眠身是投林鳥，',40,'御定全唐詩/json/458.json','["衣食支吾婚嫁畢，從今家事不相仍。夜眠身是投林鳥，", "中宵入定跏趺坐，女喚妻呼多不應。"]'),
('yuding-49','夜涼','白居易','唐','御定全唐诗','yuding','','[]','露白風清庭戶涼，老人先著夾衣裳。',32,'御定全唐詩/json/458.json','["露白風清庭戶涼，老人先著夾衣裳。", "舞腰歌袖拋何處，唯對無弦琴一張。"]'),
('yuding-50','繼之尚書自余病來寄遺非一又蒙覽醉吟先生傳題詩以美之今以此篇用伸酬謝','白居易','唐','御定全唐诗','yuding','','[]','衰殘與世日相疏，惠好唯君分有餘。茶藥贈多因病久，',40,'御定全唐詩/json/458.json','["衰殘與世日相疏，惠好唯君分有餘。茶藥贈多因病久，", "醉傅狂言人盡笑，獨知我者是尚書。"]'),
('yuding-51','五年秋病後獨宿香山寺三絕句','白居易','唐','御定全唐诗','yuding','','[]','經年不到龍門寺，今夜何人知我情。',96,'御定全唐詩/json/458.json','["經年不到龍門寺，今夜何人知我情。", "還向暢師房裏宿，新秋月色舊灘聲。", "飲徒歌伴今何在，雨散雲飛盡不回。", "從此香山風月夜，只應長是一身來。", "石盆泉畔石樓頭，十二年來晝夜遊。", "更過今年年七十，假如無病亦宜休。"]'),
('yuding-52','題香山新經堂招僧','白居易','唐','御定全唐诗','yuding','','[]','煙滿秋堂月滿庭，香花漠漠磬泠泠。',32,'御定全唐詩/json/458.json','["煙滿秋堂月滿庭，香花漠漠磬泠泠。", "誰能來此尋真諦，白老新開一藏經。"]'),
('yuding-53','偶題鄧公','白居易','唐','御定全唐诗','yuding','','[]','偶因攜酒尋村客，聊複回車訪薜蘿。且值雪寒相慰問，',40,'御定全唐詩/json/458.json','["偶因攜酒尋村客，聊複回車訪薜蘿。且值雪寒相慰問，", "一種共翁頭似雪，翁無衣食自如何。"]'),
('yuding-54','早入皇城贈王留守僕射','白居易','唐','御定全唐诗','yuding','','[]','津橋殘月曉沉沉，風露淒清禁署深。',32,'御定全唐詩/json/458.json','["津橋殘月曉沉沉，風露淒清禁署深。", "城柳宮槐謾搖落，悲愁不到貴人心。"]'),
('yuding-55','寄題廬山舊草堂，兼呈二林寺道侶','白居易','唐','御定全唐诗','yuding','','[]','三十年前草堂主，而今雖在鬢如絲。登山尋水應無力，',40,'御定全唐詩/json/458.json','["三十年前草堂主，而今雖在鬢如絲。登山尋水應無力，", "君行過到爐峰下，為報東林長老知。"]'),
('yuding-56','改業','白居易','唐','御定全唐诗','yuding','','[]','先生老去飲無興，居士病來閑有餘。猶覺醉吟多放逸，',40,'御定全唐詩/json/458.json','["先生老去飲無興，居士病來閑有餘。猶覺醉吟多放逸，", "卻被山僧戲相問，一時改業意何如。"]'),
('yuding-57','山下留別佛光和尚','白居易','唐','御定全唐诗','yuding','','[]','勞師送我下山行，此別何人識此情。',32,'御定全唐詩/json/458.json','["勞師送我下山行，此別何人識此情。", "我已七旬師九十，當知後會在他生。"]'),
('yuding-58','山中五絕句：嶺上雲','白居易','唐','御定全唐诗','yuding','','[]','嶺上白雲朝未散，田中青麥旱將枯。',32,'御定全唐詩/json/458.json','["嶺上白雲朝未散，田中青麥旱將枯。", "自生自滅成何事，能逐東風作雨無。"]'),
('yuding-59','山中五絕句：石上苔','白居易','唐','御定全唐诗','yuding','','[]','漠漠斑斑石上苔，幽芳靜綠絕纖埃。',32,'御定全唐詩/json/458.json','["漠漠斑斑石上苔，幽芳靜綠絕纖埃。", "路傍凡草榮遭遇，曾得七香車輾來。"]'),
('yuding-60','山中五絕句：林下樗','白居易','唐','御定全唐诗','yuding','','[]','香檀文桂苦雕鐫，生理何曾得自全。',32,'御定全唐詩/json/458.json','["香檀文桂苦雕鐫，生理何曾得自全。", "知我無材老樗否，一枝不損盡天年。"]'),
('yuding-61','山中五絕句：澗中魚','白居易','唐','御定全唐诗','yuding','','[]','海水桑田欲變時，風濤翻覆沸天池。',32,'御定全唐詩/json/458.json','["海水桑田欲變時，風濤翻覆沸天池。", "鯨吞蛟鬥波成血，深澗游魚樂不知。"]'),
('yuding-62','山中五絕句：洞中蝙蝠','白居易','唐','御定全唐诗','yuding','','[]','千年鼠化白蝙蝠，黑洞深藏避網羅。',32,'御定全唐詩/json/458.json','["千年鼠化白蝙蝠，黑洞深藏避網羅。", "遠害全身誠得計，一生幽暗又如何。"]'),
('yuding-63','自戲三絕句：心問身','白居易','唐','御定全唐诗','yuding','','[]','心問身雲何泰然，嚴冬暖被日高眠。',32,'御定全唐詩/json/458.json','["心問身雲何泰然，嚴冬暖被日高眠。", "放君快活知恩否，不早朝來十一年。"]'),
('yuding-64','自戲三絕句：身報心','白居易','唐','御定全唐诗','yuding','','[]','心是身王身是宮，君今居在我宮中。',32,'御定全唐詩/json/458.json','["心是身王身是宮，君今居在我宮中。", "是君家舍君須愛，何事論恩自說功。"]'),
('yuding-65','自戲三絕句：心重答身','白居易','唐','御定全唐诗','yuding','','[]','因我疏慵休罷早，遣君安樂歲時多。',32,'御定全唐詩/json/458.json','["因我疏慵休罷早，遣君安樂歲時多。", "世間老苦人何限，不放君閑奈我何。"]'),
('yuding-66','會昌元年春五絕句：病後喜過劉家','白居易','唐','御定全唐诗','yuding','','[]','忽憶前年初病後，此生甘分不銜杯。',32,'御定全唐詩/json/458.json','["忽憶前年初病後，此生甘分不銜杯。", "誰能料得今春事，又向劉家飲酒來。"]'),
('yuding-67','會昌元年春五絕句：贈舉之僕射','白居易','唐','御定全唐诗','yuding','','[]','雞球餳粥屢開筵，談笑謳吟間管弦。',32,'御定全唐詩/json/458.json','["雞球餳粥屢開筵，談笑謳吟間管弦。", "一月三回寒食會，春光應不負今年。"]'),
('yuding-68','會昌元年春五絕句：盧尹賀夢得會中作','白居易','唐','御定全唐诗','yuding','','[]','病聞川守賀筵開，起伴尚書飲一杯。',32,'御定全唐詩/json/458.json','["病聞川守賀筵開，起伴尚書飲一杯。", "任意少年長笑我，老人自覓老人來。"]'),
('yuding-69','會昌元年春五絕句：題朗之槐亭','白居易','唐','御定全唐诗','yuding','','[]','春風可惜無多日，家醞唯殘軟半瓶。',32,'御定全唐詩/json/458.json','["春風可惜無多日，家醞唯殘軟半瓶。", "猶望君歸同一醉，籃舁早晚入槐亭。"]'),
('yuding-70','會昌元年春五絕句：勸夢得酒','白居易','唐','御定全唐诗','yuding','','[]','誰人功畫麒麟閣，何客新投魑魅鄉。',32,'御定全唐詩/json/458.json','["誰人功畫麒麟閣，何客新投魑魅鄉。", "兩處榮枯君莫問，殘春更醉兩三場。"]'),
('yuding-71','過裴令公宅二絕句','白居易','唐','御定全唐诗','yuding','','[]','風吹楊柳出牆枝，憶得同歡共醉時。',64,'御定全唐詩/json/458.json','["風吹楊柳出牆枝，憶得同歡共醉時。", "每到集賢坊地過，不曾一度不低眉。", "梁王舊館雪濛濛，愁殺鄒枚二老翁。", "假使明朝深一尺，亦無人到兔園中。"]'),
('yuding-72','百日假滿，少傅官停，自喜言懷','白居易','唐','御定全唐诗','yuding','','[]','長告今朝滿十旬，從茲蕭灑便終身。老嫌手重拋牙笏，',40,'御定全唐詩/json/458.json','["長告今朝滿十旬，從茲蕭灑便終身。老嫌手重拋牙笏，", "人言世事何時了，我是人間事了人。"]'),
('yuding-73','早熱','白居易','唐','御定全唐诗','yuding','','[]','畏景又加旱，火雲殊未收。籬暄饑有雀，池涸渴無鷗。',48,'御定全唐詩/json/458.json','["畏景又加旱，火雲殊未收。籬暄饑有雀，池涸渴無鷗。", "岸幘頭仍痛，褰裳汗亦流。若為當此日，遷客向炎州。"]'),
('yuding-74','題崔少尹上林坊新居','白居易','唐','御定全唐诗','yuding','','[]','坊靜居新深且幽，忽疑縮地到滄洲。宅東籬缺嵩峰出，',40,'御定全唐詩/json/458.json','["坊靜居新深且幽，忽疑縮地到滄洲。宅東籬缺嵩峰出，", "若能為客烹雞黍，願伴田蘇日日遊。"]'),
('yuding-75','新澗亭','白居易','唐','御定全唐诗','yuding','','[]','煙蘿初合澗新開，閑上西亭日幾回。',32,'御定全唐詩/json/458.json','["煙蘿初合澗新開，閑上西亭日幾回。", "老病歸山應未得，且移泉石就身來。"]'),
('yuding-76','對酒有懷寄李十九郎中','白居易','唐','御定全唐诗','yuding','','[]','往年江外拋桃葉，去歲樓中別柳枝。寂寞春來一杯酒，',24,'御定全唐詩/json/458.json','["往年江外拋桃葉，去歲樓中別柳枝。寂寞春來一杯酒，"]'),
('yuding-77','楊六尚書頻寄新詩詩中多有思閒相就之志因書鄙意報而諭之','白居易','唐','御定全唐诗','yuding','','[]','君年殊未及懸車，未合將閑逐老夫。身健正宜金印綬，',40,'御定全唐詩/json/458.json','["君年殊未及懸車，未合將閑逐老夫。身健正宜金印綬，", "進退是非俱是夢，丘中闕下亦何殊。"]'),
('yuding-78','偶吟自慰兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','且喜同年滿七旬，莫嫌衰病莫嫌貧。已為海內有名客，',40,'御定全唐詩/json/458.json','["且喜同年滿七旬，莫嫌衰病莫嫌貧。已為海內有名客，", "尊榮富壽難兼得，閑坐思量最要身。"]'),
('yuding-79','寄潮州楊繼之','白居易','唐','御定全唐诗','yuding','','[]','相府潮陽俱夢中，夢中何者是窮通。',32,'御定全唐詩/json/458.json','["相府潮陽俱夢中，夢中何者是窮通。", "他時事過方應悟，不獨榮空辱亦空。"]'),
('yuding-80','雪暮偶與夢得同致仕裴賓客王尚書飲','白居易','唐','御定全唐诗','yuding','','[]','黃昏慘慘雪霏霏，白首相歡醉不歸。',32,'御定全唐詩/json/458.json','["黃昏慘慘雪霏霏，白首相歡醉不歸。", "四個老人三百歲，人間此會亦應稀。"]'),
('yuding-81','雪朝乘興欲詣李司徒留守，先以五韻戲之','白居易','唐','御定全唐诗','yuding','','[]','夜寒生酒思，曉雪引詩情。熱飲一兩盞，冷吟三五聲。',60,'御定全唐詩/json/458.json','["夜寒生酒思，曉雪引詩情。熱飲一兩盞，冷吟三五聲。", "鋪花憐地凍，銷玉畏天晴。好拂烏巾出，宜披鶴氅行。", "梁園應有興，何不召鄒生。"]'),
('yuding-82','贈思黯','白居易','唐','御定全唐诗','yuding','','[]','為憐清淺愛潺湲，一日三回到水邊。',32,'御定全唐詩/json/458.json','["為憐清淺愛潺湲，一日三回到水邊。", "若道歸仁灘更好，主人何故別三年。"]'),
('yuding-83','聽歌六絕句：聽都子歌','白居易','唐','御定全唐诗','yuding','','[]','都子新歌有性靈，一聲格轉已堪聽。',32,'御定全唐詩/json/458.json','["都子新歌有性靈，一聲格轉已堪聽。", "更聽唱到嫦娥字，猶有樊家舊典刑。"]'),
('yuding-84','聽歌六絕句：樂世','白居易','唐','御定全唐诗','yuding','','[]','管急弦繁拍漸稠，綠腰宛轉曲終頭。',32,'御定全唐詩/json/458.json','["管急弦繁拍漸稠，綠腰宛轉曲終頭。", "誠知樂世聲聲樂，老病人聽未免愁。"]'),
('yuding-85','聽歌六絕句：水調','白居易','唐','御定全唐诗','yuding','','[]','五言一遍最殷勤，調少情多似有因。',32,'御定全唐詩/json/458.json','["五言一遍最殷勤，調少情多似有因。", "不會當時翻曲意，此聲腸斷為何人。"]'),
('yuding-86','聽歌六絕句：想夫憐','白居易','唐','御定全唐诗','yuding','','[]','玉管朱弦莫急催，容聽歌送十分杯。',32,'御定全唐詩/json/458.json','["玉管朱弦莫急催，容聽歌送十分杯。", "長愛夫憐第二句，請君重唱夕陽開。"]'),
('yuding-87','聽歌六絕句：何滿子','白居易','唐','御定全唐诗','yuding','','[]','世傳滿子是人名，臨就刑時曲始成。',32,'御定全唐詩/json/458.json','["世傳滿子是人名，臨就刑時曲始成。", "一曲四調歌八疊，從頭便是斷腸聲。"]'),
('yuding-88','聽歌六絕句：離別難','白居易','唐','御定全唐诗','yuding','','[]','綠楊陌上送行人，馬去車回一望塵。',32,'御定全唐詩/json/458.json','["綠楊陌上送行人，馬去車回一望塵。", "不覺別時紅淚盡，歸來無淚可沾巾。"]'),
('yuding-89','閑樂','白居易','唐','御定全唐诗','yuding','','[]','坐安臥穩輿平肩，倚杖披衫繞四邊。空腹三杯卯後酒，',24,'御定全唐詩/json/458.json','["坐安臥穩輿平肩，倚杖披衫繞四邊。空腹三杯卯後酒，"]'),
('yuding-0','立秋夕涼風忽至炎暑稍消即事詠懷寄汴州節度使李二十尚書','白居易','唐','御定全唐诗','yuding','','[]','嫋嫋簷樹動，好風西南來。紅缸霏微滅，碧幌飄颻開。',132,'御定全唐詩/json/459.json','["嫋嫋簷樹動，好風西南來。紅缸霏微滅，碧幌飄颻開。", "披襟有餘涼，拂簟無纖埃。但喜煩暑退，不惜光陰催。", "河秋稍清淺，月午方裴回。或行或坐臥，體適心悠哉。", "美人在浚都，旌旗繞樓臺。雖非滄溟阻，難見如蓬萊。", "蟬迎節又換，雁送書未回。君位日寵重，我年日摧頹。", "無因風月下，一舉平生杯。"]'),
('yuding-1','開成二年夏聞新蟬贈夢得','白居易','唐','御定全唐诗','yuding','','[]','十載與君別，常感新蟬鳴。今年共君聽，同在洛陽城。',84,'御定全唐詩/json/459.json','["十載與君別，常感新蟬鳴。今年共君聽，同在洛陽城。", "噪處知林靜，聞時覺景清。涼風忽嫋嫋，秋思先秋生。", "殘槿花邊立，老槐陰下行。雖無索居恨，還動長年情。", "且喜未聾耳，年年聞此聲。"]'),
('yuding-2','題牛相公歸仁裏宅新成小灘','白居易','唐','御定全唐诗','yuding','','[]','平生見流水，見此轉留連。況此朱門內，君家新引泉。',144,'御定全唐詩/json/459.json','["平生見流水，見此轉留連。況此朱門內，君家新引泉。", "伊流決一帶，洛石砌千拳。與君三伏月，滿耳作潺湲。", "深處碧磷磷，淺處清濺濺。碕岸束嗚咽，沙汀散淪漣。", "翻浪雪不盡，澄波空共鮮。兩岸灩澦口，一泊瀟湘天。", "曾作天南客，漂流六七年。何山不倚杖，何水不停船。", "巴峽聲心裏，松江色眼前。今朝小灘上，能不思悠然。"]'),
('yuding-3','春日閒居三首','白居易','唐','御定全唐诗','yuding','','[]','陶雲愛吾廬，吾亦愛吾屋。屋中有琴書，聊以慰幽獨。',336,'御定全唐詩/json/459.json','["陶雲愛吾廬，吾亦愛吾屋。屋中有琴書，聊以慰幽獨。", "是時三月半，花落庭蕪綠。舍上晨鳩鳴，窗間春睡足。", "睡足起閑坐，景晏方櫛沐。今日非十齋，庖童饋魚肉。", "饑來恣餐歠，冷熱隨所欲。飽竟快搔爬，筋骸無檢束。", "豈徒暢肢體，兼欲遺耳目。便可傲松喬，何假杯中淥。", "廣池春水準，群魚恣游泳。新林綠陰成，眾鳥欣相鳴。", "時我亦瀟灑，適無累與病。魚鳥人則殊，同歸於遂性。", "緬思山梁雉，時哉感孔聖。聖人不得所，慨然歎時命。", "我今對鱗羽，取樂成謠詠。得所仍得時，吾生一何幸。", "勞者不覺歌，歌其勞苦事。逸者不覺歌，歌其逸樂意。", "問我逸如何，閒居多興味。問我樂如何，閑官少憂累。", "又問俸厚薄，百千隨月至。又問年幾何，七十行欠二。", "所得皆過望，省躬良可愧。馬閑無羈絆，鶴老有祿位。", "設自為化工，優饒只如是。安得不歌詠，默默受天賜。"]'),
('yuding-4','小閣閑坐','白居易','唐','御定全唐诗','yuding','','[]','閣前竹蕭蕭，閣下水潺潺。拂簟捲簾坐，清風生其間。',72,'御定全唐詩/json/459.json','["閣前竹蕭蕭，閣下水潺潺。拂簟捲簾坐，清風生其間。", "靜聞新蟬鳴，遠見飛鳥還。但有巾掛壁，而無客叩關。", "二疏返故里，四老歸舊山。吾亦適所願，求閑而得閒。"]'),
('yuding-5','游平泉宴浥澗，宿香山石樓，贈座客','白居易','唐','御定全唐诗','yuding','','[]','逸少集蘭亭，季倫宴金穀。金谷太繁華，蘭亭闕絲竹。',120,'御定全唐詩/json/459.json','["逸少集蘭亭，季倫宴金穀。金谷太繁華，蘭亭闕絲竹。", "何如今日會，浥澗平泉曲。杯酒與管弦，貧中隨分足。", "紫鮮林筍嫩，紅潤園桃熟。採摘助盤筵，芳滋盈口腹。", "閑吟暮雲碧，醉藉春草綠。舞妙豔流風，歌清叩寒玉。", "古詩惜晝短，勸我令秉燭。是夜勿言歸，相攜石樓宿。"]'),
('yuding-6','池上幽境','白居易','唐','御定全唐诗','yuding','','[]','嫋嫋過水橋，微微入林路。幽境深誰知，老身閑獨步。',72,'御定全唐詩/json/459.json','["嫋嫋過水橋，微微入林路。幽境深誰知，老身閑獨步。", "行行何所愛，遇物自成趣。平滑青磐石，低密綠陰樹。", "石上一素琴，樹下雙草屨。此是榮先生，坐禪三樂處。"]'),
('yuding-7','夏日閑放','白居易','唐','御定全唐诗','yuding','','[]','時暑不出門，亦無賓客至。靜室深下簾，小庭新掃地。',96,'御定全唐詩/json/459.json','["時暑不出門，亦無賓客至。靜室深下簾，小庭新掃地。", "褰裳複岸幘，閑傲得自恣。朝景枕簟清，乘涼一覺睡。", "午餐何所有，魚肉一兩味。夏服亦無多，蕉紗三五事。", "資身既給足，長物徒煩費。若比簞瓢人，吾今太富貴。"]'),
('yuding-8','和思黯居守獨飲偶醉見示六韻時夢得和篇先成頗為麗絕因添兩韻繼而美之','白居易','唐','御定全唐诗','yuding','','[]','宮漏滴漸闌，城烏啼複歇。此時若不醉，爭奈千門月。',96,'御定全唐詩/json/459.json','["宮漏滴漸闌，城烏啼複歇。此時若不醉，爭奈千門月。", "主人中夜起，妓燭前羅列。歌袂默收聲，舞鬟低赴節。", "弦吟玉柱品，酒透金杯熱。朱顏忽已酡，清奏猶未闋。", "妍詞黯先唱，逸韻劉繼發。鏗然雙雅音，金石相磨戛。"]'),
('yuding-9','和夢得洛中早春見贈七韻','白居易','唐','御定全唐诗','yuding','','[]','眾皆賞春色，君獨憐春意。春意竟如何，老夫知此味。',84,'御定全唐詩/json/459.json','["眾皆賞春色，君獨憐春意。春意竟如何，老夫知此味。", "燭餘減夜漏，衾暖添朝睡。恬和台上風，虛潤池邊地。", "開遲花養豔，語懶鶯含思。似訝來年齋，如勸迎春醉。", "何日同宴遊，心期二月二。"]'),
('yuding-10','櫻桃花下有感而作','白居易','唐','御定全唐诗','yuding','','[]','藹藹美周宅，櫻繁春日斜。一為洛下客，十見池上花。',72,'御定全唐詩/json/459.json','["藹藹美周宅，櫻繁春日斜。一為洛下客，十見池上花。", "爛熳豈無意，為君占年華。風光饒此樹，歌舞勝諸家。", "失盡白頭伴，長成紅粉娃。停杯兩相顧，堪喜亦堪嗟。"]'),
('yuding-11','洗竹','白居易','唐','御定全唐诗','yuding','','[]','布裘寒擁頸，氈履溫承足。獨立冰池前，久看洗霜竹。',96,'御定全唐詩/json/459.json','["布裘寒擁頸，氈履溫承足。獨立冰池前，久看洗霜竹。", "先除老且病，次去纖而曲。剪棄猶可憐，琅玕十餘束。", "青青複籊籊，頗異凡草木。依然若有情，回頭語僮僕。", "小者截魚竿，大者編茅屋。勿作篲與箕，而令糞土辱。"]'),
('yuding-12','新沐浴','白居易','唐','御定全唐诗','yuding','','[]','形適外無恙，心恬內無憂。夜來新沐浴，肌發舒且柔。',144,'御定全唐詩/json/459.json','["形適外無恙，心恬內無憂。夜來新沐浴，肌發舒且柔。", "寬裁夾烏帽，厚絮長白裘。裘溫裹我足，帽暖覆我頭。", "先進酒一杯，次舉粥一甌。半酣半飽時，四體春悠悠。", "是月歲陰暮，慘冽天地愁。白日冷無光，黃河凍不流。", "何處征戍行，何人羈旅遊。窮途絕糧客，寒獄無燈囚。", "勞生彼何苦，遂性我何優。撫心但自愧，孰知其所由。"]'),
('yuding-13','三年除夜','白居易','唐','御定全唐诗','yuding','','[]','晰晰燎火光，氳氳臘酒香。嗤嗤童稚戲，迢迢歲夜長。',96,'御定全唐詩/json/459.json','["晰晰燎火光，氳氳臘酒香。嗤嗤童稚戲，迢迢歲夜長。", "堂上書帳前，長幼合成行。以我年最長，次第來稱觴。", "七十期漸近，萬緣心已忘。不唯少歡樂，兼亦無悲傷。", "素屏應居士，青衣侍孟光。夫妻老相對，各坐一繩床。"]'),
('yuding-14','自題小園','白居易','唐','御定全唐诗','yuding','','[]','不斗門館華，不鬥林園大。但鬥為主人，一坐十餘載。',108,'御定全唐詩/json/459.json','["不斗門館華，不鬥林園大。但鬥為主人，一坐十餘載。", "回看甲乙第，列在都城內。素垣夾朱門，藹藹遙相對。", "主人安在哉，富貴去不回。池乃為魚鑿，林乃為禽栽。", "何如小園主，拄杖閑即來。親賓有時會，琴酒連夜開。", "以此聊自足，不羨大池台。"]'),
('yuding-15','病中宴坐','白居易','唐','御定全唐诗','yuding','','[]','有酒病不飲，有詩慵不吟。頭眩罷垂鉤，手痹休援琴。',72,'御定全唐詩/json/459.json','["有酒病不飲，有詩慵不吟。頭眩罷垂鉤，手痹休援琴。", "竟日悄無事，所居閑且深。外安支離體，中養希夷心。", "窗戶納秋景，竹木澄夕陰。宴坐小池畔，清風時動襟。"]'),
('yuding-16','戒藥','白居易','唐','御定全唐诗','yuding','','[]','促促急景中，蠢蠢微塵裏。生涯有分限，愛戀無終已。',120,'御定全唐詩/json/459.json','["促促急景中，蠢蠢微塵裏。生涯有分限，愛戀無終已。", "早夭羨中年，中年羨暮齒。暮齒又貪生，服食求不死。", "朝吞太陽精，夕吸秋石髓。徼福反成災，藥誤者多矣。", "以之資嗜欲，又望延甲子。天人陰騭間，亦恐無此理。", "域中有真道，所說不如此。後身始身存，吾聞諸老氏。"]'),
('yuding-17','贈夢得','白居易','唐','御定全唐诗','yuding','','[]','前日君家飲，昨日王家宴。今日過我廬，三日三會面。',72,'御定全唐詩/json/459.json','["前日君家飲，昨日王家宴。今日過我廬，三日三會面。", "當歌聊自放，對酒交相勸。為我盡一杯，與君發三願。", "一願世清平，二願身強健。三願臨老頭，數與君相見。"]'),
('yuding-18','逸老','白居易','唐','御定全唐诗','yuding','','[]','白日下駸駸，青天高浩浩。人生在其中，適時即為好。',204,'御定全唐詩/json/459.json','["白日下駸駸，青天高浩浩。人生在其中，適時即為好。", "勞我以少壯，息我以衰老。順之多吉壽，違之或凶夭。", "我初五十八，息老雖非早。一閑十三年，所得亦不少。", "況加祿仕後，衣食常溫飽。又從風疾來，女嫁男婚了。", "胸中一無事，浩氣凝襟抱。飄若雲信風，樂於魚在藻。", "桑榆坐已暮，鐘漏行將曉。皤然七十翁，亦足稱壽考。", "筋骸本非實，一束芭蕉草。眷屬偶相依，一夕同棲鳥。", "去何有顧戀，住亦無憂惱。生死尚複然，其餘安足道。", "是故臨老心，冥然合玄造。"]'),
('yuding-19','遇物感興因示子弟','白居易','唐','御定全唐诗','yuding','','[]','聖擇狂夫言，俗信老人語。我有老狂詞，聽之吾語汝。',144,'御定全唐詩/json/459.json','["聖擇狂夫言，俗信老人語。我有老狂詞，聽之吾語汝。", "吾觀器用中，劍銳鋒多傷。吾觀形骸內，骨勁齒先亡。", "寄言處世者，不可苦剛強。龜性愚且善，鳩心鈍無惡。", "人賤拾支床，鶻欺擒暖腳。寄言立身者，不得全柔弱。", "彼固罹禍難，此未免憂患。于何保終吉，強弱剛柔間。", "上遵周孔訓，旁鑒老莊言。不唯鞭其後，亦要軛其先。"]'),
('yuding-20','首夏南池獨酌','白居易','唐','御定全唐诗','yuding','','[]','春盡雜英歇，夏初芳草深。熏風自南至，吹我池上林。',84,'御定全唐詩/json/459.json','["春盡雜英歇，夏初芳草深。熏風自南至，吹我池上林。", "綠蘋散還合，赬鯉跳複沈。新葉有佳色，殘鶯猶好音。", "依然謝家物，池酌對風琴。慚無康樂作，秉筆思沈吟。", "境勝才思劣，詩成不稱心。"]'),
('yuding-21','官俸初罷，親故見憂，以詩諭之','白居易','唐','御定全唐诗','yuding','','[]','七年為少傅，品高俸不薄。乘軒已多慚，況是一病鶴。',144,'御定全唐詩/json/459.json','["七年為少傅，品高俸不薄。乘軒已多慚，況是一病鶴。", "又及懸車歲，筋力轉衰弱。豈以貧是憂，尚為名所縛。", "今春始病免，纓組初擺落。蜩甲有何知，雲心無所著。", "囷中殘舊穀，可備歲饑惡。園中多新蔬，未至食藜藿。", "不求安師卜，不問陳生藥。但對丘中琴，時開池上酌。", "信風舟不系，掉尾魚方樂。親友不我知，而憂我寂寞。"]'),
('yuding-22','閒居偶吟，招鄭庶子、皇甫郎中','白居易','唐','御定全唐诗','yuding','','[]','自哂此迂叟，少迂老更迂。家計不一問，園林聊自娛。',132,'御定全唐詩/json/459.json','["自哂此迂叟，少迂老更迂。家計不一問，園林聊自娛。", "竹間琴一張，池上酒一壺。更無俗物到，但與秋光俱。", "古石蒼錯落，新泉碧縈紆。焉用車馬客，即此是吾徒。", "猶有所思人，各在城一隅。杳然愛不見，搔首方踟躕。", "玄晏風韻遠，子真雲貌孤。誠知厭朝市，何必憶江湖。", "能來小澗上，一聽潺湲無。"]'),
('yuding-23','亭西牆下伊渠水中置石激流潺湲成韻頗有幽趣以詩記之','白居易','唐','御定全唐诗','yuding','','[]','嵌巉嵩石峭，皎潔伊流清。立為遠峰勢，激作寒玉聲。',96,'御定全唐詩/json/459.json','["嵌巉嵩石峭，皎潔伊流清。立為遠峰勢，激作寒玉聲。", "夾岸羅密樹，面灘開小亭。忽疑嚴子瀨，流入洛陽城。", "是時群動息，風靜微月明。高枕夜悄悄，滿耳秋泠泠。", "終日臨大道，何人知此情。此情苟自愜，亦不要人聽。"]'),
('yuding-24','閑題家池，寄王屋張道士','白居易','唐','御定全唐诗','yuding','','[]','有石白磷磷，有水清潺潺。有叟頭似雪，婆娑乎其間。',120,'御定全唐詩/json/459.json','["有石白磷磷，有水清潺潺。有叟頭似雪，婆娑乎其間。", "進不趨要路，退不入深山。深山太濩落，要路多險艱。", "不如家池上，樂逸無憂患。有食適吾口，有酒酡吾顏。", "恍惚遊醉鄉，希夷造玄關。五千言下悟，十二年來閑。", "富者我不顧，貴者我不攀。唯有天罎子，時來一往還。"]'),
('yuding-25','李盧二中丞各創山居俱誇勝絕然去城稍遠來往頗勞弊居新泉實在宇下偶題十五韻聊戲二君','白居易','唐','御定全唐诗','yuding','','[]','龍門蒼石壁，浥澗碧潭水。各在一山隅，迢遙幾十裏。',180,'御定全唐詩/json/459.json','["龍門蒼石壁，浥澗碧潭水。各在一山隅，迢遙幾十裏。", "清鏡碧屏風，惜哉信為美。愛而不得見，亦與無相似。", "聞君每來去，矻矻事行李。脂轄複裹糧，心力頗勞止。", "未如吾捨下，石與泉甚邇。鑿鑿複濺濺，晝夜流不已。", "洛石千萬拳，襯波鋪錦綺。海瑉一兩片，激瀨含宮征。", "綠宜春濯足，淨可朝漱齒。繞砌紫鱗遊，拂簾白鳥起。", "何言履道叟，便是滄浪子。君若趁歸程，請君先到此。", "願以潺湲聲，洗君塵土耳。"]'),
('yuding-26','北窗竹石','白居易','唐','御定全唐诗','yuding','','[]','一片瑟瑟石，數竿青青竹。向我如有情，依然看不足。',72,'御定全唐詩/json/459.json','["一片瑟瑟石，數竿青青竹。向我如有情，依然看不足。", "況臨北窗下，複近西塘曲。筠風散餘清，苔雨含微綠。", "有妻亦衰老，無子方煢獨。莫掩夜窗扉，共渠相伴宿。"]'),
('yuding-27','飲後戲示弟子','白居易','唐','御定全唐诗','yuding','','[]','吾為爾先生，爾為吾弟子。孔門有遺訓，複坐吾告爾。',132,'御定全唐詩/json/459.json','["吾為爾先生，爾為吾弟子。孔門有遺訓，複坐吾告爾。", "先生饌酒食，弟子服勞止。孝敬不在他，在茲而已矣。", "欲我少憂愁，欲我多歡喜。無如醞好酒，酒須多且旨。", "旨即賓可留，多即罍不恥。吾更有一言，爾宜聽入耳。", "人老多憂貧，人病多憂死。我今雖老病，所憂不在此。", "憂在半酣時，尊空座客起。"]'),
('yuding-28','閑坐看書，貽諸少年','白居易','唐','御定全唐诗','yuding','','[]','雨砌長寒蕪，風庭落秋果。窗間有閑叟，盡日看書坐。',96,'御定全唐詩/json/459.json','["雨砌長寒蕪，風庭落秋果。窗間有閑叟，盡日看書坐。", "書中見往事，歷歷知福禍。多取終厚亡，疾驅必先墮。", "勸君少幹名，名為錮身鎖。勸君少求利，利是焚身火。", "我心知已久，吾道無不可。所以雀羅門，不能寂寞我。"]'),
('yuding-29','夢上山','白居易','唐','御定全唐诗','yuding','','[]','夜夢上嵩山，獨攜藜杖出。千岩與萬壑，遊覽皆周畢。',96,'御定全唐詩/json/459.json','["夜夢上嵩山，獨攜藜杖出。千岩與萬壑，遊覽皆周畢。", "夢中足不病，健似少年日。既悟神返初，依然舊形質。", "始知形神內，形病神無疾。形神兩是幻，夢寐俱非實。", "晝行雖蹇澀，夜步頗安逸。晝夜既平分，其間何得失。"]'),
('yuding-30','對酒閑吟，贈同老者','白居易','唐','御定全唐诗','yuding','','[]','人生七十稀，我年幸過之。遠行將盡路，春夢欲覺時。',168,'御定全唐詩/json/459.json','["人生七十稀，我年幸過之。遠行將盡路，春夢欲覺時。", "家事口不問，世名心不思。老既不足歎，病亦不能治。", "扶持仰婢僕，將養信妻兒。饑飽進退食，寒暄加減衣。", "聲妓放鄭衛，裘馬脫輕肥。百事盡除去，尚餘酒與詩。", "興來吟一篇，吟罷酒一卮。不獨適情性，兼用扶衰羸。", "雲液灑六腑，陽和生四肢。于中我自樂，此外吾不知。", "寄問同老者，舍此將安歸。莫學蓬心叟，胸中殘是非。"]'),
('yuding-31','晚起閑行','白居易','唐','御定全唐诗','yuding','','[]','皤然一老子，擁裘仍隱幾。坐穩夜忘眠，臥安朝不起。',72,'御定全唐詩/json/459.json','["皤然一老子，擁裘仍隱幾。坐穩夜忘眠，臥安朝不起。", "起來無可作，閉目時叩齒。靜對銅爐香，暖漱銀瓶水。", "午齋何儉潔，餅與蔬而已。西寺講楞伽，閑行一隨喜。"]'),
('yuding-32','香山居士寫真詩','白居易','唐','御定全唐诗','yuding','','[]','昔作少學士，圖形入集賢。今為老居士，寫貌寄香山。',72,'御定全唐詩/json/459.json','["昔作少學士，圖形入集賢。今為老居士，寫貌寄香山。", "鶴毳變玄發，雞膚換朱顏。前形與後貌，相去三十年。", "勿歎韶華子，俄成皤叟仙。請看東海水，亦變作桑田。"]'),
('yuding-33','二年三月五日齋畢開素當食偶吟贈妻弘農郡君','白居易','唐','御定全唐诗','yuding','','[]','睡足肢體暢，晨起開中堂。初旭泛簾幕，微風拂衣裳。',228,'御定全唐詩/json/459.json','["睡足肢體暢，晨起開中堂。初旭泛簾幕，微風拂衣裳。", "二婢扶盥櫛，雙童舁簟床。庭東有茂樹，其下多陰涼。", "前月事齋戒，昨日散道場。以我久蔬素，加籩仍異糧。", "魴鱗白如雪，蒸炙加桂薑。稻飯紅似花，調沃新酪漿。", "佐以脯醢味，間之椒薤芳。老憐口尚美，病喜鼻聞香。", "嬌騃三四孫，索哺繞我傍。山妻未舉案，饞叟已先嘗。", "憶同牢巹初，家貧共糟糠。今食且如此，何必烹豬羊。", "況觀姻族間，夫妻半存亡。偕老不易得，白頭何足傷。", "食罷酒一杯，醉飽吟又狂。緬想梁高士，樂道喜文章。", "徒誇五噫作，不解贈孟光。"]'),
('yuding-34','不出門','白居易','唐','御定全唐诗','yuding','','[]','彌月不出門，永日無來賓。食飽更拂床，睡覺一嚬伸。',96,'御定全唐詩/json/459.json','["彌月不出門，永日無來賓。食飽更拂床，睡覺一嚬伸。", "輕箑白鳥羽，新簟青箭筠。方寸方丈室，空然兩無塵。", "披衣腰不帶，散發頭不巾。袒跣北窗下，葛天之遺民。", "一日亦自足，況得以終身。不知天壤內，目我為何人。"]'),
('yuding-35','感舊','白居易','唐','御定全唐诗','yuding','','[]','晦叔墳荒草已陳，夢得墓濕土猶新。微之捐館將一紀，',72,'御定全唐詩/json/459.json','["晦叔墳荒草已陳，夢得墓濕土猶新。微之捐館將一紀，", "篋中亦有舊書劄，紙穿字蠹成灰塵。平生定交取人窄，", "豈無晚歲新相識，相識面親心不親。人生莫羨苦長命，"]'),
('yuding-36','送毛仙翁','白居易','唐','御定全唐诗','yuding','','[]','仙翁已得道，混跡尋岩泉。肌膚冰雪瑩，衣服雲霞鮮。',288,'御定全唐詩/json/459.json','["仙翁已得道，混跡尋岩泉。肌膚冰雪瑩，衣服雲霞鮮。", "紺發絲並致，齠容花共妍。方瞳點玄漆，高步淩非煙。", "幾見桑海變，莫知龜鶴年。所憩九清外，所遊五嶽巔。", "軒昊舊為侶，松喬難比肩。每嗟人世人，役役如狂顛。", "孰能脫羈鞅，盡遭名利牽。貌隨歲律換，神逐光陰遷。", "惟餘負憂譴，憔悴湓江壖。衰鬢忽霜白，愁腸如火煎。", "羈旅坐多感，裴回私自憐。晴眺五老峰，玉洞多神仙。", "何當憫湮厄，授道安虛孱。我師惠然來，論道窮重玄。", "浩蕩八溟闊，志泰心超然。形骸既無束，得喪亦都捐。", "豈識椿菌異，那知鵬鷃懸。丹華既相付，促景定當延。", "玄功曷可報，感極惟勤拳。霓旌不肯駐，又歸武夷川。", "語罷倏然別，孤鶴升遙天。賦詩敘明德，永續步虛篇。"]'),
('yuding-37','達哉樂天行','白居易','唐','御定全唐诗','yuding','','[]','達哉達哉白樂天，分司東都十三年。七旬才滿冠已掛，',120,'御定全唐詩/json/459.json','["達哉達哉白樂天，分司東都十三年。七旬才滿冠已掛，", "二年忘卻問家事，門庭多草廚少煙。庖童朝告鹽米盡，", "起來與爾畫生計，薄產處置有後先。先賣南坊十畝園，", "半與爾充衣食費，半與吾供酒肉錢。吾今已年七十一，", "未歸且住亦不惡，饑餐樂飲安穩眠。死生無可無不可，"]'),
('yuding-38','春池閑泛','白居易','唐','御定全唐诗','yuding','','[]','綠塘新水準，紅檻小舟輕。解纜隨風去，開襟信意行。',120,'御定全唐詩/json/459.json','["綠塘新水準，紅檻小舟輕。解纜隨風去，開襟信意行。", "淺憐清演漾，深愛綠澄泓。白撲柳飛絮，紅浮桃落英。", "古文科鬥出，新葉剪刀生。樹集鶯朋友，雲行雁弟兄。", "飛沈皆適性，酣詠自怡情。花助銀盃氣，松添玉軫聲。", "魚跳何事樂，鷗起複誰驚。莫唱滄浪曲，無塵可濯纓。"]'),
('yuding-39','池上寓興二絕','白居易','唐','御定全唐诗','yuding','','[]','濠梁莊惠謾相爭，未必人情知物情。',64,'御定全唐詩/json/459.json','["濠梁莊惠謾相爭，未必人情知物情。", "獺捕魚來魚躍出，此非魚樂是魚驚。", "水淺魚稀白鷺饑，勞心瞪目待魚時。", "外容閒暇中心苦，似是而非誰得知。"]'),
('yuding-40','宴後題府中水堂贈盧尹中丞','白居易','唐','御定全唐诗','yuding','','[]','水齋歲久漸荒蕪，自愧甘棠無一株。新酒客來方宴飲，',40,'御定全唐詩/json/459.json','["水齋歲久漸荒蕪，自愧甘棠無一株。新酒客來方宴飲，", "從我到君十一尹，相看自置府來無。"]'),
('yuding-41','和敏中洛下即事','白居易','唐','御定全唐诗','yuding','','[]','昨日池塘春草生，阿連新有好詩成。花園到處鶯呼入，',40,'御定全唐詩/json/459.json','["昨日池塘春草生，阿連新有好詩成。花園到處鶯呼入，", "洛中佳境應無限，若欲諳知問老兄。"]'),
('yuding-42','送敏中新授戶部員外郎西歸','白居易','唐','御定全唐诗','yuding','','[]','千里歸程三伏天，官新身健馬翩翩。行沖赤日加餐飯，',40,'御定全唐詩/json/459.json','["千里歸程三伏天，官新身健馬翩翩。行沖赤日加餐飯，", "前鴻後雁行難續，相去迢迢二十年。"]'),
('yuding-43','南侍禦以石相贈，助成水聲，因以絕句謝之','白居易','唐','御定全唐诗','yuding','','[]','泉石磷磷聲似琴，閑眠靜聽洗塵心。',32,'御定全唐詩/json/459.json','["泉石磷磷聲似琴，閑眠靜聽洗塵心。", "莫輕兩片青苔石，一夜潺湲直萬金。"]'),
('yuding-44','閒居自題，戲招宿客','白居易','唐','御定全唐诗','yuding','','[]','水畔竹林邊，閒居二十年。健常攜酒出，病即掩門眠。',96,'御定全唐詩/json/459.json','["水畔竹林邊，閒居二十年。健常攜酒出，病即掩門眠。", "解綬收朝佩，褰裳出野船。屏除身外物，擺落世間緣。", "報曙窗何早，知秋簟最先。微風深樹裏，斜日小樓前。", "渠口添新石，籬根寫亂泉。欲招同宿客，誰解愛潺湲。"]'),
('yuding-45','李留守相公見過池上汎舟舉酒話及翰林舊事因成四韻以獻之','白居易','唐','御定全唐诗','yuding','','[]','引棹尋池岸，移尊就菊叢。何言濟川後，相訪釣船中。',48,'御定全唐詩/json/459.json','["引棹尋池岸，移尊就菊叢。何言濟川後，相訪釣船中。", "白首故情在，青雲往事空。同時六學士，五相一漁翁。"]'),
('yuding-46','閏九月九日獨飲','白居易','唐','御定全唐诗','yuding','','[]','黃花叢畔綠尊前，猶有些些舊管弦。偶遇閏秋重九日，',24,'御定全唐詩/json/459.json','["黃花叢畔綠尊前，猶有些些舊管弦。偶遇閏秋重九日，"]'),
('yuding-47','覽盧子蒙侍御舊詩多與微之唱和感今傷昔因贈子蒙題於卷後','白居易','唐','御定全唐诗','yuding','','[]','早聞元九詠君詩，恨與盧君相識遲。今日逢君開舊卷，',40,'御定全唐詩/json/459.json','["早聞元九詠君詩，恨與盧君相識遲。今日逢君開舊卷，", "聞道咸陽墳上樹，已抽三丈白楊枝。"]'),
('yuding-48','寒亭留客','白居易','唐','御定全唐诗','yuding','','[]','今朝閑坐石亭中，爐火銷殘尊又空。',32,'御定全唐詩/json/459.json','["今朝閑坐石亭中，爐火銷殘尊又空。", "冷落若為留客住，冰池霜竹雪髯翁。"]'),
('yuding-49','新小灘','白居易','唐','御定全唐诗','yuding','','[]','石淺沙平流水寒，水邊斜插一漁竿。',32,'御定全唐詩/json/459.json','["石淺沙平流水寒，水邊斜插一漁竿。", "江南客見生鄉思，道似嚴陵七裏灘。"]'),
('yuding-50','和李中丞與李給事山居雪夜同宿小酌','白居易','唐','御定全唐诗','yuding','','[]','憲府觸邪峨豸角，瑣闈駁正犯龍鱗。那知近地齋居客，',40,'御定全唐詩/json/459.json','["憲府觸邪峨豸角，瑣闈駁正犯龍鱗。那知近地齋居客，", "林泉莫作多時計，諫獵登封憶舊臣。"]'),
('yuding-51','履道西門二首','白居易','唐','御定全唐诗','yuding','','[]','履道西門有弊居，池塘竹樹繞吾廬。豪華肥壯雖無分，',80,'御定全唐詩/json/459.json','["履道西門有弊居，池塘竹樹繞吾廬。豪華肥壯雖無分，", "夷齊黃綺誇芝蕨，比我盤飧恐不如。", "履道西門獨掩扉，官休病退客來稀。亦知軒冕榮堪戀，", "世間認得身人少，今我雖愚亦庶幾。"]'),
('yuding-52','偶吟','白居易','唐','御定全唐诗','yuding','','[]','人生變改故無窮，昔是朝官今野翁。久寄形于朱紫內，',40,'御定全唐詩/json/459.json','["人生變改故無窮，昔是朝官今野翁。久寄形于朱紫內，", "猶有鱸魚蓴菜興，來春或擬往江東。"]'),
('yuding-53','雪夜小飲贈夢得','白居易','唐','御定全唐诗','yuding','','[]','同為懶慢園林客，共對蕭條雨雪天。小酌酒巡銷永夜，',40,'御定全唐詩/json/459.json','["同為懶慢園林客，共對蕭條雨雪天。小酌酒巡銷永夜，", "呼作散仙應有以，曾看東海變桑田。"]'),
('yuding-54','歲暮夜長病中燈下聞盧尹夜宴以詩戲之且為來日張本也','白居易','唐','御定全唐诗','yuding','','[]','榮鬧興多嫌晝短，衰閑睡少覺明遲。當君秉燭銜杯夜，',40,'御定全唐詩/json/459.json','["榮鬧興多嫌晝短，衰閑睡少覺明遲。當君秉燭銜杯夜，", "明朝強出須謀樂，不擬車公更擬誰。"]'),
('yuding-55','病中數會張道士見譏，以此答之','白居易','唐','御定全唐诗','yuding','','[]','亦知數出妨將息，不可端居守寂寥。病即藥窗眠盡日，',40,'御定全唐詩/json/459.json','["亦知數出妨將息，不可端居守寂寥。病即藥窗眠盡日，", "張道士輸白道士，一杯沆瀣便逍遙。"]'),
('yuding-56','卯飲','白居易','唐','御定全唐诗','yuding','','[]','短屏風掩臥床頭，烏帽青氈白氎裘。',32,'御定全唐詩/json/459.json','["短屏風掩臥床頭，烏帽青氈白氎裘。", "卯飲一杯眠一覺，世間何事不悠悠。"]'),
('yuding-57','寄題餘杭郡樓，兼呈裴使君','白居易','唐','御定全唐诗','yuding','','[]','官曆二十政，宦遊三十秋。江山與風月，最憶是杭州。',72,'御定全唐詩/json/459.json','["官曆二十政，宦遊三十秋。江山與風月，最憶是杭州。", "北郭沙堤尾，西湖石岸頭。綠觴春送客，紅燭夜回舟。", "不敢言遺愛，空知念舊遊。憑君吟此句，題向望濤樓。"]'),
('yuding-58','楊六尚書留太湖石在洛下借置庭中因對舉杯寄贈絕句','白居易','唐','御定全唐诗','yuding','','[]','借君片石意何如，置向庭中慰索居。',32,'御定全唐詩/json/459.json','["借君片石意何如，置向庭中慰索居。", "每就玉山傾一酌，興來如對醉尚書。"]'),
('yuding-59','喜入新年自詠','白居易','唐','御定全唐诗','yuding','','[]','白須如雪五朝臣，又值新正第七旬。老過占他藍尾酒，',40,'御定全唐詩/json/459.json','["白須如雪五朝臣，又值新正第七旬。老過占他藍尾酒，", "大歷年中騎竹馬，幾人得見會昌春。"]'),
('yuding-60','灘聲','白居易','唐','御定全唐诗','yuding','','[]','碧玉班班沙歷歷，清流決決響泠泠。',32,'御定全唐詩/json/459.json','["碧玉班班沙歷歷，清流決決響泠泠。", "自從造得灘聲後，玉管朱弦可要聽。"]'),
('yuding-61','題石泉','白居易','唐','御定全唐诗','yuding','','[]','殷勤傍石繞泉行，不說何人知我情。',32,'御定全唐詩/json/459.json','["殷勤傍石繞泉行，不說何人知我情。", "漸恐耳聾兼眼暗，聽泉看石不分明。"]'),
('yuding-62','送王卿使君赴任蘇州因思花迎新使感舊遊寄題郡中木蘭西院一別','白居易','唐','御定全唐诗','yuding','','[]','一別蘇州十八載，時光人事隨年改。不論竹馬盡成人，',40,'御定全唐詩/json/459.json','["一別蘇州十八載，時光人事隨年改。不論竹馬盡成人，", "為報江山風月知，至今白使君猶在。"]'),
('yuding-63','出齋日喜皇甫十早訪','白居易','唐','御定全唐诗','yuding','','[]','三旬齋滿欲銜杯，平旦敲門門未開。',32,'御定全唐詩/json/459.json','["三旬齋滿欲銜杯，平旦敲門門未開。", "除卻朗之攜一榼，的應不是別人來。"]'),
('yuding-64','會昌二年春題池西小樓','白居易','唐','御定全唐诗','yuding','','[]','花邊春水水邊樓，一坐經今四十秋。望月橋傾三遍換，',48,'御定全唐詩/json/459.json','["花邊春水水邊樓，一坐經今四十秋。望月橋傾三遍換，", "蘇李冥蒙隨燭滅，陳樊漂泊逐萍流。雖貧眼下無妨樂，"]'),
('yuding-65','酬南洛陽早春見贈','白居易','唐','御定全唐诗','yuding','','[]','物華春意尚遲回，賴有東風晝夜催。寒縋柳腰收未得，',40,'御定全唐詩/json/459.json','["物華春意尚遲回，賴有東風晝夜催。寒縋柳腰收未得，", "久病長齋詩老退，爭禁年少洛陽才。"]'),
('yuding-66','對新家醞玩自種花','白居易','唐','御定全唐诗','yuding','','[]','香麹親看造，芳叢手自栽。迎春報酒熟，垂老看花開。',72,'御定全唐詩/json/459.json','["香麹親看造，芳叢手自栽。迎春報酒熟，垂老看花開。", "紅蠟半含萼，綠油新醱醅。玲瓏五六樹，瀲灩兩三杯。", "恐有狂風起，愁無好客來。獨酣還獨語，待取月明回。"]'),
('yuding-67','攜酒往朗之莊居同飲','白居易','唐','御定全唐诗','yuding','','[]','慵中又少經過處，別後都無勸酒人。',32,'御定全唐詩/json/459.json','["慵中又少經過處，別後都無勸酒人。", "不挈一壺相就醉，若為將老度殘春。"]'),
('yuding-68','以詩代書，酬慕巢尚書見寄','白居易','唐','御定全唐诗','yuding','','[]','書意詩情不偶然，苦雲夢想在林泉。願為愚谷煙霞侶，',40,'御定全唐詩/json/459.json','["書意詩情不偶然，苦雲夢想在林泉。願為愚谷煙霞侶，", "不知待得心期否，老校於君六七年。"]'),
('yuding-69','春盡日','白居易','唐','御定全唐诗','yuding','','[]','芳景銷殘暑氣生，感時思事坐含情。無人開口共誰語，',40,'御定全唐詩/json/459.json','["芳景銷殘暑氣生，感時思事坐含情。無人開口共誰語，", "春歸似遣鶯留語，好住園林三兩聲。"]'),
('yuding-70','招山僧','白居易','唐','御定全唐诗','yuding','','[]','能入城中乞食否，莫辭塵土汙袈裟。',32,'御定全唐詩/json/459.json','["能入城中乞食否，莫辭塵土汙袈裟。", "欲知住處東城下，繞竹泉聲是白家。"]'),
('yuding-71','夏日與閑禪師林下避暑','白居易','唐','御定全唐诗','yuding','','[]','洛景城西塵土紅，伴僧閑坐竹泉東。綠蘿潭上不見日，',40,'御定全唐詩/json/459.json','["洛景城西塵土紅，伴僧閑坐竹泉東。綠蘿潭上不見日，", "每因毒暑悲親故，多在炎方瘴海中。"]'),
('yuding-72','題新澗亭，兼酬寄朝中親故見贈','白居易','唐','御定全唐诗','yuding','','[]','何處披襟風快哉，一亭臨澗四門開。金章紫綬辭腰去，',40,'御定全唐詩/json/459.json','["何處披襟風快哉，一亭臨澗四門開。金章紫綬辭腰去，", "禽魚出得池籠後，縱有人呼可更回。"]'),
('yuding-73','病中看經贈諸道侶','白居易','唐','御定全唐诗','yuding','','[]','右眼昏花左足風，金篦石水用無功。不如回念三乘樂，',40,'御定全唐詩/json/459.json','["右眼昏花左足風，金篦石水用無功。不如回念三乘樂，", "何煩更請僧為侶，月上新歸伴病翁。"]'),
('yuding-74','游豐樂招提佛光三寺','白居易','唐','御定全唐诗','yuding','','[]','竹鞋葵扇白綃巾，林野為家雲是身。山寺每遊多寄宿，',40,'御定全唐詩/json/459.json','["竹鞋葵扇白綃巾，林野為家雲是身。山寺每遊多寄宿，", "昨日制書臨郡縣，不該愚穀醉鄉人。"]'),
('yuding-75','醉中得上都親友書以予停俸多時憂問貧乏偶乘酒興詠而報之','白居易','唐','御定全唐诗','yuding','','[]','頭白醉昏昏，狂歌秋複春。一生耽酒客，五度棄官人。',120,'御定全唐詩/json/459.json','["頭白醉昏昏，狂歌秋複春。一生耽酒客，五度棄官人。", "異世陶元亮，前生劉伯倫。臥將琴作枕，行以鍤隨身。", "歲要衣三對，年支穀一囷。園葵烹佐飯，林葉掃添薪。", "沒齒甘蔬食，搖頭謝縉紳。自能拋爵祿，終不惱交親。", "但得杯中淥，從生甑上塵。煩君問生計，憂醒不憂貧。"]'),
('yuding-76','池畔逐涼','白居易','唐','御定全唐诗','yuding','','[]','風清泉冷竹修修，三伏炎天涼似秋。黃犬引迎騎馬客，',40,'御定全唐詩/json/459.json','["風清泉冷竹修修，三伏炎天涼似秋。黃犬引迎騎馬客，", "料得此身終老處，只應林下與灘頭。"]'),
('yuding-77','池鶴八絕句：雞贈鶴','白居易','唐','御定全唐诗','yuding','','[]','一聲警露君能薄，五德司晨我用多。',32,'御定全唐詩/json/459.json','["一聲警露君能薄，五德司晨我用多。", "不會悠悠時俗士，重君輕我意如何。"]'),
('yuding-78','池鶴八絕句：鶴答雞','白居易','唐','御定全唐诗','yuding','','[]','爾爭伉儷泥中鬥，吾整羽儀松上棲。',32,'御定全唐詩/json/459.json','["爾爭伉儷泥中鬥，吾整羽儀松上棲。", "不可遣他天下眼，卻輕野鶴重家雞。"]'),
('yuding-79','池鶴八絕句：烏贈鶴','白居易','唐','御定全唐诗','yuding','','[]','與君白黑大分明，縱不相親莫見輕。',32,'御定全唐詩/json/459.json','["與君白黑大分明，縱不相親莫見輕。", "我每夜啼君怨別，玉徽琴裏忝同聲。"]'),
('yuding-80','池鶴八絕句：鶴答烏','白居易','唐','御定全唐诗','yuding','','[]','吾愛棲雲上華表，汝多攫肉下田中。',32,'御定全唐詩/json/459.json','["吾愛棲雲上華表，汝多攫肉下田中。", "吾音中羽汝聲角，琴曲雖同調不同。"]'),
('yuding-81','池鶴八絕句：鳶贈鶴','白居易','唐','御定全唐诗','yuding','','[]','君誇名鶴我名鳶，君叫聞天我戾天。',32,'御定全唐詩/json/459.json','["君誇名鶴我名鳶，君叫聞天我戾天。", "更有與君相似處，饑來一種啄腥膻。"]'),
('yuding-82','池鶴八絕句：鶴答鳶','白居易','唐','御定全唐诗','yuding','','[]','無妨自是莫相非，清濁高低各有歸。',32,'御定全唐詩/json/459.json','["無妨自是莫相非，清濁高低各有歸。", "鸞鶴群中彩雲裏，幾時曾見喘鳶飛。"]'),
('yuding-83','池鶴八絕句：鵝贈鶴','白居易','唐','御定全唐诗','yuding','','[]','君因風送入青雲，我被人驅向鴨群。',32,'御定全唐詩/json/459.json','["君因風送入青雲，我被人驅向鴨群。", "雪頸霜毛紅網掌，請看何處不如君。"]'),
('yuding-84','池鶴八絕句：鶴答鵝','白居易','唐','御定全唐诗','yuding','','[]','右軍歿後欲何依，只合隨雞逐鴨飛。',32,'御定全唐詩/json/459.json','["右軍歿後欲何依，只合隨雞逐鴨飛。", "未必犧牲及吾輩，大都我瘦勝君肥。"]'),
('yuding-85','談氏小外孫玉童','白居易','唐','御定全唐诗','yuding','','[]','外翁七十孫三歲，笑指琴書欲遣傳。自念老夫今耄矣，',40,'御定全唐詩/json/459.json','["外翁七十孫三歲，笑指琴書欲遣傳。自念老夫今耄矣，", "才與不才爭料得，東床空後且嬌憐。"]'),
('yuding-86','送後集往廬山東林寺，兼寄雲皋上人','白居易','唐','御定全唐诗','yuding','','[]','後集寄將何處去，故山迢遞在匡廬。舊僧獨有雲皋在，',40,'御定全唐詩/json/459.json','["後集寄將何處去，故山迢遞在匡廬。舊僧獨有雲皋在，", "來生緣會應非遠，彼此年過七十餘。"]'),
('yuding-87','客有說','白居易','唐','御定全唐诗','yuding','','[]','近有人從海上回，海山深處見樓臺。',32,'御定全唐詩/json/459.json','["近有人從海上回，海山深處見樓臺。", "中有仙龕虛一室，多傳此待樂天來。"]'),
('yuding-88','答客說','白居易','唐','御定全唐诗','yuding','','[]','吾學空門非學仙，恐君此說是虛傳。',32,'御定全唐詩/json/459.json','["吾學空門非學仙，恐君此說是虛傳。", "海山不是吾歸處，歸即應歸兜率天。"]'),
('yuding-89','哭劉尚書夢得二首','白居易','唐','御定全唐诗','yuding','','[]','四海齊名白與劉，百年交分兩綢繆。同貧同病退閑日，',80,'御定全唐詩/json/459.json','["四海齊名白與劉，百年交分兩綢繆。同貧同病退閑日，", "賢豪雖歿精靈在，應共微之地下游。", "今日哭君吾道孤，寢門淚滿白髭須。不知箭折弓何用，", "夜台暮齒期非遠，但問前頭相見無。"]'),
('yuding-0','昨日複今辰','白居易','唐','御定全唐诗','yuding','','[]','昨日複今辰，悠悠七十春。所經多故處，卻想似前身。',72,'御定全唐詩/json/460.json','["昨日複今辰，悠悠七十春。所經多故處，卻想似前身。", "散秩優遊老，閒居淨潔貧。螺杯中有物，鶴氅上無塵。", "解佩收朝帶，抽簪換野巾。風儀與名號，別是一生人。"]'),
('yuding-1','病瘡','白居易','唐','御定全唐诗','yuding','','[]','門有醫來往，庭無客送迎。病銷談笑興，老足歎嗟聲。',48,'御定全唐詩/json/460.json','["門有醫來往，庭無客送迎。病銷談笑興，老足歎嗟聲。", "鶴伴臨池立，人扶下砌行。腳瘡春斷酒，那得有心情。"]'),
('yuding-2','游趙村杏花','白居易','唐','御定全唐诗','yuding','','[]','趙村紅杏每年開，十五年來看幾回。',32,'御定全唐詩/json/460.json','["趙村紅杏每年開，十五年來看幾回。", "七十三人難再到，今春來是別花來。"]'),
('yuding-3','刑部尚書致仕','白居易','唐','御定全唐诗','yuding','','[]','十五年來洛下居，道緣俗累兩何如。迷路心回因向佛，',40,'御定全唐詩/json/460.json','["十五年來洛下居，道緣俗累兩何如。迷路心回因向佛，", "唯是名銜人不會，毗耶長者白尚書。"]'),
('yuding-4','初致仕後戲酬留守牛相公，並呈分司諸寮友','白居易','唐','御定全唐诗','yuding','','[]','南北東西無所羈，掛冠自在勝分司。探花嘗酒多先到，',40,'御定全唐詩/json/460.json','["南北東西無所羈，掛冠自在勝分司。探花嘗酒多先到，", "報君一語君應笑，兼亦無心羨保厘。"]'),
('yuding-5','問諸親友','白居易','唐','御定全唐诗','yuding','','[]','七十人難到，過三更較稀。占花租野寺，定酒典朝衣。',48,'御定全唐詩/json/460.json','["七十人難到，過三更較稀。占花租野寺，定酒典朝衣。", "趁醉春多出，貪歡夜未歸。不知親故口，道我是耶非。"]'),
('yuding-6','戲問牛司徒','白居易','唐','御定全唐诗','yuding','','[]','抖擻塵纓捋白須，半酣扶起問司徒。',32,'御定全唐詩/json/460.json','["抖擻塵纓捋白須，半酣扶起問司徒。", "不知詔下懸車後，醉舞狂歌有例無。"]'),
('yuding-7','不與老為期','白居易','唐','御定全唐诗','yuding','','[]','不與老為期，因何兩鬢絲。才應免夭促，便已及衰羸。',96,'御定全唐詩/json/460.json','["不與老為期，因何兩鬢絲。才應免夭促，便已及衰羸。", "昨夜夢何在，明朝身不知。百憂非我所，三樂是吾師。", "閉目常閑坐，低頭每靜思。存神機慮息，養氣語言遲。", "行亦攜詩篋，眠多枕酒卮。自慚無一事，少有不安時。"]'),
('yuding-8','開龍門八節石灘詩二首','白居易','唐','御定全唐诗','yuding','','[]','鐵鑿金錘殷若雷，八灘九石劍棱摧。竹篙桂楫飛如箭，',80,'御定全唐詩/json/460.json','["鐵鑿金錘殷若雷，八灘九石劍棱摧。竹篙桂楫飛如箭，", "他時相逐四方去，莫慮塵沙路不開。", "七十三翁旦暮身，誓開險路作通津。夜舟過此無傾覆，", "我身雖歿心長在，暗施慈悲與後人。"]'),
('yuding-9','閑坐','白居易','唐','御定全唐诗','yuding','','[]','婆娑放雞犬，嬉戲任兒童。閑坐槐陰下，開襟向晚風。',48,'御定全唐詩/json/460.json','["婆娑放雞犬，嬉戲任兒童。閑坐槐陰下，開襟向晚風。", "漚麻池水裏，曬棗日陽中。人物何相稱，居然田舍翁。"]'),
('yuding-10','酬寄牛相公同宿話舊勸酒見贈','白居易','唐','御定全唐诗','yuding','','[]','每來政事堂中宿，共憶華陽觀裏時。日暮獨歸愁米盡，',40,'御定全唐詩/json/460.json','["每來政事堂中宿，共憶華陽觀裏時。日暮獨歸愁米盡，", "彼此相看頭雪白，一杯可合重推辭。"]'),
('yuding-11','道場獨坐','白居易','唐','御定全唐诗','yuding','','[]','整頓衣巾拂淨床，一瓶秋水一爐香。不論煩惱先須去，',40,'御定全唐詩/json/460.json','["整頓衣巾拂淨床，一瓶秋水一爐香。不論煩惱先須去，", "世間無用殘年處，只合逍遙坐道場。"]'),
('yuding-12','偶作寄朗之','白居易','唐','御定全唐诗','yuding','','[]','曆想為官日，無如刺史時。歡娛接賓客，飽暖及妻兒。',168,'御定全唐詩/json/460.json','["曆想為官日，無如刺史時。歡娛接賓客，飽暖及妻兒。", "自到東都後，安閒更得宜。分司勝刺史，致仕勝分司。", "何況園林下，欣然得朗之。仰名同舊識，為樂即新知。", "有雪先相訪，無花不作期。鬥醲幹釀酒，誇妙細吟詩。", "裏巷千來往，都門五別離。岐分兩回首，書到一開眉。", "葉落槐亭院，冰生竹閣池。雀羅誰問訊，鶴氅罷追隨。", "身與心俱病，容將力共衰。老來多健忘，唯不忘相思。"]'),
('yuding-13','狂吟七言十四韻','白居易','唐','御定全唐诗','yuding','','[]','亦知世是休明世，自想身非富貴身。但恐人間為長物，',96,'御定全唐詩/json/460.json','["亦知世是休明世，自想身非富貴身。但恐人間為長物，", "性海澄渟平少浪，心田灑掃淨無塵。香山閑宿一千夜，", "藥停有喜閑銷疾，金盡無憂醉忘貧。補綻衣裳愧妻女，", "洛堰魚鮮供取足，遊村果熟饋爭新。詩章人與傳千首，"]'),
('yuding-14','喜裴濤使君攜詩見訪，醉中戲贈','白居易','唐','御定全唐诗','yuding','','[]','忽聞扣戶醉吟聲，不覺停杯倒屣迎。',32,'御定全唐詩/json/460.json','["忽聞扣戶醉吟聲，不覺停杯倒屣迎。", "共放詩狂同酒癖，與君別是一親情。"]'),
('yuding-15','得潮州楊相公繼之書並詩，以此寄之','白居易','唐','御定全唐诗','yuding','','[]','詩情書意兩殷勤，來自天南瘴海濱。初睹銀鉤還啟齒，',40,'御定全唐詩/json/460.json','["詩情書意兩殷勤，來自天南瘴海濱。初睹銀鉤還啟齒，", "唯有新昌故園月，至今分照兩鄉人。"]'),
('yuding-16','宿府池西亭','白居易','唐','御定全唐诗','yuding','','[]','池上平橋橋下亭，夜深睡覺上橋行。',32,'御定全唐詩/json/460.json','["池上平橋橋下亭，夜深睡覺上橋行。", "白頭老尹重來宿，十五年前舊月明。"]'),
('yuding-17','閑眠','白居易','唐','御定全唐诗','yuding','','[]','暖床斜臥日曛腰，一覺閑眠百病銷。',32,'御定全唐詩/json/460.json','["暖床斜臥日曛腰，一覺閑眠百病銷。", "盡日一餐茶兩碗，更無所要到明朝。"]'),
('yuding-18','楊柳枝詞','白居易','唐','御定全唐诗','yuding','','[]','一樹春風千萬枝，嫩于金色軟於絲。',32,'御定全唐詩/json/460.json','["一樹春風千萬枝，嫩于金色軟於絲。", "永豐西角荒園裏，盡日無人屬阿誰。"]'),
('yuding-19','詔取永豐柳植禁苑感賦','白居易','唐','御定全唐诗','yuding','','[]','一樹衰殘委泥土，雙枝榮耀植天庭。',32,'御定全唐詩/json/460.json','["一樹衰殘委泥土，雙枝榮耀植天庭。", "定知玄象今春後，柳宿光中添兩星。"]'),
('yuding-20','齋居春久，感事遣懷','白居易','唐','御定全唐诗','yuding','','[]','齋戒坐三旬，笙歌發四鄰。月明停酒夜，眼暗看花人。',96,'御定全唐詩/json/460.json','["齋戒坐三旬，笙歌發四鄰。月明停酒夜，眼暗看花人。", "賴學空為觀，深知念是塵。猶思閑語笑，未忘舊交親。", "久作龍門主，多為兔苑賓。水嬉歌盡日，雪宴燭通晨。", "事事皆過分，時時自問身。風光拋得也，七十四年春。"]'),
('yuding-21','每見呂南二郎中新文輒竊有所嘆惜因成長句以詠所懷','白居易','唐','御定全唐诗','yuding','','[]','雙金百煉少人知，縱我知君徒爾為。望梅閣老無妨渴，',40,'御定全唐詩/json/460.json','["雙金百煉少人知，縱我知君徒爾為。望梅閣老無妨渴，", "壯年可惜虛銷擲，遣把閑杯吟詠詩。"]'),
('yuding-22','胡吉鄭劉盧張等六賢皆多年壽予亦次焉偶於弊居合成尚齒之會七老相顧既醉且歡靜而思之此會稀有因成七言六韻以紀之傳好事者','白居易','唐','御定全唐诗','yuding','','[]','七人五百七十歲，拖紫紆朱垂白須。手裏無金莫嗟歎，',48,'御定全唐詩/json/460.json','["七人五百七十歲，拖紫紆朱垂白須。手裏無金莫嗟歎，", "嵬峨狂歌教婢拍，婆娑醉舞遣孫扶。天年高過二疏傅，"]'),
('yuding-23','歡喜二偈','白居易','唐','御定全唐诗','yuding','','[]','得老加年誠可喜，當春對酒亦宜歡。',64,'御定全唐詩/json/460.json','["得老加年誠可喜，當春對酒亦宜歡。", "心中別有歡喜事，開得龍門八節灘。", "眼暗頭旋耳重聽，唯餘心口尚醒醒。", "今朝歡喜緣何事，禮徹佛名百部經。"]'),
('yuding-24','閒居貧活計','白居易','唐','御定全唐诗','yuding','','[]','冠蓋閒居少，簞瓢陋巷深。稱家開戶牖，量力置園林。',72,'御定全唐詩/json/460.json','["冠蓋閒居少，簞瓢陋巷深。稱家開戶牖，量力置園林。", "儉薄身都慣，營為力不任。饑烹一斤肉，暖臥兩重衾。", "尊有陶潛酒，囊無陸賈金。莫嫌貧活計，更富即勞心。"]'),
('yuding-25','贈諸少年','白居易','唐','御定全唐诗','yuding','','[]','少年莫笑我蹉跎，聽我狂翁一曲歌。入手榮名取雖少，',40,'御定全唐詩/json/460.json','["少年莫笑我蹉跎，聽我狂翁一曲歌。入手榮名取雖少，", "官給俸錢天與壽，些些貧病奈吾何。"]'),
('yuding-26','感所見','白居易','唐','御定全唐诗','yuding','','[]','巧者焦勞智者愁，愚翁何喜複何憂。莫嫌山木無人用，',40,'御定全唐詩/json/460.json','["巧者焦勞智者愁，愚翁何喜複何憂。莫嫌山木無人用，", "誰人會我心中事，冷笑時時一掉頭。"]'),
('yuding-27','寄黔州馬常侍','白居易','唐','御定全唐诗','yuding','','[]','閑看雙節信為貴，樂飲一杯誰與同。',32,'御定全唐詩/json/460.json','["閑看雙節信為貴，樂飲一杯誰與同。", "可惜風情與心力，五年拋擲在黔中。"]'),
('yuding-28','和李相公留守題漕上新橋六韻','白居易','唐','御定全唐诗','yuding','','[]','選石鋪新路，安橋壓古堤。似從銀漢下，落傍玉川西。',72,'御定全唐詩/json/460.json','["選石鋪新路，安橋壓古堤。似從銀漢下，落傍玉川西。", "影定欄杆倒，標高華表齊。煙開虹半見，月冷鶴雙棲。", "材映夔龍小，功嫌元凱低。從容濟世後，餘力及黔黎。"]'),
('yuding-29','閒居','白居易','唐','御定全唐诗','yuding','','[]','風雨蕭條秋少客，門庭冷靜晝多關。金羈駱馬近賣卻，',48,'御定全唐詩/json/460.json','["風雨蕭條秋少客，門庭冷靜晝多關。金羈駱馬近賣卻，", "眼昏入夜休看月，腳重經春不上山。心靜無妨喧處寂，"]'),
('yuding-30','新秋夜雨','白居易','唐','御定全唐诗','yuding','','[]','蟋蟀暮啾啾，光陰不少留。松簷半夜雨，風幌滿床秋。',48,'御定全唐詩/json/460.json','["蟋蟀暮啾啾，光陰不少留。松簷半夜雨，風幌滿床秋。", "曙早燈猶在，涼初簟未收。新晴好天氣，誰伴老人游。"]'),
('yuding-31','春眠','白居易','唐','御定全唐诗','yuding','','[]','枕低被暖身安穩，日照房門帳未開。',32,'御定全唐詩/json/460.json','["枕低被暖身安穩，日照房門帳未開。", "還有少年春氣味，時時暫到夢中來。"]'),
('yuding-32','喜老自嘲','白居易','唐','御定全唐诗','yuding','','[]','面黑頭雪白，自嫌還自憐。毛龜蓍下老，蝙蝠鼠中仙。',96,'御定全唐詩/json/460.json','["面黑頭雪白，自嫌還自憐。毛龜蓍下老，蝙蝠鼠中仙。", "名籍同逋客，衣裝類古賢。裘輕被白氎，靴暖蹋烏氈。", "周易休開卦，陶琴不上弦。任從人棄擲，自與我周旋。", "鐵馬因疲退，鉛刀以鈍全。行開第八秩，可謂盡天年。"]'),
('yuding-33','能無愧','白居易','唐','御定全唐诗','yuding','','[]','十兩新綿褐，披行暖似春。一團香絮枕，倚坐穩於人。',48,'御定全唐詩/json/460.json','["十兩新綿褐，披行暖似春。一團香絮枕，倚坐穩於人。", "婢僕遣他嘗藥草，兒孫與我拂衣巾。回看左右能無愧，"]'),
('yuding-34','河陽石尚書破迴鶻迎貴主過上黨射鷺𪆁繪畫為圖猥蒙見示稱歎不足以詩美之','白居易','唐','御定全唐诗','yuding','','[]','塞北虜郊隨手破，山東賊壘掉鞭收。烏孫公主歸秦地，',48,'御定全唐詩/json/460.json','["塞北虜郊隨手破，山東賊壘掉鞭收。烏孫公主歸秦地，", "須知鳥目猶難漏，縱有天狼豈足憂。畫角三聲刁鬥曉，"]'),
('yuding-35','自詠老身示諸家屬','白居易','唐','御定全唐诗','yuding','','[]','壽及七十五，俸沾五十千。夫妻偕老日，甥侄聚居年。',96,'御定全唐詩/json/460.json','["壽及七十五，俸沾五十千。夫妻偕老日，甥侄聚居年。", "粥美嘗新米，袍溫換故綿。家居雖濩落，眷屬幸團圓。", "置榻素屏下，移爐青帳前。書聽孫子讀，湯看侍兒煎。", "走筆還詩債，抽衣當藥錢。支分閒事了，爬背向陽眠。"]'),
('yuding-36','自問此心呈諸老伴','白居易','唐','御定全唐诗','yuding','','[]','朝問此心何所思，暮問此心何所為。不入公門慵斂手，',48,'御定全唐詩/json/460.json','["朝問此心何所思，暮問此心何所為。不入公門慵斂手，", "閒談亹亹留諸老，美醞徐徐進一卮。心未曾求過分事，"]'),
('yuding-37','六年立春日人日作','白居易','唐','御定全唐诗','yuding','','[]','二日立春人七日，盤蔬餅餌逐時新。年方吉鄭猶為少，',40,'御定全唐詩/json/460.json','["二日立春人七日，盤蔬餅餌逐時新。年方吉鄭猶為少，", "試作循潮封眼想，何由得見洛陽春。"]'),
('yuding-38','齋居偶作','白居易','唐','御定全唐诗','yuding','','[]','童子裝爐火，行添一炷香。老翁持麈尾，坐拂半張床。',96,'御定全唐詩/json/460.json','["童子裝爐火，行添一炷香。老翁持麈尾，坐拂半張床。", "卷縵看天色，移齋近日陽。甘鮮新餅果，穩暖舊衣裳。", "止足安生理，悠閒樂性場。是非一以遣，動靜百無妨。", "豈有物相累，兼無情可忘。不須憂老病，心是自醫王。"]'),
('yuding-39','詠身','白居易','唐','御定全唐诗','yuding','','[]','自中風來三曆閏，從懸車後幾逢春。周南留滯稱遺老，',40,'御定全唐詩/json/460.json','["自中風來三曆閏，從懸車後幾逢春。周南留滯稱遺老，", "餘年自問將何用，恐是人間剩長身。"]'),
('yuding-40','予與山南王僕射起淮南李僕射紳事歷五朝踰三紀海內年輩今唯三人榮路雖殊交情不替聊題長句寄舉之公垂二相公','白居易','唐','御定全唐诗','yuding','','[]','故交海內只三人，二坐岩廊一臥雲。老愛詩書還似我，',40,'御定全唐詩/json/460.json','["故交海內只三人，二坐岩廊一臥雲。老愛詩書還似我，", "阿閣鸞凰野田鶴，何人通道舊同群。"]'),
('yuding-41','讀道德經','白居易','唐','御定全唐诗','yuding','','[]','玄元皇帝著遺文，烏角先生仰後塵。金玉滿堂非己物，',40,'御定全唐詩/json/460.json','["玄元皇帝著遺文，烏角先生仰後塵。金玉滿堂非己物，", "只有一身宜愛護，少教冰炭逼心神。"]'),
('yuding-42','禽蟲十二章','白居易','唐','御定全唐诗','yuding','','[]','燕違戊巳鵲避歲，茲事因何羽族知。',384,'御定全唐詩/json/460.json','["燕違戊巳鵲避歲，茲事因何羽族知。", "疑有鳳凰頒鳥曆，一時一日不參差。", "水中科鬥長成蛙，林下桑蟲老作蛾。", "蛙跳蛾舞仰頭笑，焉用鶤鵬鱗羽多。", "江魚群從稱妻妾，塞雁聯行號弟兄。", "但恐世間真眷屬，親疏亦是強為名。", "蠶老繭成不庇身，蜂饑蜜熟屬他人。", "須知年老憂家者，恐是二蟲虛苦辛。", "阿閣鵷鸞田舍烏，妍蚩貴賤兩懸殊。", "如何閉向深籠裏，一種摧頹觸四隅。", "獸中刀槍多怒吼，鳥遭羅弋盡哀鳴。", "羔羊口在緣何事，暗死屠門無一聲。", "蟭螟殺敵蚊巢上，蠻觸交爭蝸角中。", "應是諸天觀下界，一微塵內鬥英雄。", "蠨蛸網上罥蜉蝣，反復相持死始休。", "何異浮生臨老日，一彈指頃報恩讎。", "蟻王化飯為臣妾，蜾母偷蟲作子孫。", "彼此假名非本物，其間何怨複何恩。", "豆苗鹿嚼解烏毒，艾葉雀銜奪燕巢。", "鳥獸不曾看本草，諳知藥性是誰教。", "一鼠得仙生羽翼，眾鼠相看有羨色。", "豈知飛上未半空，已作烏鳶口中食。", "鵝乳養雛遺在水，魚心想子變成鱗。", "細微幽隱何窮事，知者唯應是聖人。"]'),
('yuding-0','窗中列遠岫','白居易','唐','御定全唐诗','yuding','','[]','天靜秋山好，窗開曉翠通。遙憐峰窈窕，不隔竹朦朧。',72,'御定全唐詩/json/461.json','["天靜秋山好，窗開曉翠通。遙憐峰窈窕，不隔竹朦朧。", "萬點當虛室，千重疊遠空。列簷攢秀氣，緣隙助清風。", "碧愛新晴後，明宜反照中。宣城郡齋在，望與古時同。"]'),
('yuding-1','玉水記方流','白居易','唐','御定全唐诗','yuding','','[]','良璞含章久，寒泉徹底幽。矩浮光灩灩，方折浪悠悠。',72,'御定全唐詩/json/461.json','["良璞含章久，寒泉徹底幽。矩浮光灩灩，方折浪悠悠。", "淩亂波紋異，縈回水性柔。似風搖淺瀨，疑月落清流。", "潛潁應傍達，藏真豈上浮。玉人如不見，淪棄即千秋。"]'),
('yuding-2','大社觀獻捷詩','白居易','唐','御定全唐诗','yuding','','[]','淮海妖氛滅，乾坤嘉氣通。班師郊社內，操袂凱歌中。',48,'御定全唐詩/json/461.json','["淮海妖氛滅，乾坤嘉氣通。班師郊社內，操袂凱歌中。", "廟算無遺策，天兵不戰功。小臣同鳥獸，率舞向皇風。"]'),
('yuding-3','自誨','白居易','唐','御定全唐诗','yuding','','[]','樂天樂天，來與汝言。汝宜拳拳，終身行焉。物有萬類，',164,'御定全唐詩/json/461.json','["樂天樂天，來與汝言。汝宜拳拳，終身行焉。物有萬類，", "使汝未老，形枯如柴。萬感遞至，火汝心懷。使汝未死，", "人生百歲七十稀，設使與汝七十期。汝今年已四十四，", "樂天樂天，可不大哀。而今而後，汝宜饑而食，渴而飲；", "晝而興，夜而寢；無浪喜，無妄憂；病則臥，死則休。", "此中是汝家，此中是汝鄉，汝何舍此而去，自取其遑遑。", "遑遑兮欲安往哉，樂天樂天歸去來。"]'),
('yuding-4','三謠：蟠木謠','白居易','唐','御定全唐诗','yuding','','[]','蟠木蟠木，有似我身；不中乎器，無用於人。',129,'御定全唐詩/json/461.json','["蟠木蟠木，有似我身；不中乎器，無用於人。", "下擁腫而上轔菌，桷不桷兮輪不輪。", "天子建明堂兮既非梁棟，諸侯斫大輅兮材又不中。", "唯我病夫，或有所用。用爾為幾，承吾臂支吾頤而已矣。", "不傷爾性，不枉爾理。爾怏怏為幾之外，無所用爾。", "爾既不材，吾亦不材，胡為乎人間裴回？蟠木蟠木，"]'),
('yuding-5','三謠：素屏謠','白居易','唐','御定全唐诗','yuding','','[]','素屏素屏，胡為乎不文不飾，不丹不青？',104,'御定全唐詩/json/461.json','["素屏素屏，胡為乎不文不飾，不丹不青？", "當世豈無李陽冰之篆字，張旭之筆跡？邊鸞之花鳥，", "吾於香爐峰下置草堂，二屏倚在東西牆。", "夜如明月入我室，曉如白雲圍我床。我心久養浩然氣，", "貴豪待此方悅目，晏然寢臥乎其中。素屏素屏，"]'),
('yuding-6','三謠：朱藤謠','白居易','唐','御定全唐诗','yuding','','[]','朱藤朱藤，溫如紅玉，直如朱繩。自我得爾以為杖，',94,'御定全唐詩/json/461.json','["朱藤朱藤，溫如紅玉，直如朱繩。自我得爾以為杖，", "中途不進，部曲多回。唯此朱藤，實隨我來。瘴癘之鄉，", "或水或陸，自北徂南。泥黏雪滑，足力不堪。吾本兩足，", "吾與爾披雲撥水，環山繞野。二年蹋遍匡廬間，"]'),
('yuding-7','無可奈何歌','白居易','唐','御定全唐诗','yuding','','[]','無可奈何兮，白日走而朱顏頹。少日往而老日催，',180,'御定全唐詩/json/461.json','["無可奈何兮，白日走而朱顏頹。少日往而老日催，", "嗟吾生之幾何，寄瞬息乎其中。又如太倉之稊米，", "倔強其骨髓，齟齬其心胸。合冰炭以交戰，只自苦兮厥躬。", "彼造物者，雲何不為？此與化者，雲何不隨？或喣或吹，", "誰達此觀，喪馬之翁。俾吾為秋毫之杪，吾亦自足，", "是以達人靜則吻然與陰合跡，動則浩然與陽同波。", "委順而已，孰知其他。時邪命邪，吾其無奈彼何；", "委邪順邪，彼亦無奈吾何。夫兩無奈何，"]'),
('yuding-8','池上篇','白居易','唐','御定全唐诗','yuding','','[]','十畝之宅，五畝之園。有水一池，有竹千竿。勿謂土狹，',75,'御定全唐詩/json/461.json','["十畝之宅，五畝之園。有水一池，有竹千竿。勿謂土狹，", "有書有酒，有歌有弦。有叟在中，白須飄然。識分知足，", "靈鶴怪石，紫菱白蓮。皆吾所好，盡在吾前。時飲一杯，"]'),
('yuding-9','齒落辭','白居易','唐','御定全唐诗','yuding','','[]','嗟嗟乎雙齒，自吾有之爾，俾爾嚼肉咀蔬，銜杯漱水；',167,'御定全唐詩/json/461.json','["嗟嗟乎雙齒，自吾有之爾，俾爾嚼肉咀蔬，銜杯漱水；", "豐吾膚革，滋吾血髓；從幼逮老，勤亦至矣。幸有輔車，", "老與齒別，齒隨涕零。我老日來，爾去不回。嗟嗟乎雙齒，", "為口中之物，忽乎六十餘年。昔君之壯也，血剛齒堅；", "今君之老矣，血衰齒寒。輔車齗齶，日削月朘。", "上參差而下卼臲，曾何足以少安。嘻，君其聽哉：", "女長辭姥，臣老辭主。發衰辭頭，葉枯辭樹。物無細大，"]'),
('yuding-10','不能忘情吟','白居易','唐','御定全唐诗','yuding','','[]','鬻駱馬兮放楊柳枝，掩翠黛兮頓金羈。',77,'御定全唐詩/json/461.json','["鬻駱馬兮放楊柳枝，掩翠黛兮頓金羈。", "馬不能言兮長鳴而卻顧，楊柳枝再拜長跪而致辭。", "辭曰：主乘此駱五年，凡千有八百日。銜橛之下，", "我姑酌彼金罍，我與爾歸醉鄉去來。"]'),
('yuding-0','《勸酒','白居易','唐','御定全唐诗','yuding','','[]','昨與美人對尊酒，朱顏如花腰似柳。今與美人傾一杯，',160,'御定全唐詩/json/462.json','["昨與美人對尊酒，朱顏如花腰似柳。今與美人傾一杯，", "東鄰起樓高百尺，璿題照日光相射。珠翠無非二八人，", "身年三十未入仕，仰望東鄰安可期。一朝逸翮乘風勢，", "不逾十稔居台衡，門前車馬紛縱橫。人人仰望在何處，", "金玉車馬一不存，朱門更有何人待。牆垣反鎖長安春，", "憶昔東鄰宅初構，雲甍彩棟皆非舊。玳瑁筵前翡翠棲，", "但教帝裏笙歌在，池上年年醉五侯。"]'),
('yuding-1','南陽小將張彥硤口鎮稅人場射虎歌','白居易','唐','御定全唐诗','yuding','','[]','海內昔年狎太平，橫目穰穰何崢嶸。天生天殺豈天怒，',88,'御定全唐詩/json/462.json','["海內昔年狎太平，橫目穰穰何崢嶸。天生天殺豈天怒，", "張彥雄特製殘暴，見之叱起如叱羊。鳴弦霹靂越幽阻，", "老饕已斃眾雛恐，童稚揶揄皆自勇。忠良效順勢亦然，", "試征張彥作將軍，幾個將軍願策勳。"]'),
('yuding-2','陰雨','白居易','唐','御定全唐诗','yuding','','[]','潤葉濡枝浹四方，濃雲來去勢何長。',32,'御定全唐詩/json/462.json','["潤葉濡枝浹四方，濃雲來去勢何長。", "曠然寰宇清風滿，救旱功高暑氣涼。"]'),
('yuding-3','喜雨','白居易','唐','御定全唐诗','yuding','','[]','西北油然雲勢濃，須臾滂沛雨飄空。',32,'御定全唐詩/json/462.json','["西北油然雲勢濃，須臾滂沛雨飄空。", "頓疏萬物焦枯意，定看秋郊稼穡豐。"]'),
('yuding-4','過故洛城','白居易','唐','御定全唐诗','yuding','','[]','故城門前春日斜，故城門裏無人家。',32,'御定全唐詩/json/462.json','["故城門前春日斜，故城門裏無人家。", "市朝欲認不知處，漠漠野田飛草花。"]'),
('yuding-5','江南喜逢蕭九徹因話長安舊遊戲贈五十韻','白居易','唐','御定全唐诗','yuding','','[]','憶昔嬉遊伴，多陪歡宴場。寓居同永樂，幽會共平康。',576,'御定全唐詩/json/462.json','["憶昔嬉遊伴，多陪歡宴場。寓居同永樂，幽會共平康。", "師子尋前曲，聲兒出內坊。花深態奴宅，竹錯得憐堂。", "庭晚開紅藥，門閑蔭綠楊。經過悉同巷，居處盡連牆。", "時世高梳髻，風流澹作妝。戴花紅石竹，帔暈紫檳榔。", "鬢動懸蟬翼，釵垂小鳳行。拂胸輕粉絮，暖手小香囊。", "選勝移銀燭，邀歡舉玉觴。爐煙凝麝氣，酒色注鵝黃。", "急管停還奏，繁弦慢更張。雪飛回舞袖，塵起繞歌梁。", "舊曲翻調笑，新聲打義揚。名情推阿軌，巧語許秋娘。", "風暖春將暮，星回夜未央。宴餘添粉黛，坐久換衣裳。", "結伴歸深院，分頭入洞房。彩帷開翡翠，羅薦拂鴛鴦。", "留宿爭牽袖，貪眠各占床。綠窗籠水影，紅壁背燈光。", "索鏡收花鈿，邀人解袷襠。暗嬌妝靨笑，私語口脂香。", "怕聽鐘聲坐，羞明映縵藏。眉殘蛾翠淺，鬟解綠雲長。", "聚散知無定，憂歡事不常。離筵開夕宴，別騎促晨裝。", "去住青門外，留連滻水傍。車行遙寄語，馬駐共相望。", "雲雨分何處，山川共異方。野行初寂寞，店宿乍恓惶。", "別後嫌宵永，愁來厭歲芳。幾看花結子，頻見露為霜。", "歲月何超忽，音容坐渺茫。往還書斷絕，來去夢遊揚。", "自我辭秦地，逢君客楚鄉。常嗟異岐路，忽喜共舟航。", "話舊堪垂淚，思鄉數斷腸。愁雲接巫峽，淚竹近瀟湘。", "月落江湖闊，天高節候涼。浦深煙渺渺，沙冷月蒼蒼。", "紅葉江楓老，青蕪驛路荒。野風吹蟋蟀，湖水浸菰蔣。", "帝路何由見，心期不可忘。舊遊千裏外，往事十年強。", "春晝提壺飲，秋林摘橘嘗。強歌還自感，縱飲不成狂。"]'),
('yuding-6','贈薛濤','白居易','唐','御定全唐诗','yuding','','[]','蛾眉山勢接雲霓，欲逐劉郎北路迷。',32,'御定全唐詩/json/462.json','["蛾眉山勢接雲霓，欲逐劉郎北路迷。", "若似剡中容易到，春風猶隔武陵溪。"]'),
('yuding-7','酬令狐留守尚書見贈十韻','白居易','唐','御定全唐诗','yuding','','[]','長慶清風在，夔龍燮理餘。太和膏雨降，周邵保厘初。',120,'御定全唐詩/json/462.json','["長慶清風在，夔龍燮理餘。太和膏雨降，周邵保厘初。", "嵩少當宮署，伊瀍入禁渠。曉關開玉兔，夕鑰納銀魚。", "舊眷憐移疾，新吟念索居。離聲雙白鸝，行色一籃輿。", "罷免無餘俸，休閒有敝廬。慵于嵇叔夜，渴似馬相如。", "酒每蒙酤我，詩嘗許起予。洛中歸計定，一半為尚書。"]'),
('yuding-8','聽蘆管','白居易','唐','御定全唐诗','yuding','','[]','幽咽新蘆管，淒涼古竹枝。似臨猿峽唱，疑在雁門吹。',96,'御定全唐詩/json/462.json','["幽咽新蘆管，淒涼古竹枝。似臨猿峽唱，疑在雁門吹。", "調為高多切，聲緣小乍遲。粗豪嫌觱篥，細妙勝參差。", "雲水巴南客，風沙隴上兒。屈原收淚夜，蘇武斷腸時。", "仰秣胡駒聽，驚棲越鳥知。何言胡越異，聞此一同悲。"]'),
('yuding-9','送滕庶子致仕歸婺州','白居易','唐','御定全唐诗','yuding','','[]','春風秋月攜歌酒，八十年來玩物華。已見曾孫騎竹馬，',40,'御定全唐詩/json/462.json','["春風秋月攜歌酒，八十年來玩物華。已見曾孫騎竹馬，", "兒著繡衣身衣錦，東陽門戶勝滕家。"]'),
('yuding-10','送劉郎中赴任蘇州','白居易','唐','御定全唐诗','yuding','','[]','仁風膏雨去隨輪，勝境歡遊到逐身。水驛路穿兒店月，',40,'御定全唐詩/json/462.json','["仁風膏雨去隨輪，勝境歡遊到逐身。水驛路穿兒店月，", "何似姑蘇詩太守，吟詩相繼有三人。"]'),
('yuding-11','福先寺雪中餞劉蘇州','白居易','唐','御定全唐诗','yuding','','[]','送君何處展離筵，大梵王宮大雪天。庾嶺梅花落歌管，',40,'御定全唐詩/json/462.json','["送君何處展離筵，大梵王宮大雪天。庾嶺梅花落歌管，", "卻笑召鄒兼訪戴，只持空酒駕空船。"]'),
('yuding-12','除夜言懷，兼贈張常侍','白居易','唐','御定全唐诗','yuding','','[]','三百六旬今夜盡，六十四年明日催。不用歎身隨日老，',40,'御定全唐詩/json/462.json','["三百六旬今夜盡，六十四年明日催。不用歎身隨日老，", "唯恨詩成君去後，紅箋紙卷為誰開。"]'),
('yuding-13','送張常侍西歸','白居易','唐','御定全唐诗','yuding','','[]','二年花下為閑伴，一旦尊前棄老夫。西午橋街行悵望，',40,'御定全唐詩/json/462.json','["二年花下為閑伴，一旦尊前棄老夫。西午橋街行悵望，", "出鎮歸朝但相訪，此身應不離東都。"]'),
('yuding-14','和河南鄭尹新歲對雪','白居易','唐','御定全唐诗','yuding','','[]','白雪吟詩鈴閣開，故情新興兩裴回。昔經勤苦照書卷，',40,'御定全唐詩/json/462.json','["白雪吟詩鈴閣開，故情新興兩裴回。昔經勤苦照書卷，", "銅街金穀春知否，又有詩人作尹來。"]'),
('yuding-15','吹笙內人出家','白居易','唐','御定全唐诗','yuding','','[]','雨露難忘君念重，電泡易滅妾身輕。金刀已剃頭然發，',40,'御定全唐詩/json/462.json','["雨露難忘君念重，電泡易滅妾身輕。金刀已剃頭然發，", "道場夜半香花冷，猶在燈前禮佛名。"]'),
('yuding-16','醉中見微之舊卷有感','白居易','唐','御定全唐诗','yuding','','[]','今朝何事一沾襟，檢得君詩醉後吟。老淚交流風病眼，',40,'御定全唐詩/json/462.json','["今朝何事一沾襟，檢得君詩醉後吟。老淚交流風病眼，", "聞道墓松高一丈，更無消息到如今。"]'),
('yuding-17','壽安歇馬重吟','白居易','唐','御定全唐诗','yuding','','[]','春衫細薄馬蹄輕，一日遲遲進一程。野棗花含新蜜氣，',40,'御定全唐詩/json/462.json','["春衫細薄馬蹄輕，一日遲遲進一程。野棗花含新蜜氣，", "忽憶家園須速去，櫻桃欲熟筍應生。"]'),
('yuding-18','贈張處士山人','白居易','唐','御定全唐诗','yuding','','[]','蘿襟蕙帶竹皮巾，雖到塵中不染塵。每見俗人多慘澹，',40,'御定全唐詩/json/462.json','["蘿襟蕙帶竹皮巾，雖到塵中不染塵。每見俗人多慘澹，", "世說三生如不謬，共疑巢許是前身。"]'),
('yuding-19','池畔閑坐，兼呈侍中','白居易','唐','御定全唐诗','yuding','','[]','池畔最平處，樹陰新合時。移床解衣帶，坐任清風吹。',48,'御定全唐詩/json/462.json','["池畔最平處，樹陰新合時。移床解衣帶，坐任清風吹。", "舉棹鳥先覺，垂綸魚未知。前頭何所有，一卷晉公詩。"]'),
('yuding-20','初冬即事憶皇甫十','白居易','唐','御定全唐诗','yuding','','[]','冷竹風成韻，荒街葉作堆。欲尋聯句卷，先飲暖寒杯。',48,'御定全唐詩/json/462.json','["冷竹風成韻，荒街葉作堆。欲尋聯句卷，先飲暖寒杯。", "帽為迎霜戴，爐因試火開。時時還有客，終不當君來。"]'),
('yuding-21','小庭寒夜寄夢得','白居易','唐','御定全唐诗','yuding','','[]','庭小同蝸舍，門閑稱雀羅。火將燈共盡，風與雪相和。',48,'御定全唐詩/json/462.json','["庭小同蝸舍，門閑稱雀羅。火將燈共盡，風與雪相和。", "老睡隨年減，衰情向夕多。不知同病者，爭奈夜長何。"]'),
('yuding-22','西還壽安路西歇馬','白居易','唐','御定全唐诗','yuding','','[]','槐陰歇鞍馬，柳絮惹衣巾。日晚獨歸路，春深多思人。',48,'御定全唐詩/json/462.json','["槐陰歇鞍馬，柳絮惹衣巾。日晚獨歸路，春深多思人。", "去家才百里，為客只三旬。已念紗窗下，應生寶瑟塵。"]'),
('yuding-23','雨中訪崔十八','白居易','唐','御定全唐诗','yuding','','[]','肩舁仍挈榼，莫怪就君來。秋雨經三宿，無人勸一杯。',24,'御定全唐詩/json/462.json','["肩舁仍挈榼，莫怪就君來。秋雨經三宿，無人勸一杯。"]'),
('yuding-24','夢得得新詩','白居易','唐','御定全唐诗','yuding','','[]','池上今宵風月涼，閑教少樂理霓裳。',32,'御定全唐詩/json/462.json','["池上今宵風月涼，閑教少樂理霓裳。", "集仙殿裏新詞到，便播笙歌作樂章。"]'),
('yuding-25','初見劉二十八郎中有感','白居易','唐','御定全唐诗','yuding','','[]','欲話毗陵君反袂，欲言夏口我沾衣。',32,'御定全唐詩/json/462.json','["欲話毗陵君反袂，欲言夏口我沾衣。", "誰知臨老相逢日，悲歎聲多語笑稀。"]'),
('yuding-26','夜題玉泉','白居易','唐','御定全唐诗','yuding','','[]','遇客多言愛山水，逢僧盡道厭囂塵。',32,'御定全唐詩/json/462.json','["遇客多言愛山水，逢僧盡道厭囂塵。", "玉泉潭畔松間宿，要且經年無一人。"]'),
('yuding-27','拜表早出，贈皇甫賓客','白居易','唐','御定全唐诗','yuding','','[]','一月一回同拜表，莫辭侵早過中橋。',32,'御定全唐詩/json/462.json','["一月一回同拜表，莫辭侵早過中橋。", "老于君者應無數，猶趁西京十五朝。"]'),
('yuding-28','贈鄭尹','白居易','唐','御定全唐诗','yuding','','[]','府池東北舊亭台，久別長思醉一回。',32,'御定全唐詩/json/462.json','["府池東北舊亭台，久別長思醉一回。", "但請主人空掃地，自攜杯酒管弦來。"]'),
('yuding-29','別楊同州後卻寄','白居易','唐','御定全唐诗','yuding','','[]','潘驛橋南醉中別，下邽村北醒時歸。',32,'御定全唐詩/json/462.json','["潘驛橋南醉中別，下邽村北醒時歸。", "春風怪我君知否，榆葉楊花撲面飛。"]'),
('yuding-30','狐泉店前作','白居易','唐','御定全唐诗','yuding','','[]','野狐泉上柳花飛，逐水東流便不歸。',32,'御定全唐詩/json/462.json','["野狐泉上柳花飛，逐水東流便不歸。", "花水悠悠兩無意，因風吹落偶相依。"]'),
('yuding-31','贈盧績','白居易','唐','御定全唐诗','yuding','','[]','餘杭縣裏盧明府，虛白亭中白舍人。',32,'御定全唐詩/json/462.json','["餘杭縣裏盧明府，虛白亭中白舍人。", "今日相逢頭似雪，一杯相勸送殘春。"]'),
('yuding-32','與裴華州同過敷水戲贈','白居易','唐','御定全唐诗','yuding','','[]','使君五馬且踟躕，馬上能聽絕句無。',32,'御定全唐詩/json/462.json','["使君五馬且踟躕，馬上能聽絕句無。", "每過桑間試留意，何妨後代有羅敷。"]'),
('yuding-33','閒遊','白居易','唐','御定全唐诗','yuding','','[]','欲笑隨情酒逐身，此身雖老未辜春。',32,'御定全唐詩/json/462.json','["欲笑隨情酒逐身，此身雖老未辜春。", "春來點檢閒遊數，猶自多於年少人。"]'),
('yuding-34','招韜光禪師','白居易','唐','御定全唐诗','yuding','','[]','白屋炊香飯，葷膻不入家。濾泉澄葛粉，洗手摘藤花。',48,'御定全唐詩/json/462.json','["白屋炊香飯，葷膻不入家。濾泉澄葛粉，洗手摘藤花。", "青芥除黃葉，紅薑帶紫芽。命師相伴食，齋罷一甌茶。"]'),
('yuding-35','和柳公權登齊雲樓','白居易','唐','御定全唐诗','yuding','','[]','樓外春晴百鳥鳴，樓中春酒美人傾。路旁花日添衣色，',40,'御定全唐詩/json/462.json','["樓外春晴百鳥鳴，樓中春酒美人傾。路旁花日添衣色，", "佳時莫起興亡恨，遊樂今逢四海清。"]'),
('yuding-36','毛公壇','白居易','唐','御定全唐诗','yuding','','[]','毛公壇上片雲閑，得道何年去不還。',32,'御定全唐詩/json/462.json','["毛公壇上片雲閑，得道何年去不還。", "千載鶴翎歸碧落，五湖空鎮萬重山。"]'),
('yuding-37','靈岩寺','白居易','唐','御定全唐诗','yuding','','[]','館娃宮畔千年寺，水闊雲多客到稀。',32,'御定全唐詩/json/462.json','["館娃宮畔千年寺，水闊雲多客到稀。", "聞說春來更惆悵，百花深處一僧歸。"]'),
('yuding-38','白雲泉','白居易','唐','御定全唐诗','yuding','','[]','天平山上白雲泉，雲自無心水自閑。',32,'御定全唐詩/json/462.json','["天平山上白雲泉，雲自無心水自閑。", "何必奔沖山下去，更添波浪向人間。"]'),
('yuding-39','寄韜光禪師','白居易','唐','御定全唐诗','yuding','','[]','一山門作兩山門，兩寺原從一寺分。東澗水流西澗水，',40,'御定全唐詩/json/462.json','["一山門作兩山門，兩寺原從一寺分。東澗水流西澗水，", "遙想吾師行道處，天香桂子落紛紛。"]'),
('yuding-40','和夢得夏至憶蘇州呈盧賓客','白居易','唐','御定全唐诗','yuding','','[]','憶在蘇州日，常諳夏至筵。粽香筒竹嫩，炙脆子鵝鮮。',96,'御定全唐詩/json/462.json','["憶在蘇州日，常諳夏至筵。粽香筒竹嫩，炙脆子鵝鮮。", "水國多台榭，吳風尚管弦。每家皆有酒，無處不過船。", "交印君相次，褰帷我在前。此鄉俱老矣，東望共依然。", "洛下麥秋月，江南梅雨天。齊雲樓上事，已上十三年。"]'),
('yuding-41','曲江','白居易','唐','御定全唐诗','yuding','','[]','細草岸西東，酒旗搖水風。樓臺在花杪，鷗鷺下煙中。',48,'御定全唐詩/json/462.json','["細草岸西東，酒旗搖水風。樓臺在花杪，鷗鷺下煙中。", "翠幄晴相接，芳洲夜暫空。何人賞秋景，興與此時同。"]'),
('yuding-42','歲夜詠懷，兼寄思黯','白居易','唐','御定全唐诗','yuding','','[]','遍數故交親，何人得六旬。今年已入手，餘事豈關身。',48,'御定全唐詩/json/462.json','["遍數故交親，何人得六旬。今年已入手，餘事豈關身。", "老自無多興，春應不揀人。陶窗與弘閣，風景一時新。"]'),
('yuding-43','寒食日過棗團店','白居易','唐','御定全唐诗','yuding','','[]','寒食棗團店，春低楊柳枝。酒香留客住，鶯語和人詩。',48,'御定全唐詩/json/462.json','["寒食棗團店，春低楊柳枝。酒香留客住，鶯語和人詩。", "困立攀花久，慵行上馬遲。若為將此意，前字與僧期。"]'),
('yuding-44','宿張雲舉院','白居易','唐','御定全唐诗','yuding','','[]','不食胡麻飯，杯中自得仙。隔房招好客，可室致芳筵。',72,'御定全唐詩/json/462.json','["不食胡麻飯，杯中自得仙。隔房招好客，可室致芳筵。", "美醞香醪嫩，時新異果鮮。夜深唯畏曉，坐穩不思眠。", "棋罷嫌無敵，詩成愧在前。明朝題壁上，誰得眾人傳。"]'),
('yuding-45','惜花','白居易','唐','御定全唐诗','yuding','','[]','可憐夭豔正當時，剛被狂風一夜吹。',32,'御定全唐詩/json/462.json','["可憐夭豔正當時，剛被狂風一夜吹。", "今日流鶯來舊處，百般言語泥空枝。"]'),
('yuding-46','七夕','白居易','唐','御定全唐诗','yuding','','[]','煙霄微月澹長空，銀漢秋期萬古同。',32,'御定全唐詩/json/462.json','["煙霄微月澹長空，銀漢秋期萬古同。", "幾許歡情與離恨，年年並在此宵中。"]'),
('yuding-47','宿誠禪師山房題贈','白居易','唐','御定全唐诗','yuding','','[]','不出孤峰上，人間四十秋。視身如傳舍，閱世任東流。',48,'御定全唐詩/json/462.json','["不出孤峰上，人間四十秋。視身如傳舍，閱世任東流。", "法為因緣立，心從次第修。中宵問真偈，有住是吾憂。"]'),
('yuding-48','新池','白居易','唐','御定全唐诗','yuding','','[]','數日自穿鑿，引泉來近陂。尋渠通咽處，繞岸待清時。',48,'御定全唐詩/json/462.json','["數日自穿鑿，引泉來近陂。尋渠通咽處，繞岸待清時。", "深好求魚養，閑堪與鶴期。幽聲聽難盡，入夜睡常遲。"]'),
('yuding-49','南池','白居易','唐','御定全唐诗','yuding','','[]','蕭條微雨絕，荒岸抱清源。入舫山侵塞，分泉道接村。',48,'御定全唐詩/json/462.json','["蕭條微雨絕，荒岸抱清源。入舫山侵塞，分泉道接村。", "秋聲依樹色，月影在蒲根。淹泊方難遂，他宵關夢魂。"]'),
('yuding-50','宿池上','白居易','唐','御定全唐诗','yuding','','[]','泉來從絕壑，亭敞在中流。竹密無空岸，松長可絆舟。',48,'御定全唐詩/json/462.json','["泉來從絕壑，亭敞在中流。竹密無空岸，松長可絆舟。", "蟪蛄潭上夜，河漢島前秋。異夕期新漲，攜琴卻此遊。"]'),
('yuding-51','翻經台','白居易','唐','御定全唐诗','yuding','','[]','一會靈山猶未散，重翻貝葉有來由。',32,'御定全唐詩/json/462.json','["一會靈山猶未散，重翻貝葉有來由。", "是名精進才開眼，岩石無端亦點頭。"]'),
('yuding-52','《寄題上強山精舍寺','白居易','唐','御定全唐诗','yuding','','[]','慣游山水住南州，行盡天臺及虎丘。',32,'御定全唐詩/json/462.json','["慣游山水住南州，行盡天臺及虎丘。", "惟有上強精舍寺，最堪游處未曾遊。"]'),
('yuding-53','一字至七字詩','白居易','唐','御定全唐诗','yuding','','[]','詩。綺美，瑰奇。明月夜，落花時。能助歡笑，亦傷別離。',68,'御定全唐詩/json/462.json','["詩。綺美，瑰奇。明月夜，落花時。能助歡笑，亦傷別離。", "調清金石怨，吟苦鬼神悲。天下只應我愛，世間唯有君知。", "自從都尉別蘇句，便到司空送白辭。"]'),
('yuding-54','九老圖詩','白居易','唐','御定全唐诗','yuding','','[]','雪作鬚眉雲作衣，遼東華表鶴雙歸。',32,'御定全唐詩/json/462.json','["雪作鬚眉雲作衣，遼東華表鶴雙歸。", "當時一鶴猶稀有，何況今逢兩令威。"]'),
('yuding-55','和裴相公傍水閑行絕句','白居易','唐','御定全唐诗','yuding','','[]','行尋春水坐看山，早出中書晚未還。',32,'御定全唐詩/json/462.json','["行尋春水坐看山，早出中書晚未還。", "為報野僧岩客道，偷閒氣味勝長閑。"]'),
('yuding-0','七老會詩','胡杲','唐','御定全唐诗','yuding','','[]','閒居同會在三春，大抵愚年最出群。霜鬢不嫌杯酒興，',48,'御定全唐詩/json/463.json','["閒居同會在三春，大抵愚年最出群。霜鬢不嫌杯酒興，", "鑿落滿斟判酩酊，香囊高掛任氤氳。搜神得句題紅葉，"]'),
('yuding-1','七老會詩','吉皎','唐','御定全唐诗','yuding','','[]','休官罷任已閒居，林苑園亭興有餘。對酒最宜花藻發，',48,'御定全唐詩/json/463.json','["休官罷任已閒居，林苑園亭興有餘。對酒最宜花藻發，", "寧用管弦來合雜，自親松竹且清虛。飛觥酒到須先酌，"]'),
('yuding-2','七老會詩','劉真','唐','御定全唐诗','yuding','','[]','垂絲今日幸同筵，朱紫居身是大年。賞景尚知心未退，',48,'御定全唐詩/json/463.json','["垂絲今日幸同筵，朱紫居身是大年。賞景尚知心未退，", "山茗煮時秋霧碧，玉杯斟處彩霞鮮。臨階花笑如歌妓，"]'),
('yuding-3','七老會詩','鄭據','唐','御定全唐诗','yuding','','[]','東洛幽閒日暮春，邀歡多是白頭賓。官班朱紫多相似，',48,'御定全唐詩/json/463.json','["東洛幽閒日暮春，邀歡多是白頭賓。官班朱紫多相似，", "更無外事來心肺，空有清虛入思神。醉舞兩回迎勸酒，"]'),
('yuding-4','七老會詩','盧真','唐','御定全唐诗','yuding','','[]','三春已盡洛陽宮，天氣初晴景象中。千朵嫩桃迎曉日，',48,'御定全唐詩/json/463.json','["三春已盡洛陽宮，天氣初晴景象中。千朵嫩桃迎曉日，", "對酒歌聲猶覺妙，玩花詩思豈能窮。先時共作三朝貴，"]'),
('yuding-5','七老會詩','張渾','唐','御定全唐诗','yuding','','[]','幽亭春盡共為歡，印綬居身是大官。遁跡豈勞登遠岫，',48,'御定全唐詩/json/463.json','["幽亭春盡共為歡，印綬居身是大官。遁跡豈勞登遠岫，", "每況襟懷同宴會，共將心事比波瀾。風吹野柳垂羅帶，"]'),
('yuding-6','一字至七字詩：竹','韋式','唐','御定全唐诗','yuding','','[]','竹。臨池，似玉。裛露靜，和煙綠。抱節寧改，貞心自束。',68,'御定全唐詩/json/463.json','["竹。臨池，似玉。裛露靜，和煙綠。抱節寧改，貞心自束。", "渭曲偏種多，王家看不足。仙杖正驚龍化，美實當隨鳳熟。", "唯愁吹作別離聲，回首駕驂舞陣速。"]'),
('yuding-7','奉和白太守揀橘','張彤','唐','御定全唐诗','yuding','','[]','淩霜遠涉太湖深，雙卷朱旗望橘林。樹樹籠煙疑帶火，',40,'御定全唐詩/json/463.json','["淩霜遠涉太湖深，雙卷朱旗望橘林。樹樹籠煙疑帶火，", "揀選封題皆盡力，無人不感近臣心。"]'),
('yuding-8','和白太守揀貢橘','周元範','唐','御定全唐诗','yuding','','[]','離離朱實綠叢中，似火燒山處處紅。影下寒林沈綠水，',40,'御定全唐詩/json/463.json','["離離朱實綠叢中，似火燒山處處紅。影下寒林沈綠水，", "看取明朝船發後，餘香猶尚逐仁風。"]'),
('yuding-9','句','周元範','唐','御定全唐诗','yuding','','[]','誰雲蒿上煙，隨雲依碧落。',48,'御定全唐詩/json/463.json','["誰雲蒿上煙，隨雲依碧落。", "莫怪西陵風景別，鏡湖花草為先春。（賀朱慶餘及第。", "已上並見張為《主客圖》）"]'),
('yuding-10','書巫山神女祠','繁知一','唐','御定全唐诗','yuding','','[]','忠州刺史今才子，行到巫山必有詩。',32,'御定全唐詩/json/463.json','["忠州刺史今才子，行到巫山必有詩。", "為報高唐神女道，速排雲雨候清詞。"]'),
('yuding-11','唐昌觀玉蕊花折有仙人游悵然成二絕','嚴休複','唐','御定全唐诗','yuding','','[]','終日齋心禱玉宸，魂銷目斷未逢真。',64,'御定全唐詩/json/463.json','["終日齋心禱玉宸，魂銷目斷未逢真。", "不如滿樹瓊瑤蕊，笑對藏花洞裏人。", "羽車潛下玉龜山，塵世何由睹蕣顏。", "唯有多情枝上雪，好風吹綴綠雲鬟。"]'),
('yuding-12','江亭寓目','盧拱','唐','御定全唐诗','yuding','','[]','江郭帶林巒，津亭倚檻看。水風蒲葉戰，沙雨鷺鷥寒。',48,'御定全唐詩/json/463.json','["江郭帶林巒，津亭倚檻看。水風蒲葉戰，沙雨鷺鷥寒。", "晚木初凋柳，秋叢欲敗蘭。哀猿自相叫，鄉淚好無端。"]'),
('yuding-13','中元日觀法事','盧拱','唐','御定全唐诗','yuding','','[]','西孟逢秋序，三元得氣中。雲迎碧落步，章奏玉皇宮。',72,'御定全唐詩/json/463.json','["西孟逢秋序，三元得氣中。雲迎碧落步，章奏玉皇宮。", "壇滴槐花露，香飄柏子風。羽衣淩縹緲，瑤轂轉虛空。", "久慕餐霞客，常悲習蓼蟲。青囊如可授，從此訪鴻蒙。"]'),
('yuding-14','句','盧拱','唐','御定全唐诗','yuding','','[]','地甃如拳石，溪橫似葉舟。',12,'御定全唐詩/json/463.json','["地甃如拳石，溪橫似葉舟。"]'),
('yuding-15','蘇州元日郡齋感懷，寄越州元相公、杭州白舍人','李諒','唐','御定全唐诗','yuding','','[]','稱慶還鄉郡吏歸，端憂明發儼朝衣。首開三百六旬日，',72,'御定全唐詩/json/463.json','["稱慶還鄉郡吏歸，端憂明發儼朝衣。首開三百六旬日，", "舉族共資隨月俸，一身惟憶故山薇。舊交邂逅封疆近，", "絲綸暫厭分符竹，舟楫初登擁羽旗。未知今日情何似，"]'),
('yuding-16','月生','劉猛','唐','御定全唐诗','yuding','','[]','月生十五前，日望光彩圓。月滿十五後，日畏光彩瘦。',60,'御定全唐詩/json/463.json','["月生十五前，日望光彩圓。月滿十五後，日畏光彩瘦。", "不見夜花色，一尊成暗酒。匣中苔背銅，光短不照空。", "不惜補明月，慚無此良工。"]'),
('yuding-17','苦雨','劉猛','唐','御定全唐诗','yuding','','[]','自念數年間，兩手中藏鉤。於心且無恨，他日為我羞。',48,'御定全唐詩/json/463.json','["自念數年間，兩手中藏鉤。於心且無恨，他日為我羞。", "古老傳童歌，連淫亦兵象。夜夢戈甲鳴，苦不願年長。"]'),
('yuding-18','曉','劉猛','唐','御定全唐诗','yuding','','[]','朝梳一把白，夜淚千滴雨。可恥垂拱時，老作在家女。',24,'御定全唐詩/json/463.json','["朝梳一把白，夜淚千滴雨。可恥垂拱時，老作在家女。"]'),
('yuding-19','獻盧尚書','萬彤雲','唐','御定全唐诗','yuding','','[]','荷衣拭淚幾回穿，欲謁朱門抵上天。',32,'御定全唐詩/json/463.json','["荷衣拭淚幾回穿，欲謁朱門抵上天。", "不是尚書輕下客，山家無物與王權。"]'),
('yuding-20','和白尚書賦永豐柳','盧貞','唐','御定全唐诗','yuding','','[]','一樹依依在永豐，兩枝飛去杳無蹤。',32,'御定全唐詩/json/463.json','["一樹依依在永豐，兩枝飛去杳無蹤。", "玉皇曾采人間曲，應逐歌聲入九重。"]'),
('yuding-21','和劉夢得歲夜懷友','盧貞','唐','御定全唐诗','yuding','','[]','文翰走天下，琴尊臥洛陽。貞元朝士盡，新歲一悲涼。',48,'御定全唐詩/json/463.json','["文翰走天下，琴尊臥洛陽。貞元朝士盡，新歲一悲涼。", "名早緣才大，官遲為壽長。時來知病已，莫歎步趨妨。"]'),
('yuding-0','和李校書雨中自秘省見訪知早入朝便入集賢不遇詩','王起','唐','御定全唐诗','yuding','','[]','台庭才子來款扉，典校初從天祿歸。已慚陋巷回玉趾，',96,'御定全唐詩/json/464.json','["台庭才子來款扉，典校初從天祿歸。已慚陋巷回玉趾，", "憶昨謬官在烏府，喜君對門討魚魯。直廬相望夜每闌，", "校文複忝丞相屬，博物更與張侯居。新冠峨峨不變鐵，", "憶見青天霞未卷，吟玩瑤華不知晚。自憐豈是風引舟，"]'),
('yuding-1','貢舉人謁先師聞雅樂','王起','唐','御定全唐诗','yuding','','[]','藹藹觀光士，來同鵠鷺群。鞠躬遺像在，稽首雅歌聞。',72,'御定全唐詩/json/464.json','["藹藹觀光士，來同鵠鷺群。鞠躬遺像在，稽首雅歌聞。", "度曲飄清漢，餘音遏曉雲。兩楹淒已合，九仞杳難分。", "斷續同清吹，洪纖入紫氛。長言聽已罷，千載仰斯文。"]'),
('yuding-2','濁水求珠','王起','唐','御定全唐诗','yuding','','[]','行潦沈明月，光輝也不浮。識珍能洞鑒，精寶此來求。',72,'御定全唐詩/json/464.json','["行潦沈明月，光輝也不浮。識珍能洞鑒，精寶此來求。", "幾被泥沙雜，常隨混濁流。潤川終自媚，照乘且何由。", "的皪終難掩，晶熒願見收。蛇行無脛至，飲德已聞酬。"]'),
('yuding-3','和周侍郎見寄','王起','唐','御定全唐诗','yuding','','[]','貢院離來二十霜，誰知更忝主文場。楊葉縱能穿舊的，',40,'御定全唐詩/json/464.json','["貢院離來二十霜，誰知更忝主文場。楊葉縱能穿舊的，", "莫道相知不相見，蓮峰之下欲征黃。"]'),
('yuding-4','贈毛仙翁','王起','唐','御定全唐诗','yuding','','[]','冰霜肌骨稱童年，羽駕何由到俗間。丹灶化金留秘訣，',40,'御定全唐詩/json/464.json','["冰霜肌骨稱童年，羽駕何由到俗間。丹灶化金留秘訣，", "若許隨師去塵網，願陪鸞鶴向三山。"]'),
('yuding-5','賦花','王起','唐','御定全唐诗','yuding','','[]','花。點綴，分葩。露初裛，月未斜。一枝曲水，千樹山家。',68,'御定全唐詩/json/464.json','["花。點綴，分葩。露初裛，月未斜。一枝曲水，千樹山家。", "戲蝶未成夢，嬌鶯語更誇。既見東園成徑，何殊西子同車。", "漸覺風飄輕似雪，能令醉者亂如麻。"]'),
('yuding-6','賦得濁水求珠','王損之','唐','御定全唐诗','yuding','','[]','積水非澄澈，明珠不易求。依稀沈極浦，想像在中流。',72,'御定全唐詩/json/464.json','["積水非澄澈，明珠不易求。依稀沈極浦，想像在中流。", "瞪目思清淺，褰裳恨暗投。徒看川色媚，空愛夜光浮。", "月入疑龍吐，星歸似蚌遊。終希識珍者，采掇冀冥搜。"]'),
('yuding-7','賦得行不由徑','王炎','唐','御定全唐诗','yuding','','[]','邪徑趨時捷，端心惡此名。長衢貴高步，大路自規行。',72,'御定全唐詩/json/464.json','["邪徑趨時捷，端心惡此名。長衢貴高步，大路自規行。", "且慮縈紆僻，將求坦蕩情。詎同流俗好，方保立身貞。", "遠跡如違險，修仁在履平。始知夫子道，從此得堅誠。"]'),
('yuding-8','賦得行不由徑','封孟紳','唐','御定全唐诗','yuding','','[]','欲速意何成，康莊欲砥平。天衢皆利往，吾道泰方行。',72,'御定全唐詩/json/464.json','["欲速意何成，康莊欲砥平。天衢皆利往，吾道泰方行。", "不復由萊徑，無由見蔣生。三條遵廣達，九軌尚安貞。", "紫陌悠悠去，芳塵步步清。澹台千載後，公正有遺名。"]'),
('yuding-9','題馬侍中燧木香亭','邵楚萇','唐','御定全唐诗','yuding','','[]','春日遲遲木香閣，窈窕佳人褰繡幕。淋漓玉露滴紫蕤，',40,'御定全唐詩/json/464.json','["春日遲遲木香閣，窈窕佳人褰繡幕。淋漓玉露滴紫蕤，", "樹影參差斜入簷，風動玲瓏水晶箔。"]'),
('yuding-10','賦得玉水記方流','鄭俞','唐','御定全唐诗','yuding','','[]','積水綦文動，因知玉產幽。如天涵素色，侔地引方流。',72,'御定全唐詩/json/464.json','["積水綦文動，因知玉產幽。如天涵素色，侔地引方流。", "潛潤滋雲起，熒華射浪浮。魚龍泉不夜，草木岸無秋。", "璧沼寧堪比，瑤池詎可儔。若非懸坐測，誰複寄冥搜。"]'),
('yuding-11','賦得玉水記方流','吳丹','唐','御定全唐诗','yuding','','[]','玉泉何處記，四折水紋浮。潤下甯逾矩，居方在上流。',72,'御定全唐詩/json/464.json','["玉泉何處記，四折水紋浮。潤下甯逾矩，居方在上流。", "映空虛漾漾，涵白淨悠悠。影碎疑沖鬥，光清耐觸舟。", "珪璋分辨狀，沙礫共懷柔。願赴朝宗日，縈回入禦溝。"]'),
('yuding-12','賦得玉水記方流','王鑒','唐','御定全唐诗','yuding','','[]','玉潤在中洲，光臨碕岸幽。氤氳冥瑞影，演漾度方流。',72,'御定全唐詩/json/464.json','["玉潤在中洲，光臨碕岸幽。氤氳冥瑞影，演漾度方流。", "乍似輕漣合，還疑駭浪收。夤緣知有異，洞徹信無儔。", "比德稱殊賞，含輝處至柔。沉淪如見念，況乃屬時休。"]'),
('yuding-13','賦得玉水記方流','陳昌言','唐','御定全唐诗','yuding','','[]','明媚如懷玉，奇姿自托幽。白虹深不見，綠水折空流。',72,'御定全唐詩/json/464.json','["明媚如懷玉，奇姿自托幽。白虹深不見，綠水折空流。", "方玨清沙遍，縱橫氣色浮。類圭才有角，寫月讓成鉤。", "久處沉潛貴，希當特達收。滔滔在何許，揭厲願從遊。"]'),
('yuding-14','白日麗江皋','陳昌言','唐','御定全唐诗','yuding','','[]','遲景臨遙水，晴空似不高。清明開曉鏡，昭晰辨秋毫。',72,'御定全唐詩/json/464.json','["遲景臨遙水，晴空似不高。清明開曉鏡，昭晰辨秋毫。", "鬱鬱長堤土，離離淺渚毛。煙銷占一候，風靜擁千艘。", "獨媚青春柳，宜看白鷺濤。何年謝公賞，遺韻在江皋。"]'),
('yuding-15','賦得玉水記方流','杜元穎','唐','御定全唐诗','yuding','','[]','重泉生美玉，積水異常流。始玩清堪賞，因知寶可求。',72,'御定全唐詩/json/464.json','["重泉生美玉，積水異常流。始玩清堪賞，因知寶可求。", "鬥回虹氣見，磬折紫光浮。中矩皆明德，同方葉至柔。", "月華偏共映，風暖佇將遊。遇鑒終無暗，逢時願見收。"]'),
('yuding-16','太常觀閱驃國新樂','胡直鈞','唐','御定全唐诗','yuding','','[]','異音來驃國，初被奉常人。才可宮商辨，殊驚節奏新。',72,'御定全唐詩/json/464.json','["異音來驃國，初被奉常人。才可宮商辨，殊驚節奏新。", "轉規回繡面，曲折度文身。舒散隨鸞吹，喧呼雜鳥春。", "襟衽懷舊識，絲竹變恒陳。何事留中夏，長令表化淳。"]'),
('yuding-17','行不由徑','俞簡','唐','御定全唐诗','yuding','','[]','古人心有尚，乃是孔門生。為計安貧樂，當從大道行。',72,'御定全唐詩/json/464.json','["古人心有尚，乃是孔門生。為計安貧樂，當從大道行。", "詎應流遠跡，方欲料前程。捷徑雖雲易，長衢豈不平。", "後來無枉路，先達擅前名。一示遵途意，微衷益自精。"]'),
('yuding-18','丁巳歲八月祭武侯祠堂，因題臨淮公舊碑','楊嗣複','唐','御定全唐诗','yuding','','[]','齋莊修祀事，旌旆出效闉。薙草軒墀狹，塗牆赭堊新。',72,'御定全唐詩/json/464.json','["齋莊修祀事，旌旆出效闉。薙草軒墀狹，塗牆赭堊新。", "謀猷期作聖，風俗奉為神。酹酒成坳澤，持兵列偶人。", "非才膺寵任，異代揖芳塵。況是平津客，碑前淚滿巾。"]'),
('yuding-19','儀鳳','楊嗣複','唐','御定全唐诗','yuding','','[]','八方該帝澤，威鳳忽來賓。向日朱光動，迎風翠羽新。',72,'御定全唐詩/json/464.json','["八方該帝澤，威鳳忽來賓。向日朱光動，迎風翠羽新。", "低昂多異趣，飲啄迥無鄰。郊藪今翔集，河圖意等倫。", "聞韶知鼓舞，偶聖願逡巡。比屋初同俗，垂恩擊壤人。"]'),
('yuding-20','贈毛仙翁','楊嗣複','唐','御定全唐诗','yuding','','[]','天上玉郎騎白鶴，肘後金壺盛妙藥。暫游下界傲五侯，',96,'御定全唐詩/json/464.json','["天上玉郎騎白鶴，肘後金壺盛妙藥。暫游下界傲五侯，", "王母親縫紫錦囊，令向懷中藏秘訣。令威子晉皆儔侶，", "藥成自固黃金骨，天地齊兮身不沒。日月宮中便是家，", "滿朝將相門弟子，隨師盡願拋塵滓。九轉琅玕必有餘，"]'),
('yuding-21','題李處士山居','楊嗣複','唐','御定全唐诗','yuding','','[]','臥龍決起為時君，寂寞匡廬惟白雲。',32,'御定全唐詩/json/464.json','["臥龍決起為時君，寂寞匡廬惟白雲。", "今日仲容修故業，草堂焉敢更移文。"]'),
('yuding-22','謝寄新茶','楊嗣複','唐','御定全唐诗','yuding','','[]','石上生芽二月中，蒙山顧渚莫爭雄。',32,'御定全唐詩/json/464.json','["石上生芽二月中，蒙山顧渚莫爭雄。", "封題寄與楊司馬，應為前銜是相公。"]'),
('yuding-0','盧十五竹亭送侄偁歸山','楊衡','唐','御定全唐诗','yuding','','[]','落葉寒擁壁，清霜夜沾石。正是憶山時，複送歸山客。',36,'御定全唐詩/json/465.json','["落葉寒擁壁，清霜夜沾石。正是憶山時，複送歸山客。", "殷勤一尊酒，曉月當窗白。"]'),
('yuding-1','旅次江亭','楊衡','唐','御定全唐诗','yuding','','[]','扣舷不能寐，皓露清衣襟。彌傷孤舟夜，遠結萬里心。',48,'御定全唐詩/json/465.json','["扣舷不能寐，皓露清衣襟。彌傷孤舟夜，遠結萬里心。", "幽興惜瑤草，素懷寄鳴琴。三奏月初上，寂寥寒江深。"]'),
('yuding-2','賦得夜雨滴空階送魏秀才','楊衡','唐','御定全唐诗','yuding','','[]','委簷方滴滴，沾紅複灑綠。醉聽乍朦朧，愁聞多斷續。',48,'御定全唐詩/json/465.json','["委簷方滴滴，沾紅複灑綠。醉聽乍朦朧，愁聞多斷續。", "始兼泉向細，稍雜更聲促。百慮自縈心，況有人如玉。"]'),
('yuding-3','征人','楊衡','唐','御定全唐诗','yuding','','[]','西風屢鳴雁，東郊未升日。繁煙幕幕昏，暗騎蕭蕭出。',48,'御定全唐詩/json/465.json','["西風屢鳴雁，東郊未升日。繁煙幕幕昏，暗騎蕭蕭出。", "望雲愁玉塞，眠月想蕙質。借問露沾衣，何如香滿室。"]'),
('yuding-4','游陸先生故岩居','楊衡','唐','御定全唐诗','yuding','','[]','獨壑臨萬嶂，蒼苔絕行跡。仰窺猿掛樹，俯對鶴巢石。',72,'御定全唐詩/json/465.json','["獨壑臨萬嶂，蒼苔絕行跡。仰窺猿掛樹，俯對鶴巢石。", "上有一岩屋，相傳靈人宅。深林無陽暉，幽水轉鮮碧。", "拾薪遇遺鼎，探穴得古籍。結念候雲興，燒香坐終夕。"]'),
('yuding-5','題玄和師仙藥室','楊衡','唐','御定全唐诗','yuding','','[]','山邊蕭寂室，石掩浮雲扃。繞室微有路，松煙深冥冥。',72,'御定全唐詩/json/465.json','["山邊蕭寂室，石掩浮雲扃。繞室微有路，松煙深冥冥。", "入松汲寒水，對鶴問仙經。石幾香未盡，水花風欲零。", "何年去華表，幾度窮蒼冥。卻顧宦遊子，眇如霜中螢。"]'),
('yuding-6','宿陸氏齋賦得殘燈詩','楊衡','唐','御定全唐诗','yuding','','[]','殷勤照永夜，屬思未成眠。餘輝含薄霧，落燼迸空筵。',36,'御定全唐詩/json/465.json','["殷勤照永夜，屬思未成眠。餘輝含薄霧，落燼迸空筵。", "誰比秦樓曉，緘愁別幌前。"]'),
('yuding-7','夷陵郡內敘別','楊衡','唐','御定全唐诗','yuding','','[]','禮娶嗣明德，同牢夙所欽。況蒙生死契，豈顧蓬蒿心。',168,'御定全唐詩/json/465.json','["禮娶嗣明德，同牢夙所欽。況蒙生死契，豈顧蓬蒿心。", "雁幣任野薄，恩愛緣義深。同聲若鼓瑟，合韻似鳴琴。", "將迓空未立，就贅意難任。皎月托言誓，滄波信浮沉。", "荊台理晨轍，巫渚疑宵襟。憫憫百慮起，回回萬恨深。", "候更促徒侶，先曉徹夜禽。燈彩凝寒風，蟬思噪密林。", "留念同心帶，贈遠芙蓉簪。撫懷極投漆，感物重黃金。", "分鸞豈遐阻，別劍念相尋。倘甘蓬戶賤，願俟故山岑。"]'),
('yuding-8','將之荊州南與張伯剛馬惣鐘陵夜別','楊衡','唐','御定全唐诗','yuding','','[]','荊台別路長，密緒分離狀。莫訴杯來促，更籌屢已倡。',48,'御定全唐詩/json/465.json','["荊台別路長，密緒分離狀。莫訴杯來促，更籌屢已倡。", "燭花侵霧暗，瑟調寒風亮。誰念曉帆開，默睇參差浪。"]'),
('yuding-9','經端溪峽中','楊衡','唐','御定全唐诗','yuding','','[]','陰岸東流水，上有微風生。素羽漾翠澗，碧苔敷丹英。',96,'御定全唐詩/json/465.json','["陰岸東流水，上有微風生。素羽漾翠澗，碧苔敷丹英。", "重林宿雨晦，遠岫孤霞明。飛猱相攀牽，白雲亂縱橫。", "有客溯輕楫，閱勝匪羈程。逍遙一息間，糞土五侯榮。", "搴茗庶蠲熱，漱泉聊析酲。寄言絲竹者，詎識松風聲。"]'),
('yuding-10','南海苦雨，寄贈王四侍禦','楊衡','唐','御定全唐诗','yuding','','[]','炎風雜海氣，暑雨每成霖。塗泥親杖屨，苔蘚漬衣襟。',72,'御定全唐詩/json/465.json','["炎風雜海氣，暑雨每成霖。塗泥親杖屨，苔蘚漬衣襟。", "念近劇懷遠，涉淺定知深。暗溝夜滴滴，荒庭晝霪霪。", "折簡展離曠，理徑俟招尋。處陰誠多慘，況乃觸隅禽。"]'),
('yuding-11','秋夜閒居，即事寄廬山鄭員外、蜀郡符處士','楊衡','唐','御定全唐诗','yuding','','[]','憂思繁未整，良辰會無由。引領遲佳音，星紀屢以周。',96,'御定全唐詩/json/465.json','["憂思繁未整，良辰會無由。引領遲佳音，星紀屢以周。", "蓬閬絕華耀，況乃處窮愁。墜葉寒擁砌，燈火夜悠悠。", "開琴弄清弦，窺月俯澄流。冉冉鴻雁度，蕭蕭帷箔秋。", "悵懷石門詠，緬慕碧雞遊。仿佛蒙顏色，崇蘭隱芳洲。"]'),
('yuding-12','寄贈田倉曹灣','楊衡','唐','御定全唐诗','yuding','','[]','芳蘭媚庭除，灼灼紅英舒。身為陋巷客，門有絳轅車。',72,'御定全唐詩/json/465.json','["芳蘭媚庭除，灼灼紅英舒。身為陋巷客，門有絳轅車。", "朝覽夷胡傳，暮習潁陽書。盻雲高羽翼，待賈蘊璠璵。", "纓弁雖雲阻，音塵豈複疏。若因風雨晦，應念寂寥居。"]'),
('yuding-13','詠春色','楊衡','唐','御定全唐诗','yuding','','[]','靄靄複濛濛，非霧滿晴空。密添宮柳翠，暗泄路桃紅。',72,'御定全唐詩/json/465.json','["靄靄複濛濛，非霧滿晴空。密添宮柳翠，暗泄路桃紅。", "縈絲光乍失，緣隙影才通。夕迷鴛枕上，朝漫綺弦中。", "促駟馳香陌，勞鶯轉豔叢。可憐腸斷望，並在洛城東。"]'),
('yuding-14','送春','楊衡','唐','御定全唐诗','yuding','','[]','三月三十日，春歸日複暮。惆悵問春風，明朝應不住。',120,'御定全唐詩/json/465.json','["三月三十日，春歸日複暮。惆悵問春風，明朝應不住。", "送春曲江上，眷眷東西顧。但見撲水花，紛紛不知數。", "人生似行客，兩足無停步。日日進前程，前程幾多路。", "兵刃與水火，盡可違之去。惟有老到來，人間無避處。", "感時良未已，獨倚池南樹。今日送春心，心如別親故。"]'),
('yuding-15','遊峽山寺','楊衡','唐','御定全唐诗','yuding','','[]','結構天南畔，勝絕固難儔。幸蒙時所漏，遂得恣閒遊。',144,'御定全唐詩/json/465.json','["結構天南畔，勝絕固難儔。幸蒙時所漏，遂得恣閒遊。", "路石蔭松蓋，檻藤維鶴舟。雨霽花木潤，風和景氣柔。", "寶殿敞丹扉，靈幡垂絳旒。照曜芙蓉壺，金人居上頭。", "翔禽拂危刹，落日避層樓。端溪彌漫駛，曲澗潺湲流。", "高居何重遝，登覽自夷猶。煙霞無隱態，岩洞詎遺幽。", "奔駟非久耀，馳波肯暫留。會從香火緣，滅跡此山丘。"]'),
('yuding-16','宿陟岵寺雲律師院','楊衡','唐','御定全唐诗','yuding','','[]','像宇鬱參差，寶林疏複密。中有彌天子，燃燈坐虛室。',96,'御定全唐詩/json/465.json','["像宇鬱參差，寶林疏複密。中有彌天子，燃燈坐虛室。", "心證紅蓮喻，跡羈青眼律。玉爐揚翠煙，金經開縹帙。", "肆陳堅固學，破我夢幻質。碧水灑塵纓，涼扇當夏日。", "宿禽詎相保，迸火煙欲失。願回戚促勞，趨隅事休逸。"]'),
('yuding-17','秋夜桂州宴送鄭十九侍禦','楊衡','唐','御定全唐诗','yuding','','[]','秋至觸物愁，況當離別筵。短歌銷夜燭，繁緒遍高弦。',72,'御定全唐詩/json/465.json','["秋至觸物愁，況當離別筵。短歌銷夜燭，繁緒遍高弦。", "桂水舟始泛，蘭堂榻詎懸。一杯勾離阻，三載奉周旋。", "鴉噪更漏颯，露濡風景鮮。斯須不共此，且為更留連。"]'),
('yuding-18','九日陪樊尚書龍山宴集','楊衡','唐','御定全唐诗','yuding','','[]','孟嘉從宴地，千乘複登臨。緣危陟高步，憑曠寫幽襟。',72,'御定全唐詩/json/465.json','["孟嘉從宴地，千乘複登臨。緣危陟高步，憑曠寫幽襟。", "黃花玩初馥，翠物喜盈斟。雲雜組繡色，樂和山水音。", "旆搖秋吹急，筵卷夕光沉。都人瞻騎火，猶知隔寺深。"]'),
('yuding-19','江陵送客歸河北','楊衡','唐','御定全唐诗','yuding','','[]','遠客歸故里，臨路結裴回。山長水複闊，無因重此來。',36,'御定全唐詩/json/465.json','["遠客歸故里，臨路結裴回。山長水複闊，無因重此來。", "聊將歌一曲，送子手中杯。"]'),
('yuding-20','送鄭丞之羅浮中習業','楊衡','唐','御定全唐诗','yuding','','[]','百年泛飄忽，萬事系衰榮。高鴻脫矰繳，達士去簪纓。',96,'御定全唐詩/json/465.json','["百年泛飄忽，萬事系衰榮。高鴻脫矰繳，達士去簪纓。", "始從天目遊，複作羅浮行。雲臥石林密，月窺花洞明。", "全形在氣和，習默憑境清。夙秘絳囊訣，屢投金簡名。", "鐘管促離觴，煙霞隨去程。何當真府內，重得款平生。"]'),
('yuding-21','送王秀才往安南','楊衡','唐','御定全唐诗','yuding','','[]','君為蹈海客，客路誰諳悉。鯨度乍疑山，雞鳴先見日。',48,'御定全唐詩/json/465.json','["君為蹈海客，客路誰諳悉。鯨度乍疑山，雞鳴先見日。", "所嗟回棹晚，倍結離情密。無貪合浦珠，念守江陵橘。"]'),
('yuding-22','送公孫器自桂林歸蜀','楊衡','唐','御定全唐诗','yuding','','[]','桂林淺複碧，潺湲半露石。將乘觸物舟，暫駐飛空錫。',72,'御定全唐詩/json/465.json','["桂林淺複碧，潺湲半露石。將乘觸物舟，暫駐飛空錫。", "蜀鄉異青眼，蓬戶高朱戟。風度杳難尋，雲飄詎留跡。", "舊戶閑花草，馴鴿傍簷隙。揮手共忘懷，日墮千山夕。"]'),
('yuding-23','贈羅浮易煉師','楊衡','唐','御定全唐诗','yuding','','[]','海上多仙嶠，靈人信長生。榮衛冰雪姿，咽嚼日月精。',120,'御定全唐詩/json/465.json','["海上多仙嶠，靈人信長生。榮衛冰雪姿，咽嚼日月精。", "默書絳符遍，晦步鬥文成。翠發披肩長，金蓋淩風輕。", "曉籟息塵響，天雞叱幽聲。碧樹來戶陰，丹霞照窗明。", "焚香叩虛寂，稽首回太清。鸞鷺振羽儀，飛翻拂旆旌。", "左挹玉泉液，右搴雲芝英。念得參龍駕，攀天度赤城。"]'),
('yuding-24','登紫霄峰贈黃仙師','楊衡','唐','御定全唐诗','yuding','','[]','紫霄不可涉，靈峰信穹崇。下有瓊樹枝，上有翠發翁。',120,'御定全唐詩/json/465.json','["紫霄不可涉，靈峰信穹崇。下有瓊樹枝，上有翠發翁。", "雞鳴秋漢側，日出紅霞中。璨璨真仙子，執旄為侍童。", "焚香杳忘言，默念合太空。世華徒熠耀，虛室自朦朧。", "雲飛瓊瑤圃，龜息芝蘭叢。玉籙掩不開，天窗微微風。", "茲焉悟佳旨，塵境亦幽通。浩渺臨廣津，永用挹無窮。"]'),
('yuding-25','烏啼曲','楊衡','唐','御定全唐诗','yuding','','[]','可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，',24,'御定全唐詩/json/465.json','["可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，"]'),
('yuding-26','白紵歌二首','楊衡','唐','御定全唐诗','yuding','','[]','玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，',48,'御定全唐詩/json/465.json','["玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，", "躡珠履，步瓊筵，輕身起舞紅燭前。芳姿豔態妖且妍，"]'),
('yuding-27','長門怨','楊衡','唐','御定全唐诗','yuding','','[]','絲聲繁兮管聲急，珠簾不卷風吹入。萬遍凝愁枕上聽，',24,'御定全唐詩/json/465.json','["絲聲繁兮管聲急，珠簾不卷風吹入。萬遍凝愁枕上聽，"]'),
('yuding-28','寄徹公','楊衡','唐','御定全唐诗','yuding','','[]','北風吹霜霜月明，荷葉枯盡越水清。',32,'御定全唐詩/json/465.json','["北風吹霜霜月明，荷葉枯盡越水清。", "別來幾度龍宮宿，雪山童子應相逐。"]'),
('yuding-29','哭李象','楊衡','唐','御定全唐诗','yuding','','[]','白雞黃犬不將去，寂寞空餘葬時路。草死花開年複年，',24,'御定全唐詩/json/465.json','["白雞黃犬不將去，寂寞空餘葬時路。草死花開年複年，"]'),
('yuding-30','宿雲溪觀，賦得秋燈引送客','楊衡','唐','御定全唐诗','yuding','','[]','雲房寄宿秋夜客，一燈熒熒照虛壁。蟲聲呼客客未眠，',24,'御定全唐詩/json/465.json','["雲房寄宿秋夜客，一燈熒熒照虛壁。蟲聲呼客客未眠，"]'),
('yuding-31','採蓮曲','楊衡','唐','御定全唐诗','yuding','','[]','凝鮮霧渚夕，陽豔綠波風。魚遊乍散藻，露重稍欹紅。',48,'御定全唐詩/json/465.json','["凝鮮霧渚夕，陽豔綠波風。魚遊乍散藻，露重稍欹紅。", "楚客傷暮節，吳娃泣敗叢。促令芳本固，寧望雪霜中。"]'),
('yuding-32','他鄉七夕','楊衡','唐','御定全唐诗','yuding','','[]','漢渚常多別，山橋忽重遊。向雲迎翠輦，當月拜珠旒。',48,'御定全唐詩/json/465.json','["漢渚常多別，山橋忽重遊。向雲迎翠輦，當月拜珠旒。", "寢幌凝宵態，妝奩閉曉愁。不堪鳴杼日，空對白榆秋。"]'),
('yuding-33','春日偶題','楊衡','唐','御定全唐诗','yuding','','[]','何處春先到，橋東水北亭。凍花開未得，冷酒酌難醒。',48,'御定全唐詩/json/465.json','["何處春先到，橋東水北亭。凍花開未得，冷酒酌難醒。", "就日移輕榻，遮風展小屏。更無人勸飲，鶯語漸叮嚀。"]'),
('yuding-34','題山寺','楊衡','唐','御定全唐诗','yuding','','[]','千峰白露後，雲壁掛殘燈。曙色海邊日，經聲松下僧。',48,'御定全唐詩/json/465.json','["千峰白露後，雲壁掛殘燈。曙色海邊日，經聲松下僧。", "意閑門不閉，年去水空澄。稽首如何問，森羅盡一乘。"]'),
('yuding-35','廣州石門寺重送李尚赴朝，時兼宗正卿','楊衡','唐','御定全唐诗','yuding','','[]','象闕趨雲陛，龍宮憩石門。清鐃猶啟路，黃發重攀轅。',48,'御定全唐詩/json/465.json','["象闕趨雲陛，龍宮憩石門。清鐃猶啟路，黃發重攀轅。", "藻變朝天服，珠懷委地言。那令蓬蒿客，茲席未離尊。"]'),
('yuding-36','送孔周之南海謁王尚書','楊衡','唐','御定全唐诗','yuding','','[]','泛棹若流萍，桂寒山更青。望雲生碧落，看日下滄溟。',48,'御定全唐詩/json/465.json','["泛棹若流萍，桂寒山更青。望雲生碧落，看日下滄溟。", "潮盡收珠母，沙閑拾翠翎。自趨龍戟下，再為誦芳馨。"]'),
('yuding-37','冬夜舉公房送崔秀才歸南陽','楊衡','唐','御定全唐诗','yuding','','[]','聞君動征棹，犯夜故來尋。強置一尊酒，重款百年心。',48,'御定全唐詩/json/465.json','["聞君動征棹，犯夜故來尋。強置一尊酒，重款百年心。", "燈白霜氣冷，室虛松韻深。南陽三顧地，幸偶價千金。"]'),
('yuding-38','送陳房謁撫州周使君','楊衡','唐','御定全唐诗','yuding','','[]','匡山一畝宮，尚有桂蘭叢。鑿壁年雖異，穿楊志幸同。',48,'御定全唐詩/json/465.json','["匡山一畝宮，尚有桂蘭叢。鑿壁年雖異，穿楊志幸同。", "貌羸緣塞苦，道蹇為囊空。去謁臨川守，因憐鶴在籠。"]'),
('yuding-39','山齋獨宿贈晏上人','楊衡','唐','御定全唐诗','yuding','','[]','幢幢雲樹秋，黃葉下山頭。蟲響夜難度，夢閑神不遊。',48,'御定全唐詩/json/465.json','["幢幢雲樹秋，黃葉下山頭。蟲響夜難度，夢閑神不遊。", "窗燈寒幾盡，簾雨曉階愁。何以禪棲客，灰心在沃州。"]'),
('yuding-40','桂州與陳羽念別','楊衡','唐','御定全唐诗','yuding','','[]','慘戚損志抱，因君時解顏。重歎今夕會，複在幾夕間。',48,'御定全唐詩/json/465.json','["慘戚損志抱，因君時解顏。重歎今夕會，複在幾夕間。", "碧桂水連海，蒼梧雲滿山。茫茫從此去，何路入秦關。"]'),
('yuding-41','經趙處士居','楊衡','唐','御定全唐诗','yuding','','[]','雲居避世客，發白習儒經。有地水空綠，無人山自青。',48,'御定全唐詩/json/465.json','["雲居避世客，發白習儒經。有地水空綠，無人山自青。", "廢梁悲逝水，臥木思荒庭。向夕霏煙斂，徒看處士星。"]'),
('yuding-42','病中赴袁州次香館','楊衡','唐','御定全唐诗','yuding','','[]','病輿憩上館，繚繞向山隅。荒葛漫欹壁，幽禽啄朽株。',48,'御定全唐詩/json/465.json','["病輿憩上館，繚繞向山隅。荒葛漫欹壁，幽禽啄朽株。", "力微怯升降，意欲結踟躇。誰能挹香水，一為濯煩紆。"]'),
('yuding-43','送人流雷州','楊衡','唐','御定全唐诗','yuding','','[]','逐客指天涯，人間此路賒。地圖經大庾，水驛過長沙。',48,'御定全唐詩/json/465.json','["逐客指天涯，人間此路賒。地圖經大庾，水驛過長沙。", "臘月雷州雨，秋風桂嶺花。不知荒徼外，何處有人家。"]'),
('yuding-44','送徹公','楊衡','唐','御定全唐诗','yuding','','[]','白首年空度，幽居俗豈知。敗蕉依晚日，孤鶴立秋墀。',48,'御定全唐詩/json/465.json','["白首年空度，幽居俗豈知。敗蕉依晚日，孤鶴立秋墀。", "久客何由造，禪門不可窺。會同塵外友，齋沐奉威儀。"]'),
('yuding-45','贈廬山道士','楊衡','唐','御定全唐诗','yuding','','[]','寂寥高室古松寒，松下仙人字委鸞。頭垂白髮朝鳴磬，',40,'御定全唐詩/json/465.json','["寂寥高室古松寒，松下仙人字委鸞。頭垂白髮朝鳴磬，", "悠悠萬古皆如此，秋比松枝春比蘭。"]'),
('yuding-46','賦得直如朱絲弦','楊衡','唐','御定全唐诗','yuding','','[]','寂寞瑤琴上，深知直者情。幸傳朱鷺曲，那止素絲名。',72,'御定全唐詩/json/465.json','["寂寞瑤琴上，深知直者情。幸傳朱鷺曲，那止素絲名。", "瑞草人空仰，王言世久行。大方聞正位，樂府動清聲。", "文武音初合，宮商調屢更。誰能向機杼，終日泣無成。"]'),
('yuding-47','早春即事','楊衡','唐','御定全唐诗','yuding','','[]','眼重朝眠足，頭輕宿醉醒。陽光滿前戶，雪水半中庭。',72,'御定全唐詩/json/465.json','["眼重朝眠足，頭輕宿醉醒。陽光滿前戶，雪水半中庭。", "候變隨天氣，春生逐地形。北簷梅晚白，東岸柳先青。", "蔥壟抽羊角，松巢墮鶴翎。老來詩更拙，吟罷少人聽。"]'),
('yuding-48','題花樹','楊衡','唐','御定全唐诗','yuding','','[]','都無看花意，偶到樹邊來。可憐枝上色，一一為愁開。',24,'御定全唐詩/json/465.json','["都無看花意，偶到樹邊來。可憐枝上色，一一為愁開。"]'),
('yuding-49','宿吉祥寺寄廬山隱者','楊衡','唐','御定全唐诗','yuding','','[]','風鳴雲外鐘，鶴宿千年松。相思杳不見，月出山重重。',24,'御定全唐詩/json/465.json','["風鳴雲外鐘，鶴宿千年松。相思杳不見，月出山重重。"]'),
('yuding-50','邊思','楊衡','唐','御定全唐诗','yuding','','[]','蘇武節旄盡，李陵音信稀。梅當隴上發，人向隴頭歸。',24,'御定全唐詩/json/465.json','["蘇武節旄盡，李陵音信稀。梅當隴上發，人向隴頭歸。"]'),
('yuding-51','夜半步次古城','楊衡','唐','御定全唐诗','yuding','','[]','茫茫死複生，惟有古時城。夜半無鳥雀，花枝當月明。',24,'御定全唐詩/json/465.json','["茫茫死複生，惟有古時城。夜半無鳥雀，花枝當月明。"]'),
('yuding-52','春夢','楊衡','唐','御定全唐诗','yuding','','[]','空庭日照花如錦，紅妝美人當晝寢。',32,'御定全唐詩/json/465.json','["空庭日照花如錦，紅妝美人當晝寢。", "傍人不知夢中事，唯見玉釵時墜枕。"]'),
('yuding-53','宿青牛谷','楊衡','唐','御定全唐诗','yuding','','[]','隨雲步入青牛谷，青牛道士留我宿。',32,'御定全唐詩/json/465.json','["隨雲步入青牛谷，青牛道士留我宿。", "可憐夜久月明中，唯有壇邊一枝竹。"]'),
('yuding-54','槿','楊衡','唐','御定全唐诗','yuding','','[]','自用金錢買槿栽，二年方始一花開。',32,'御定全唐詩/json/465.json','["自用金錢買槿栽，二年方始一花開。", "憐紅未許家人見，蝴蝶爭知早到來。"]'),
('yuding-55','九日','楊衡','唐','御定全唐诗','yuding','','[]','黃菊紫菊傍籬落，摘菊泛酒愛芳新。',32,'御定全唐詩/json/465.json','["黃菊紫菊傍籬落，摘菊泛酒愛芳新。", "不堪今日望鄉意，強插茱萸隨眾人。"]'),
('yuding-56','仙女詞','楊衡','唐','御定全唐诗','yuding','','[]','玉京初侍紫皇君，金縷鴛鴦滿絳裙。',32,'御定全唐詩/json/465.json','["玉京初侍紫皇君，金縷鴛鴦滿絳裙。", "仙宮一閉無消息，遙結芳心向碧雲。"]'),
('yuding-57','句','楊衡','唐','御定全唐诗','yuding','','[]','賢人處霄漢，荒澤自耕耘。',32,'御定全唐詩/json/465.json','["賢人處霄漢，荒澤自耕耘。", "隴首降時雨，雷聲出夏雲。", "一一鶴聲飛上天。"]'),
('yuding-0','享太廟樂章','牛僧孺','唐','御定全唐诗','yuding','','[]','湜湜頎頎，融昭德輝。不紐不舒，貫成九圍。',40,'御定全唐詩/json/466.json','["湜湜頎頎，融昭德輝。不紐不舒，貫成九圍。", "武烈文經，敷施當宜。纂堯付啟，億萬熙熙。"]'),
('yuding-1','樂天夢得有歲夜詩聊以奉和','牛僧孺','唐','御定全唐诗','yuding','','[]','惜歲歲今盡，少年應不知。淒涼數流輩，歡喜見孫兒。',48,'御定全唐詩/json/466.json','["惜歲歲今盡，少年應不知。淒涼數流輩，歡喜見孫兒。", "暗減一身力，潛添滿鬢絲。莫愁花笑老，花自幾多時。"]'),
('yuding-2','李蘇州遺太湖石奇狀絕倫因題二十韻奉呈夢得、樂天','牛僧孺','唐','御定全唐诗','yuding','','[]','胚渾何時結，嵌空此日成。掀蹲龍虎鬥，挾怪鬼神驚。',241,'御定全唐詩/json/466.json','["胚渾何時結，嵌空此日成。掀蹲龍虎鬥，挾怪鬼神驚。", "帶雨新水靜，輕敲碎玉鳴。攙叉鋒刃簇，縷絡釣絲縈。", "近水搖奇冷，依松助澹清。通身鱗甲隱，透穴洞天明。", "醜凸隆胡准，深凹刻兕觥。雷風疑欲變，陰黑訝將行。", "噤z9微寒早，輪囷數片橫。地祇愁墊壓，鼇足困支撐。", "珍重姑蘇守，相憐懶慢情。為探湖裏物，不怕浪中鯨。", "利涉餘千里，山河僅百程。池塘初展見，金玉自凡輕。", "側眩魂猶悚，周觀意漸平。似逢三益友，如對十年兄。", "旺興添魔力，消煩破宿酲。媲人當綺皓，視秩即公卿。", "念此園林寶，還須別識精。詩仙有劉白，為汝數逢迎。"]'),
('yuding-3','席上贈劉夢得','牛僧孺','唐','御定全唐诗','yuding','','[]','粉署為郎四十春，今來名輩更無人。休論世上升沉事，',40,'御定全唐詩/json/466.json','["粉署為郎四十春，今來名輩更無人。休論世上升沉事，", "莫嫌恃酒輕言語，曾把文章謁後塵。"]'),
('yuding-4','句','牛僧孺','唐','御定全唐诗','yuding','','[]','但愁封寄去，魔物或驚禪。',62,'御定全唐詩/json/466.json','["但愁封寄去，魔物或驚禪。", "惟羨東都白居士，年年香積問禪師。", "不是道公狂不得，恨公逢我不教狂。", "地瘦草叢短。", "求人氣色沮，憑酒意乃伸。"]'),
('yuding-5','賦得月照冰池','葉季良','唐','御定全唐诗','yuding','','[]','霽夕雲初斂，棲娥月未虧。圓光生碧海，素色滿瑤池。',72,'御定全唐詩/json/466.json','["霽夕雲初斂，棲娥月未虧。圓光生碧海，素色滿瑤池。", "天迥輪空見，波凝影詎窺。浮霜玉比彩，照像鏡同規。", "皎潔寒偏淨，裴回夜轉宜。誰憐幽境在，長與賞心隨。"]'),
('yuding-6','賦得琢玉成器','葉季良','唐','御定全唐诗','yuding','','[]','片玉寄幽石，紛綸當代名。荊人獻始遇，良匠琢初成。',72,'御定全唐詩/json/466.json','["片玉寄幽石，紛綸當代名。荊人獻始遇，良匠琢初成。", "冰映寒光動，虹開晚色明。雅容看更澈，餘響扣彌清。", "自與瓊瑤比，方隨掌握榮。因知君有用，高價佇連城。"]'),
('yuding-7','省試吳宮教美人戰','葉季良','唐','御定全唐诗','yuding','','[]','強吳矜霸略，講武在深宮。盡出嬌娥妓，先觀上將風。',72,'御定全唐詩/json/466.json','["強吳矜霸略，講武在深宮。盡出嬌娥妓，先觀上將風。", "揮戈羅袖卷，擐甲汗妝紅。掩笑分旗下，含羞入隊中。", "鼓停行未正，刑舉令才崇。自可威鄰國，何勞逞戰功。"]'),
('yuding-8','題曆山司徒右長史祖宅','湛賁','唐','御定全唐诗','yuding','','[]','隳官長史籍，高步曆山椒。麗句傳黃絹，香名播宋朝。',72,'御定全唐詩/json/466.json','["隳官長史籍，高步曆山椒。麗句傳黃絹，香名播宋朝。", "分能知止足，跡貴出塵囂。松竹心長固，池台興自饒。", "龍宮欣訪舊，鶯谷忝遷喬。從事叨承乏，銅章愧在腰。"]'),
('yuding-9','伏覽呂侍郎丘員外舊題十三代祖曆山草堂詩因書記事','湛賁','唐','御定全唐诗','yuding','','[]','名遂貴知己，道勝方晦跡。高居葺蓮宮，遺文煥石壁。',72,'御定全唐詩/json/466.json','["名遂貴知己，道勝方晦跡。高居葺蓮宮，遺文煥石壁。", "桑田代已變，池草春猶碧。識曲遇周郎，知音荷宗伯。", "調逸南平兆，風清建安跡。祖德今發揚，還同書史冊。"]'),
('yuding-10','別慧山書堂','湛賁','唐','御定全唐诗','yuding','','[]','捲簾曉望雲平檻，下榻宵吟月半窗。',32,'御定全唐詩/json/466.json','["捲簾曉望雲平檻，下榻宵吟月半窗。", "病守未能依結社，更施何術去為邦。"]'),
('yuding-11','暮春自南台丞再除給事中','薛存誠','唐','御定全唐诗','yuding','','[]','再入青鎖闈，忝官誠自非。拂塵驚物在，開戶似僧歸。',48,'御定全唐詩/json/466.json','["再入青鎖闈，忝官誠自非。拂塵驚物在，開戶似僧歸。", "積草漸無徑，殘花猶灑衣。禁垣偏日近，行坐是恩輝。"]'),
('yuding-12','禦制段太尉碑','薛存誠','唐','御定全唐诗','yuding','','[]','葬儀從儉禮，刊石荷堯君。露跡垂繁字，天哀灑麗文。',72,'御定全唐詩/json/466.json','["葬儀從儉禮，刊石荷堯君。露跡垂繁字，天哀灑麗文。", "詔深榮嗣子，海變記孤墳。寶思皆涵象，皇心永念勳。", "雅詞黃絹妙，渥澤紫泥分。青史應同久，芳名萬古聞。"]'),
('yuding-13','禦題國子監門','薛存誠','唐','御定全唐诗','yuding','','[]','宸翰符玄造，榮題國子門。筆鋒回日月，字勢動乾坤。',72,'御定全唐詩/json/466.json','["宸翰符玄造，榮題國子門。筆鋒回日月，字勢動乾坤。", "簷下雲光絕，梁間鵲影翻。張英聖莫擬，索靖妙難言。", "為著盤龍跡，能彰舞鳳蹲。更隨垂露像，常以沐皇恩。"]'),
('yuding-14','禦箭連中雙兔','薛存誠','唐','御定全唐诗','yuding','','[]','宸游經上苑，羽獵向閒田。狡兔初迷窟，纖驪詎著鞭。',72,'御定全唐詩/json/466.json','["宸游經上苑，羽獵向閒田。狡兔初迷窟，纖驪詎著鞭。", "三驅仍百步，一發遂雙連。影射含霜草，魂消向月弦。", "驩聲動寒木，喜氣滿晴天。那似陳王意，空隨樂府篇。"]'),
('yuding-15','太學創置石經','薛存誠','唐','御定全唐诗','yuding','','[]','聖唐復古制，德義功無替。奧旨悅詩書，遺文分篆隸。',72,'御定全唐詩/json/466.json','["聖唐復古制，德義功無替。奧旨悅詩書，遺文分篆隸。", "銀鉤互交映，石壁靡塵翳。永與乾坤期，不逐日月逝。", "儒林道益廣，學者心彌銳。從此理化成，恩光遍遐裔。"]'),
('yuding-16','觀南郊回仗','薛存誠','唐','御定全唐诗','yuding','','[]','傳警千門寂，南郊彩仗回。但驚龍再見，誰識日雙開。',72,'御定全唐詩/json/466.json','["傳警千門寂，南郊彩仗回。但驚龍再見，誰識日雙開。", "德澤施雲雨，恩光變燼灰。閱兵貔武振，聽樂鳳凰來。", "候刻移宸輦，遵時集觀台。多慚遠臣賤，不得禮容陪。"]'),
('yuding-17','聞擊壤','薛存誠','唐','御定全唐诗','yuding','','[]','堯年聽野老，擊壤複何雲。自謂歡由己，寧知德在君。',72,'御定全唐詩/json/466.json','["堯年聽野老，擊壤複何雲。自謂歡由己，寧知德在君。", "氣平閑易暢，聲賀作難分。耕鑿方隨日，恩威比望雲。", "簣桴均下調，和木等南熏。無落於吾事，誰將帝已聞。"]'),
('yuding-18','膏澤多豐年','薛存誠','唐','御定全唐诗','yuding','','[]','帝德方多澤，莓莓井徑同。八方甘雨布，四遠報年豐。',72,'御定全唐詩/json/466.json','["帝德方多澤，莓莓井徑同。八方甘雨布，四遠報年豐。", "廒庾千廂在，幽流萬壑通。候時勤稼穡，擊壤樂農功。", "畎畝人無惰，田廬歲不空。何須憂伏臘，千載賀堯風。"]'),
('yuding-19','東都父老望幸','薛存誠','唐','御定全唐诗','yuding','','[]','鑾輿秦地久，羽衛洛陽空。彼土雖憑固，茲川乃得中。',96,'御定全唐詩/json/466.json','["鑾輿秦地久，羽衛洛陽空。彼土雖憑固，茲川乃得中。", "龍顏覲白日，鶴發仰清風。望幸誠逾邈，懷來意不窮。", "昔因封泰嶽，今佇躡維嵩。天地心無異，神祇理亦同。", "翠華翔渭北，玉檢候關東。眾願其難阻，明君早勒功。"]'),
('yuding-20','嵩山望幸','薛存誠','唐','御定全唐诗','yuding','','[]','峻極位何崇，方知造化功。降靈逢聖主，望幸表維嵩。',72,'御定全唐詩/json/466.json','["峻極位何崇，方知造化功。降靈逢聖主，望幸表維嵩。", "隱映連青壁，嵯峨向碧空。象車因葉瑞，龍駕願升中。", "萬歲聲長在，千岩氣轉雄。東都歌盛事，西笑佇皇風。"]'),
('yuding-21','華清宮望幸','薛存誠','唐','御定全唐诗','yuding','','[]','驪岫接新豐，岧嶢駕碧空。鑿山開秘殿，隱霧蔽仙宮。',72,'御定全唐詩/json/466.json','["驪岫接新豐，岧嶢駕碧空。鑿山開秘殿，隱霧蔽仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，深沉閉綺櫳。東郊望幸處，瑞氣靄濛濛。"]'),
('yuding-22','謁見日將至雙闕','薛存誠','唐','御定全唐诗','yuding','','[]','曉色臨雙闕，微臣禮位陪。遠驚龍鳳睹，誰識冕旒開。',72,'御定全唐詩/json/466.json','["曉色臨雙闕，微臣禮位陪。遠驚龍鳳睹，誰識冕旒開。", "藹藹千年盛，顒顒萬國來。天文標日月，時令布雲雷。", "迥出黃金殿，全分白玉台。雕蟲竟何取，瞻戀不知回。"]'),
('yuding-23','南至日隔仗望含元殿爐香','裴次元','唐','御定全唐诗','yuding','','[]','冕旒初負扆，卉服盡朝天。暘谷初移日，金爐漸起煙。',72,'御定全唐詩/json/466.json','["冕旒初負扆，卉服盡朝天。暘谷初移日，金爐漸起煙。", "芬馨流遠近，散漫入貂蟬。霜仗凝逾白，朱欄映轉鮮。", "始看浮闕在，稍見逐風遷。為沐皇家慶，來瞻羽衛前。"]'),
('yuding-24','律中應鐘','裴次元','唐','御定全唐诗','yuding','','[]','律窮方數寸，室暗在三重。伶管灰先動，秦正節已逢。',72,'御定全唐詩/json/466.json','["律窮方數寸，室暗在三重。伶管灰先動，秦正節已逢。", "商聲辭玉笛，羽調入金鐘。密葉翻霜彩，輕冰斂水容。", "望鴻南去絕，迎氣北來濃。願托無凋性，寒林自比松。"]'),
('yuding-25','賦得亞父碎玉鬥','裴次元','唐','御定全唐诗','yuding','','[]','雄謀竟不決，寶玉將何愛。倏爾霜刃揮，颯然春冰碎。',72,'御定全唐詩/json/466.json','["雄謀竟不決，寶玉將何愛。倏爾霜刃揮，颯然春冰碎。", "飛光動旗幟，散響驚環佩。霜濃繡帳前，星流錦筵內。", "圖王業已失，為虜言空悔。獨有青史中，英風冠千載。"]'),
('yuding-26','句','裴次元','唐','御定全唐诗','yuding','','[]','積高依郡城，迥拔淩霄漢。',12,'御定全唐詩/json/466.json','["積高依郡城，迥拔淩霄漢。"]'),
('yuding-27','並州路','李宣遠','唐','御定全唐诗','yuding','','[]','秋日並州路，黃榆落故關。孤城吹角罷，數騎射雕還。',48,'御定全唐詩/json/466.json','["秋日並州路，黃榆落故關。孤城吹角罷，數騎射雕還。", "帳幕遙臨水，牛羊自下山。征人正垂淚，烽火起雲間。"]'),
('yuding-28','近無西耗','李宣遠','唐','御定全唐诗','yuding','','[]','遠戎兵壓境，遷客淚橫襟。烽堠驚秦塞，囚居困越吟。',48,'御定全唐詩/json/466.json','["遠戎兵壓境，遷客淚橫襟。烽堠驚秦塞，囚居困越吟。", "自憐牛馬走，未識犬羊心。一月無消息，西看日又沉。"]'),
('yuding-29','曲江亭望慈恩寺杏園花發','李君何','唐','御定全唐诗','yuding','','[]','春晴憑水軒，仙杏發南園。開蕊風初曉，浮香景欲暄。',72,'御定全唐詩/json/466.json','["春晴憑水軒，仙杏發南園。開蕊風初曉，浮香景欲暄。", "光華臨禦陌，色相對空門。野雪遙添淨，山煙近借繁。", "地閑分鹿苑，景勝類桃源。況值新晴日，芳枝度彩鴛。"]'),
('yuding-30','除夜書情','周弘亮','唐','御定全唐诗','yuding','','[]','何處風塵歲，雲陽古驛前。三冬不再稔，曉日又明年。',48,'御定全唐詩/json/466.json','["何處風塵歲，雲陽古驛前。三冬不再稔，曉日又明年。", "春入江南柳，寒歸塞北天。還傷知候客，花景對韋編。"]'),
('yuding-31','曲江亭望慈恩寺杏園花發','周弘亮','唐','御定全唐诗','yuding','','[]','江亭閑望處，遠近見秦源。古寺遲春景，新花發杏園。',72,'御定全唐詩/json/466.json','["江亭閑望處，遠近見秦源。古寺遲春景，新花發杏園。", "萼中輕蕊密，枝上素姿繁。拂雨雲初起，含風雪欲翻。", "容輝明十地，香氣遍千門。願莫隨桃李，芳菲不為言。"]'),
('yuding-32','故鄉除夜','周弘亮','唐','御定全唐诗','yuding','','[]','三百六十日雲終，故鄉還與異鄉同。非唯律變情堪恨，',40,'御定全唐詩/json/466.json','["三百六十日雲終，故鄉還與異鄉同。非唯律變情堪恨，", "詩成始欲吟將看，早是去年牽課中。"]'),
('yuding-33','曲江亭望慈恩寺杏園花發','陳翥','唐','御定全唐诗','yuding','','[]','曲江晴望好，近接梵王家。十畝開金地，千林發杏花。',72,'御定全唐詩/json/466.json','["曲江晴望好，近接梵王家。十畝開金地，千林發杏花。", "映雪猶誤雪，煦日欲成霞。紫陌傳香遠，紅泉落影斜。", "園中春尚早，亭上路非賒。芳景堪遊處，其如惜物華。"]'),
('yuding-34','曲江亭望慈恩寺杏園花發','曹著','唐','御定全唐诗','yuding','','[]','渚亭臨淨域，憑望一開軒。晚日分初地，東風發杏園。',72,'御定全唐詩/json/466.json','["渚亭臨淨域，憑望一開軒。晚日分初地，東風發杏園。", "異香飄九陌，麗色映千門。照灼瑤華散，葳蕤玉露繁。", "未教遊妓折，乍聽早鶯喧。誰複爭桃李，含芳自不言。"]'),
('yuding-35','魚上冰','王公亮','唐','御定全唐诗','yuding','','[]','春生寒氣減，稍動久潛魚。乍喜東風至，來看曲岸初。',72,'御定全唐詩/json/466.json','["春生寒氣減，稍動久潛魚。乍喜東風至，來看曲岸初。", "出冰朱鬣見，望日錦鱗舒。漸覺流澌近，還欣掉尾餘。", "噞喁情自樂，沿溯意寧疏。倘得隨鯤化，終能上太虛。"]'),
('yuding-36','賦得竹箭有筠','張仲方','唐','御定全唐诗','yuding','','[]','東南生綠竹，獨美有筠箭。枝葉詎曾凋，風霜孰雲變。',72,'御定全唐詩/json/466.json','["東南生綠竹，獨美有筠箭。枝葉詎曾凋，風霜孰雲變。", "偏宜林表秀，多向歲寒見。碧色乍蔥蘢，清光常蒨練。", "皮開鳳彩出，節勁龍文現。愛此守堅貞，含歌屬時彥。"]'),
('yuding-37','贈毛仙翁','張仲方','唐','御定全唐诗','yuding','','[]','毛仙翁，毛仙翁，容貌常如二八童。幾歲頭梳雲鬢綠，',96,'御定全唐詩/json/466.json','["毛仙翁，毛仙翁，容貌常如二八童。幾歲頭梳雲鬢綠，", "方口秀眉編貝齒，了然炅炅雙瞳子。芝椿稟氣本堅強，", "靈通指下磚甓化，瑞氣爐中金玉流。定是煙霞列仙侶，", "陰功足，陰功成，羽駕何年歸上清。待我休官了婚嫁，"]'),
('yuding-38','句','張仲方','唐','御定全唐诗','yuding','','[]','入門池色靜，登閣雨聲來。',12,'御定全唐詩/json/466.json','["入門池色靜，登閣雨聲來。"]'),
('yuding-39','和白樂天','崔玄亮','唐','御定全唐诗','yuding','','[]','病餘歸到洛陽頭，拭目開眉見白侯。鳳詔恐君今歲去，',40,'御定全唐詩/json/466.json','["病餘歸到洛陽頭，拭目開眉見白侯。鳳詔恐君今歲去，", "相對憶劉劉在遠，寒宵耿耿夢長洲。"]'),
('yuding-40','臨終詩','崔玄亮','唐','御定全唐诗','yuding','','[]','暫榮暫悴石敲火，即空即色眼生花。',32,'御定全唐詩/json/466.json','["暫榮暫悴石敲火，即空即色眼生花。", "許時為客今歸去，大曆元年是我家。"]'),
('yuding-41','句','崔玄亮','唐','御定全唐诗','yuding','','[]','共相呼喚醉歸來。',8,'御定全唐詩/json/466.json','["共相呼喚醉歸來。"]'),
('yuding-42','省試臨淵羡魚','徐牧','唐','御定全唐诗','yuding','','[]','清泚濯纓處，今來喜一臨。慚無下釣處，空有羨魚心。',72,'御定全唐詩/json/466.json','["清泚濯纓處，今來喜一臨。慚無下釣處，空有羨魚心。", "退省時頻改，謀身歲屢沉。鬣成川上媚，網就水寧深。", "赬尾臨波里，朱須破浪潯。此時倘不漏，江上免行吟。"]'),
('yuding-43','淮南遊故居感舊，酬西川李尚書德裕','王播','唐','御定全唐诗','yuding','','[]','昔年獻賦去江湄，今日行春到卻悲。三徑僅存新竹樹，',40,'御定全唐詩/json/466.json','["昔年獻賦去江湄，今日行春到卻悲。三徑僅存新竹樹，", "更見橋邊記名姓，始知題柱免人嗤。"]'),
('yuding-44','題木蘭院二首','王播','唐','御定全唐诗','yuding','','[]','三十年前此院遊，木蘭花發院新修。',64,'御定全唐詩/json/466.json','["三十年前此院遊，木蘭花發院新修。", "如今再到經行處，樹老無花僧白頭。", "上堂已了各西東，慚愧闍黎飯後鐘。", "三十年來塵撲面，如今始得碧紗籠。"]'),
('yuding-45','上巳接清明遊宴','獨孤良弼','唐','御定全唐诗','yuding','','[]','上巳歡初罷，清明賞又追。閏年侵舊曆，令節並芳時。',72,'御定全唐詩/json/466.json','["上巳歡初罷，清明賞又追。閏年侵舊曆，令節並芳時。", "細雨鶯飛重，春風酒醞遲。尋花迷白雪，看柳拆青絲。", "淑氣如相待，天和意為誰。籲嗟名未立，空詠宴遊詩。"]'),
('yuding-46','次潭州，酬唐侍禦、姚員外游道林嶽麓寺題示','沈傳師','唐','御定全唐诗','yuding','','[]','承明年老輒自論，乞得湘守東南奔。為聞楚國富山水，',112,'御定全唐詩/json/466.json','["承明年老輒自論，乞得湘守東南奔。為聞楚國富山水，", "不令執簡候亭館，直許攜手游山樊。忽驚列岫曉來逼，", "華鑣躞蹀絢砂步，大旆彩錯輝松門。樛枝競騖龍蛇勢，", "目傷平楚虞帝魂，情多思遠聊開樽。危弦細管逐歌飄，", "嗟餘潦倒久不利，忍複感激論元元。"]'),
('yuding-47','和李德裕觀玉蕊花見懷之作','沈傳師','唐','御定全唐诗','yuding','','[]','曾對金鑾直，同依玉樹陰。雪英飛舞近，煙葉動搖深。',48,'御定全唐詩/json/466.json','["曾對金鑾直，同依玉樹陰。雪英飛舞近，煙葉動搖深。", "素萼年年密，衰容日日侵。勞君想華髮，近欲不勝簪。"]'),
('yuding-48','贈毛仙翁','沈傳師','唐','御定全唐诗','yuding','','[]','安期何事出雲煙，為把仙方與世傳。只向人間稱百歲，',40,'御定全唐詩/json/466.json','["安期何事出雲煙，為把仙方與世傳。只向人間稱百歲，", "更說桃源更深處，異花長占四時天。"]'),
('yuding-49','《寄大府兄侍史','沈傳師','唐','御定全唐诗','yuding','','[]','積雪山陰馬過難，殘更深夜鐵衣寒。',32,'御定全唐詩/json/466.json','["積雪山陰馬過難，殘更深夜鐵衣寒。", "將軍破了單于陣，更把兵書仔細看。"]'),
('yuding-50','《蒙泉','沈傳師','唐','御定全唐诗','yuding','','[]','京路馬駸駸，塵勞日向深。蒙泉聊息駕，可以洗君心。',24,'御定全唐詩/json/466.json','["京路馬駸駸，塵勞日向深。蒙泉聊息駕，可以洗君心。"]'),
('yuding-51','春從何處來','白行簡','唐','御定全唐诗','yuding','','[]','欲識春生處，先從木德來。入門潛報柳，度嶺暗驚梅。',72,'御定全唐詩/json/466.json','["欲識春生處，先從木德來。入門潛報柳，度嶺暗驚梅。", "透雪寒光散，消冰水鏡開。曉迎郊騎發，夜逐鬥杓回。", "淑氣空中變，新聲雨後催。偏宜資律呂，應是候陽臺。"]'),
('yuding-52','貢院樓北新栽小松','白行簡','唐','御定全唐诗','yuding','','[]','華省春霜曙，樓陰植小松。移根依厚地，委質別危峰。',72,'御定全唐詩/json/466.json','["華省春霜曙，樓陰植小松。移根依厚地，委質別危峰。", "北戶知猶遠，東堂幸見容。心堅終待鶴，枝嫩未成龍。", "夜影看仍薄，朝嵐色漸濃。山苗不可蔭，孤直俟秦封。"]'),
('yuding-53','金在熔','白行簡','唐','御定全唐诗','yuding','','[]','巨橐方熔物，洪爐欲范金。紫光看漸發，赤氣望逾深。',72,'御定全唐詩/json/466.json','["巨橐方熔物，洪爐欲范金。紫光看漸發，赤氣望逾深。", "焰熱晴雲變，煙浮晝景陰。堅剛由我性，鼓鑄任君心。", "踴躍徒標異，沈潛自可欽。何當得成器，待叩向知音。"]'),
('yuding-54','歸馬華山','白行簡','唐','御定全唐诗','yuding','','[]','牧野功成後，周王戰馬閑。驅馳休伏皂，飲齕任依山。',72,'御定全唐詩/json/466.json','["牧野功成後，周王戰馬閑。驅馳休伏皂，飲齕任依山。", "逐日朝仍去，隨風暮自還。冰生疑隴阪，葉落似榆關。", "躞蹀仙峰下，騰驤渭水灣。幸逢時偃武，不復鼓鼙間。"]'),
('yuding-55','夫子鼓琴得其人','白行簡','唐','御定全唐诗','yuding','','[]','宣父窮玄奧，師襄授素琴。稍殊流水引，全辨聖人心。',72,'御定全唐詩/json/466.json','["宣父窮玄奧，師襄授素琴。稍殊流水引，全辨聖人心。", "慕德聲逾感，懷人意自深。泠泠傳妙手，摵摵振空林。", "促調清風至，操弦白日沈。曲終情不盡，千古仰知音。"]'),
('yuding-56','李都尉重陽日得蘇屬國書','白行簡','唐','御定全唐诗','yuding','','[]','降虜意何如，窮荒九月初。三秋異鄉節，一紙故人書。',72,'御定全唐詩/json/466.json','["降虜意何如，窮荒九月初。三秋異鄉節，一紙故人書。", "對酒情無極，開緘思有餘。感時空寂寞，懷舊幾躊躇。", "雁盡平沙迥，煙銷大漠虛。登臺南望處，掩淚對雙魚。"]'),
('yuding-57','在巴南望郡南山呈樂天','白行簡','唐','御定全唐诗','yuding','','[]','臨江一嶂白雲間，紅綠層層錦繡班。',32,'御定全唐詩/json/466.json','["臨江一嶂白雲間，紅綠層層錦繡班。", "不作巴南天外意，何殊昭應望驪山。"]'),
('yuding-58','春雲','裴澄','唐','御定全唐诗','yuding','','[]','漠漠複溶溶，乘春任所從。映林初展葉，觸石未成峰。',72,'御定全唐詩/json/466.json','["漠漠複溶溶，乘春任所從。映林初展葉，觸石未成峰。", "旭日消寒翠，晴煙點淨容。霏微將似滅，深淺又如重。", "薄彩臨溪散，輕陰帶雨濃。空餘負樵者，嶺上自相逢。"]'),
('yuding-59','賦得沽美玉','羅立言','唐','御定全唐诗','yuding','','[]','誰憐被褐士，懷玉正求沽。成器終期達，逢時豈見誣。',72,'御定全唐詩/json/466.json','["誰憐被褐士，懷玉正求沽。成器終期達，逢時豈見誣。", "寶同珠照乘，價重劍論都。浮彩朝虹滿，懸光夜月孤。", "幾年淪瓦礫，今日出泥塗。采斫資良匠，無令瑕掩瑜。"]'),
('yuding-60','寒食遣懷','張燦','唐','御定全唐诗','yuding','','[]','繁華泣清露，悄悄落衣巾。明日逢寒食，春風見故人。',48,'御定全唐詩/json/466.json','["繁華泣清露，悄悄落衣巾。明日逢寒食，春風見故人。", "病來羞滯楚，西去欲迷秦。憔悴此時久，青山歸四鄰。"]'),
('yuding-0','春日山亭','牟融','唐','御定全唐诗','yuding','','[]','醉來重整華陽巾，搔首驚看白髮新。莫道愁多因病酒，',40,'御定全唐詩/json/467.json','["醉來重整華陽巾，搔首驚看白髮新。莫道愁多因病酒，", "正是聖朝全盛日，詎知林下有閒人。"]'),
('yuding-1','寄周韶州','牟融','唐','御定全唐诗','yuding','','[]','十年學道困窮廬，空有長才重老儒。功業要當垂永久，',40,'御定全唐詩/json/467.json','["十年學道困窮廬，空有長才重老儒。功業要當垂永久，", "寄語故人休悵怏，古來賢達事多殊。"]'),
('yuding-2','秋夜醉歸，有感而賦','牟融','唐','御定全唐诗','yuding','','[]','銜杯誰道易更闌，沉醉歸來不自歡。惆悵後時孤劍冷，',40,'御定全唐詩/json/467.json','["銜杯誰道易更闌，沉醉歸來不自歡。惆悵後時孤劍冷，", "多少客懷消不得，臨風搔首浩漫漫。"]'),
('yuding-3','寄範使君','牟融','唐','御定全唐诗','yuding','','[]','未秋為別已終秋，咫尺婁江路阻修。心上惟君知委曲，',40,'御定全唐詩/json/467.json','["未秋為別已終秋，咫尺婁江路阻修。心上惟君知委曲，", "西望家山成浩歎，臨風搔首不勝愁。"]'),
('yuding-4','送羅約','牟融','唐','御定全唐诗','yuding','','[]','雨晴江館柳依依，握手那堪此別離。獨鶴孤琴隨遠旆，',40,'御定全唐詩/json/467.json','["雨晴江館柳依依，握手那堪此別離。獨鶴孤琴隨遠旆，", "後夜定知相憶處，東風回首不勝悲。"]'),
('yuding-5','題李昭訓山水','牟融','唐','御定全唐诗','yuding','','[]','卜築藏修地自偏，尊前詩酒集群賢。半岩松暝時藏鶴，',40,'御定全唐詩/json/467.json','["卜築藏修地自偏，尊前詩酒集群賢。半岩松暝時藏鶴，", "南州人物依然在，山水幽居勝輞川。"]'),
('yuding-6','處厚游杭，作詩寄之','牟融','唐','御定全唐诗','yuding','','[]','江村搖落暫逢秋，況是聞君獨遠遊。浙水風煙思吊古，',40,'御定全唐詩/json/467.json','["江村搖落暫逢秋，況是聞君獨遠遊。浙水風煙思吊古，", "念我故人勞碌久，不如投老臥滄洲。"]'),
('yuding-7','山中有懷李十二','牟融','唐','御定全唐诗','yuding','','[]','林前風景晚蒼蒼，林下懷人路杳茫。白髮流年淹舊業，',40,'御定全唐詩/json/467.json','["林前風景晚蒼蒼，林下懷人路杳茫。白髮流年淹舊業，", "何事登樓□□□，幾回搔首□思歸。"]'),
('yuding-8','客中作','牟融','唐','御定全唐诗','yuding','','[]','異鄉歲晚悵離懷，遊子驅馳愧不才。夜夜砧聲催客去，',40,'御定全唐詩/json/467.json','["異鄉歲晚悵離懷，遊子驅馳愧不才。夜夜砧聲催客去，", "幾度無聊倍惆悵，臨風搔首獨興哀。"]'),
('yuding-9','山寺律僧畫蘭竹圖','牟融','唐','御定全唐诗','yuding','','[]','偶來絕頂興無窮，獨有山僧筆最工。綠徑日長袁戶在，',40,'御定全唐詩/json/467.json','["偶來絕頂興無窮，獨有山僧筆最工。綠徑日長袁戶在，", "欲結歲寒盟不去，忘機相對畫圖中。"]'),
('yuding-10','送客之杭','牟融','唐','御定全唐诗','yuding','','[]','西風吹冷透貂裘，行色匆匆不暫留。帆帶夕陽投越浦，',40,'御定全唐詩/json/467.json','["西風吹冷透貂裘，行色匆匆不暫留。帆帶夕陽投越浦，", "懸想到杭州興地，尊前應與話離憂。"]'),
('yuding-11','有感二首','牟融','唐','御定全唐诗','yuding','','[]','何事離懷入夢頻，貧居寂寞四無鄰。詩因韻險難成律，',80,'御定全唐詩/json/467.json','["何事離懷入夢頻，貧居寂寞四無鄰。詩因韻險難成律，", "十年飄泊如萍跡，一度登臨一悵神。", "搔首臨風獨倚欄，客邊驚覺歲華殘。棲遲未遇常鋾薦，", "何如日日長如醉，付與詩人一笑看。"]'),
('yuding-12','送沈侯之京','牟融','唐','御定全唐诗','yuding','','[]','悠悠旌旆出東樓，特出仙郎上帝州。劉旻才高能富國，',40,'御定全唐詩/json/467.json','["悠悠旌旆出東樓，特出仙郎上帝州。劉旻才高能富國，", "欲盡故人尊酒意，春風江上暫停舟。"]'),
('yuding-13','寄羽士','牟融','唐','御定全唐诗','yuding','','[]','別來有路隔仙凡，幾度臨風欲去難。樂道無時忘鶴伴，',40,'御定全唐詩/json/467.json','["別來有路隔仙凡，幾度臨風欲去難。樂道無時忘鶴伴，", "使我浮生塵鞅脫，相從應得一盤桓。"]'),
('yuding-14','題趙支','牟融','唐','御定全唐诗','yuding','','[]','林間曲徑掩衡茅，繞屋青青翡翠梢。一枕秋聲鸞舞月，',40,'御定全唐詩/json/467.json','["林間曲徑掩衡茅，繞屋青青翡翠梢。一枕秋聲鸞舞月，", "我有清風高節在，知君不負歲寒交。"]'),
('yuding-15','司馬遷墓','牟融','唐','御定全唐诗','yuding','','[]','落落長才負不羈，中原回首益堪悲。英雄此日誰能薦，',40,'御定全唐詩/json/467.json','["落落長才負不羈，中原回首益堪悲。英雄此日誰能薦，", "經過詞客空惆悵，落日寒煙賦黍離。"]'),
('yuding-16','春遊','牟融','唐','御定全唐诗','yuding','','[]','錦袍日暖耀冰蠶，上客陪遊酒半酣。笑拂吟鞭邀好興，',40,'御定全唐詩/json/467.json','["錦袍日暖耀冰蠶，上客陪遊酒半酣。笑拂吟鞭邀好興，", "正是太平行樂處，春風花下且停驂。"]'),
('yuding-17','水西草堂','牟融','唐','御定全唐诗','yuding','','[]','蘿徑蕭然曲業存，閑雲流水四無鄰。身留白屋潛蹤跡，',40,'御定全唐詩/json/467.json','["蘿徑蕭然曲業存，閑雲流水四無鄰。身留白屋潛蹤跡，", "遺書自有親□處，何必驅馳擾世塵。"]'),
('yuding-18','送羽衣之京','牟融','唐','御定全唐诗','yuding','','[]','羽衣縹緲拂塵囂，悵別河梁贈柳條。閬苑雲深孤鶴迥，',40,'御定全唐詩/json/467.json','["羽衣縹緲拂塵囂，悵別河梁贈柳條。閬苑雲深孤鶴迥，", "自是長生林下客，也陪鴛鷺入清朝。"]'),
('yuding-19','題道院壁','牟融','唐','御定全唐诗','yuding','','[]','山中舊宅四無鄰，草淨雲和迥絕塵。神棗胡麻能飯客，',40,'御定全唐詩/json/467.json','["山中舊宅四無鄰，草淨雲和迥絕塵。神棗胡麻能飯客，", "若使凡緣終可脫，也應從此度閑身。"]'),
('yuding-20','贈歐陽詹','牟融','唐','御定全唐诗','yuding','','[]','為客囊無季子金，半生蹤跡任浮沉。服勤因念劬勞重，',40,'御定全唐詩/json/467.json','["為客囊無季子金，半生蹤跡任浮沉。服勤因念劬勞重，", "家林千里遙相憶，幾度停車一悵吟。"]'),
('yuding-21','邵公母','牟融','唐','御定全唐诗','yuding','','[]','搔首驚聞楚些歌，拂衣歸去淚懸河。劬勞常想三春恨，',40,'御定全唐詩/json/467.json','["搔首驚聞楚些歌，拂衣歸去淚懸河。劬勞常想三春恨，", "傷心獨有黃堂客，幾度臨風詠蓼莪。"]'),
('yuding-22','客中作','牟融','唐','御定全唐诗','yuding','','[]','千里雲山戀舊遊，寒窗涼雨夜悠悠。浮亭花竹頻勞夢，',40,'御定全唐詩/json/467.json','["千里雲山戀舊遊，寒窗涼雨夜悠悠。浮亭花竹頻勞夢，", "一杯重向樽前醉，莫遣相思累白頭。"]'),
('yuding-23','贈楊處厚','牟融','唐','御定全唐诗','yuding','','[]','十年學道苦勞神，贏得尊前一病身。天上故人皆自貴，',40,'御定全唐詩/json/467.json','["十年學道苦勞神，贏得尊前一病身。天上故人皆自貴，", "幾度臨風一回首，笑看華髮及時新。"]'),
('yuding-24','重贈張籍','牟融','唐','御定全唐诗','yuding','','[]','舊日儀容只宛然，笑談不覺度流年。凡緣未了嗟無子，',40,'御定全唐詩/json/467.json','["舊日儀容只宛然，笑談不覺度流年。凡緣未了嗟無子，", "人生隨處堪為樂，管甚秋香滿鬢邊。"]'),
('yuding-25','贈殷以道','牟融','唐','御定全唐诗','yuding','','[]','世路紅塵懶步趨，長年結屋傍岩隅。獨留鄉井誠非隱，',40,'御定全唐詩/json/467.json','["世路紅塵懶步趨，長年結屋傍岩隅。獨留鄉井誠非隱，", "閑來撫景窮吟處，尊酒臨風不自娛。"]'),
('yuding-26','翁母些','牟融','唐','御定全唐诗','yuding','','[]','滿頭華髮向人垂，長逝音容迥莫追。先壟每懷風木夜，',40,'御定全唐詩/json/467.json','["滿頭華髮向人垂，長逝音容迥莫追。先壟每懷風木夜，", "獨有賢人崇孝義，傷心共詠蓼莪詩。"]'),
('yuding-27','題山莊','牟融','唐','御定全唐诗','yuding','','[]','蘿屋蕭蕭事事幽，臨風搔首遠凝眸。東園松菊存遺業，',40,'御定全唐詩/json/467.json','["蘿屋蕭蕭事事幽，臨風搔首遠凝眸。東園松菊存遺業，", "床頭濁酒時時漉，上客相過一任留。"]'),
('yuding-28','沈存尚林亭夜宴','牟融','唐','御定全唐诗','yuding','','[]','草堂寂寂景偏幽，到此令人一縱眸。松菊寒香三徑晚，',40,'御定全唐詩/json/467.json','["草堂寂寂景偏幽，到此令人一縱眸。松菊寒香三徑晚，", "終日忘情能自樂，清尊應得遣閒愁。"]'),
('yuding-29','題孫君山亭','牟融','唐','御定全唐诗','yuding','','[]','長年樂道遠塵氛，靜築藏修學隱淪。吟對琴樽庭下月，',40,'御定全唐詩/json/467.json','["長年樂道遠塵氛，靜築藏修學隱淪。吟對琴樽庭下月，", "林壑能忘軒冕貴，白雲黃鶴好相親。"]'),
('yuding-30','題徐俞山居','牟融','唐','御定全唐诗','yuding','','[]','青山重疊巧裁攢，引水流泉夜激湍。嵐鎖岩扉清晝暝，',40,'御定全唐詩/json/467.json','["青山重疊巧裁攢，引水流泉夜激湍。嵐鎖岩扉清晝暝，", "老我不堪詩思杳，幾回吟倚曲欄幹。"]'),
('yuding-31','送範啟東還京','牟融','唐','御定全唐诗','yuding','','[]','蕭蕭行李上征鞍，滿目離情欲去難。客裏故人尊酒別，',40,'御定全唐詩/json/467.json','["蕭蕭行李上征鞍，滿目離情欲去難。客裏故人尊酒別，", "重到京華舊游處，春風佳麗好盤桓。"]'),
('yuding-32','樓城敘別','牟融','唐','御定全唐诗','yuding','','[]','故人為客上神州，傾蓋相逢感昔遊。屈指年華嗟遠別，',40,'御定全唐詩/json/467.json','["故人為客上神州，傾蓋相逢感昔遊。屈指年華嗟遠別，", "此際那堪重分手，綠波芳草暫停舟。"]'),
('yuding-33','寫意二首','牟融','唐','御定全唐诗','yuding','','[]','寂寥荒館閉閑門，苔徑陰陰屐少痕。白髮顛狂塵夢斷，',80,'御定全唐詩/json/467.json','["寂寥荒館閉閑門，苔徑陰陰屐少痕。白髮顛狂塵夢斷，", "醉後曲肱林下臥，此生榮辱不須論。", "蕭蕭華髮滿頭生，深遠蓬門倦送迎。獨喜冥心無外慕，", "林下貧居甘困守，盡教城市不知名。"]'),
('yuding-34','贈浙西李相公','牟融','唐','御定全唐诗','yuding','','[]','長庚烈烈獨遙天，盛世應知降謫仙。月裏昔曾分兔藥，',40,'御定全唐詩/json/467.json','["長庚烈烈獨遙天，盛世應知降謫仙。月裏昔曾分兔藥，", "尊酒與君稱壽畢，春風入醉綺羅筵。"]'),
('yuding-35','天臺','牟融','唐','御定全唐诗','yuding','','[]','碧溪流水泛桃花，樹繞天臺迥不賒。洞裏無塵通客境，',40,'御定全唐詩/json/467.json','["碧溪流水泛桃花，樹繞天臺迥不賒。洞裏無塵通客境，", "此地不知何處去，暫留瓊佩臥煙霞。"]'),
('yuding-36','送陳衡','牟融','唐','御定全唐诗','yuding','','[]','秋江煙景晚蒼蒼，江上離人促去航。千里一官嗟獨往，',40,'御定全唐詩/json/467.json','["秋江煙景晚蒼蒼，江上離人促去航。千里一官嗟獨往，", "不必臨風悲冷落，古來白首尚為郎。"]'),
('yuding-37','送沈翔','牟融','唐','御定全唐诗','yuding','','[]','江上西風一棹歸，故人此別會應稀。清朝盡道無遺逸，',40,'御定全唐詩/json/467.json','["江上西風一棹歸，故人此別會應稀。清朝盡道無遺逸，", "臨岐不用空惆悵，未必新豐老布衣。"]'),
('yuding-38','過蠡湖','牟融','唐','御定全唐诗','yuding','','[]','東湖煙水浩漫漫，湘浦秋聲入夜寒。風外暗香飄落粉，',40,'御定全唐詩/json/467.json','["東湖煙水浩漫漫，湘浦秋聲入夜寒。風外暗香飄落粉，", "幾度篝簾相對處，無邊詩思到吟壇。"]'),
('yuding-39','登環翠樓','牟融','唐','御定全唐诗','yuding','','[]','山中地僻好藏修，寂寂幽居架小樓。雲樹四圍當戶暝，',40,'御定全唐詩/json/467.json','["山中地僻好藏修，寂寂幽居架小樓。雲樹四圍當戶暝，", "我亦人間肥遁客，也將蹤跡寄林丘。"]'),
('yuding-40','遊淮雲寺','牟融','唐','御定全唐诗','yuding','','[]','白雲深鎖沃州山，冠蓋登臨眾仰攀。松徑風清聞鶴唳，',40,'御定全唐詩/json/467.json','["白雲深鎖沃州山，冠蓋登臨眾仰攀。松徑風清聞鶴唳，", "興盡凡緣因未晚，裴回依舊到人間。"]'),
('yuding-41','遊報本寺','牟融','唐','御定全唐诗','yuding','','[]','山房寂寂蓽門開，此日相期社友來。雅興共尋方外樂，',80,'御定全唐詩/json/467.json','["山房寂寂蓽門開，此日相期社友來。雅興共尋方外樂，", "醉後不知明月上，狂歌直到夜深回。", "了然塵事不相關，錫杖時時獨看山。白髮任教雙鬢改，", "自笑微軀長碌碌，幾時來此學無還。"]'),
('yuding-42','題陳侯竹亭','牟融','唐','御定全唐诗','yuding','','[]','曾向幽亭一榻分，清風滿座絕塵氛。丹山鳳泣鉤簾聽，',40,'御定全唐詩/json/467.json','["曾向幽亭一榻分，清風滿座絕塵氛。丹山鳳泣鉤簾聽，", "歲寒高節誰能識，獨有王猷愛此君。"]'),
('yuding-43','送報本寺分韻得通字','牟融','唐','御定全唐诗','yuding','','[]','幾度乘閑謁梵宮，此郎聲價重江東。貴侯知重曾忘勢，',40,'御定全唐詩/json/467.json','["幾度乘閑謁梵宮，此郎聲價重江東。貴侯知重曾忘勢，", "□□□□□□□，□□□□□□□。"]'),
('yuding-44','寄永平友人','牟融','唐','御定全唐诗','yuding','','[]','故人千里隔天涯，幾度臨風動遠思。賈誼上書曾伏闕，',80,'御定全唐詩/json/467.json','["故人千里隔天涯，幾度臨風動遠思。賈誼上書曾伏闕，", "何日歸來話疇昔，一樽重敘舊襟期。", "朔風獵獵慘寒沙，關月寥寥咽暮笳。放逐一心終去國，", "直道未容淹屈久，暫勞蹤跡寄天涯。"]'),
('yuding-45','陳使君山莊','牟融','唐','御定全唐诗','yuding','','[]','新蔔幽居地自偏，士林爭羨使君賢。數椽瀟灑臨溪屋，',40,'御定全唐詩/json/467.json','["新蔔幽居地自偏，士林爭羨使君賢。數椽瀟灑臨溪屋，", "秋成准擬重來此，沉醉何妨一榻眠。"]'),
('yuding-46','題寺壁','牟融','唐','御定全唐诗','yuding','','[]','僧家勝景瞰平川，霧重嵐深馬不前。宛轉數聲花外鳥，',40,'御定全唐詩/json/467.json','["僧家勝景瞰平川，霧重嵐深馬不前。宛轉數聲花外鳥，", "聞道此中堪遁跡，肯容一榻學逃禪。"]'),
('yuding-47','送徐浩','牟融','唐','御定全唐诗','yuding','','[]','渡口潮平促去舟，莫辭尊酒暫相留。弟兄聚散雲邊雁，',40,'御定全唐詩/json/467.json','["渡口潮平促去舟，莫辭尊酒暫相留。弟兄聚散雲邊雁，", "知君此去情偏切，堂上椿萱雪滿頭。"]'),
('yuding-48','謝惠劍','牟融','唐','御定全唐诗','yuding','','[]','感君三尺鐵，揮攉鬼神驚。浩氣中心發，雄風兩腋生。',48,'御定全唐詩/json/467.json','["感君三尺鐵，揮攉鬼神驚。浩氣中心發，雄風兩腋生。", "犬戎從此滅，巢穴不時平。萬里橫行去，封侯賴有成。"]'),
('yuding-49','送僧','牟融','唐','御定全唐诗','yuding','','[]','梵王生別思，之子事遐征。煙水浮杯渡，雲山只履行。',48,'御定全唐詩/json/467.json','["梵王生別思，之子事遐征。煙水浮杯渡，雲山只履行。", "三生塵夢醒，一錫衲衣輕。此去家林近，飄飄物外情。"]'),
('yuding-50','送友人','牟融','唐','御定全唐诗','yuding','','[]','有客棹扁舟，相逢不暫留。衣冠重文物，詩酒足風流。',48,'御定全唐詩/json/467.json','["有客棹扁舟，相逢不暫留。衣冠重文物，詩酒足風流。", "官路生歸興，家林想舊遊。臨岐分手後，乘月過蘇州。"]'),
('yuding-51','題朱慶餘閒居四首','牟融','唐','御定全唐诗','yuding','','[]','瀟灑藏修處，琴書與畫圖。白丁門外遠，俗子眼前無。',192,'御定全唐詩/json/467.json','["瀟灑藏修處，琴書與畫圖。白丁門外遠，俗子眼前無。", "楚楚臨軒竹，青青映水蒲。道人能愛靜，諸事近清枯。", "盡日衡門閉，蒼苔一徑新。客心非厭靜，悟道不憂貧。", "白屋懸塵榻，清樽憶故人。近來疏懶甚，詩債後吟身。", "閑客幽棲處，瀟然一草廬。路通元亮宅，門對子雲居。", "按劍心猶壯，琴書樂有餘。黃金都散盡，收得鄴侯書。", "寂寥荒館下，投老欲何為。草色凝陳榻，書聲出董帷。", "閑雲長作伴，歸鶴獨相隨。才薄知無用，安貧不自危。"]'),
('yuding-52','寄張源','牟融','唐','御定全唐诗','yuding','','[]','咫尺西江路，悲歡暫莫聞。青年俱未達，白社獨離群。',48,'御定全唐詩/json/467.json','["咫尺西江路，悲歡暫莫聞。青年俱未達，白社獨離群。", "曲徑荒秋草，衡茅掩夕曛。相思不相見，愁絕賦停雲。"]'),
('yuding-53','題竹','牟融','唐','御定全唐诗','yuding','','[]','瀟灑碧玉枝，清風追晉賢。數點渭川雨，一縷湘江煙。',48,'御定全唐詩/json/467.json','["瀟灑碧玉枝，清風追晉賢。數點渭川雨，一縷湘江煙。", "不見鳳凰尾，誰識珊瑚鞭。柯亭丁相遇，驚聽奏鈞天。"]'),
('yuding-54','有感','牟融','唐','御定全唐诗','yuding','','[]','盛世嗟沉伏，中情怏未舒。途窮悲阮籍，病久憶相如。',48,'御定全唐詩/json/467.json','["盛世嗟沉伏，中情怏未舒。途窮悲阮籍，病久憶相如。", "無客空塵榻，閑門閉草廬。不勝岑絕處，高臥半床書。"]'),
('yuding-55','題山房壁','牟融','唐','御定全唐诗','yuding','','[]','珠林春寂寂，寶地夜沉沉。玄奧凝神久，禪機入妙深。',48,'御定全唐詩/json/467.json','["珠林春寂寂，寶地夜沉沉。玄奧凝神久，禪機入妙深。", "參同大塊理，窺測至人心。定處波羅蜜，須從物外尋。"]'),
('yuding-56','訪請上人','牟融','唐','御定全唐诗','yuding','','[]','曲徑繞叢林，鐘聲雜梵音。松風吹定衲，蘿月照禪心。',48,'御定全唐詩/json/467.json','["曲徑繞叢林，鐘聲雜梵音。松風吹定衲，蘿月照禪心。", "撫景吟行遠，談玄入悟深。不能塵鞅脫，聊複一登臨。"]'),
('yuding-57','送範啟東','牟融','唐','御定全唐诗','yuding','','[]','楊柳春江上，東風一棹輕。行囊歸客興，尊酒故人情。',48,'御定全唐詩/json/467.json','["楊柳春江上，東風一棹輕。行囊歸客興，尊酒故人情。", "畫史名當代，聲華重兩京。臨岐分手處，無奈別離生。"]'),
('yuding-58','客中作','牟融','唐','御定全唐诗','yuding','','[]','十年江漢客，幾度帝京遊。跡比風前葉，身如水上鷗。',48,'御定全唐詩/json/467.json','["十年江漢客，幾度帝京遊。跡比風前葉，身如水上鷗。", "醉吟愁裏月，羞對鏡中秋。悵望頻回首，西風憶故丘。"]'),
('yuding-59','贈韓翃','牟融','唐','御定全唐诗','yuding','','[]','京國久知名，江河近識荊。不辭今日醉，便有故人情。',48,'御定全唐詩/json/467.json','["京國久知名，江河近識荊。不辭今日醉，便有故人情。", "細雨孤鴻遠，西風一棹輕。暫時分手去，應不負詩盟。"]'),
('yuding-60','禁煙作','牟融','唐','御定全唐诗','yuding','','[]','柳拖金縷拂朱欄，花撲香塵滿繡鞍。',32,'御定全唐詩/json/467.json','["柳拖金縷拂朱欄，花撲香塵滿繡鞍。", "尊酒臨風酬令節，越羅衣薄覺春寒。"]'),
('yuding-61','閩中回','牟融','唐','御定全唐诗','yuding','','[]','帆影隨風過富陽，櫓聲搖月下錢塘。',32,'御定全唐詩/json/467.json','["帆影隨風過富陽，櫓聲搖月下錢塘。", "千山積雪凝寒碧，夢入楓宸繞禦床。"]'),
('yuding-0','苦婦詞','劉言史','唐','御定全唐诗','yuding','','[]','地遠易驕崇，用刑匪精研。哀哉苦婦身，夫死百殃纏。',216,'御定全唐詩/json/468.json','["地遠易驕崇，用刑匪精研。哀哉苦婦身，夫死百殃纏。", "草草催出門，衣墮發披肩。獨隨軍吏行，當夕餘欲遷。", "來時已厭生，到此自不全。臨江臥黃砂，二子死在邊。", "氣噦不發聲，背頭血涓涓。有時強為言，只是尤青天。", "稿蓐無一枝，冷氣兩懸懸。窮荒夷教卑，骨肉病棄捐。", "況非本族音，肌露誰為憐。事痛感行賓，住得貪程船。", "必當負嚴法，豈有胎孕篇。遊畋複釋麛，羔兔尚免鸇。", "何處擯逐深，一罪三見顛。校尉勳望重，幕府才且賢。", "蘭裙間珠履，食玉處花筵。但勿輕所暗，莫慮無人焉。"]'),
('yuding-1','與孟郊洛北野泉上煎茶','劉言史','唐','御定全唐诗','yuding','','[]','粉細越筍芽，野煎寒溪濱。恐乖靈草性，觸事皆手親。',108,'御定全唐詩/json/468.json','["粉細越筍芽，野煎寒溪濱。恐乖靈草性，觸事皆手親。", "敲石取鮮火，撇泉避腥鱗。熒熒爨風鐺，拾得墜巢薪。", "潔色既爽別，浮氳亦殷勤。以茲委曲靜，求得正味真。", "宛如摘山時，自歠指下春。湘瓷泛輕花，滌盡昏渴神。", "此遊愜醒趣，可以話高人。"]'),
('yuding-2','七夕歌','劉言史','唐','御定全唐诗','yuding','','[]','星寥寥兮月細輪，佳期可想兮不可親。雲衣香薄妝態新，',49,'御定全唐詩/json/468.json','["星寥寥兮月細輪，佳期可想兮不可親。雲衣香薄妝態新，", "寂寞低容入舊機，歇著金梭思往夕。人間不見因誰知，"]'),
('yuding-3','立秋日','劉言史','唐','御定全唐诗','yuding','','[]','商風動葉初，蕭索一貧居。老性容茶少，羸肌與簟疏。',48,'御定全唐詩/json/468.json','["商風動葉初，蕭索一貧居。老性容茶少，羸肌與簟疏。", "舊醅難重漉，新菜未勝鉏。才薄無潘興，便便畫偃廬。"]'),
('yuding-4','題茅山仙台藥院','劉言史','唐','御定全唐诗','yuding','','[]','擾擾浮生外，華陽一洞春。道書金字小，仙圃玉苗新。',60,'御定全唐詩/json/468.json','["擾擾浮生外，華陽一洞春。道書金字小，仙圃玉苗新。", "芝草迎飛燕，桃花笑俗人。樓臺爭聳漢，雞犬亦嫌秦。", "願得青芽散，長年駐此身。"]'),
('yuding-5','送婆羅門歸本國','劉言史','唐','御定全唐诗','yuding','','[]','刹利王孫字迦攝，竹錐橫寫叱蘿葉。遙知漢地未有經，',64,'御定全唐詩/json/468.json','["刹利王孫字迦攝，竹錐橫寫叱蘿葉。遙知漢地未有經，", "地盡年深始到船，海裏更行三十國。行多耳斷金環落，", "出漠獨行人絕處，磧西天漏雨絲絲。"]'),
('yuding-6','瀟湘游','劉言史','唐','御定全唐诗','yuding','','[]','夷女采山蕉，緝紗浸江水。野花滿髻妝色新，',68,'御定全唐詩/json/468.json','["夷女采山蕉，緝紗浸江水。野花滿髻妝色新，", "翠華寂寞嬋娟沒，野筱空餘紅淚情。青煙冥冥覆杉桂，", "清猿未盡鼯鼠切，淚水流到湘妃祠。北人莫作瀟湘遊，"]'),
('yuding-7','放螢怨','劉言史','唐','御定全唐诗','yuding','','[]','放螢去，不須留，聚時年少今白頭。架中科鬥萬餘卷，',48,'御定全唐詩/json/468.json','["放螢去，不須留，聚時年少今白頭。架中科鬥萬餘卷，", "且逍遙，還酩酊，仲舒漫不窺園井。那將寂寞老病身，"]'),
('yuding-8','觀繩伎','劉言史','唐','御定全唐诗','yuding','','[]','泰陵遺樂何最珍，彩繩冉冉天仙人。廣場寒食風日好，',72,'御定全唐詩/json/468.json','["泰陵遺樂何最珍，彩繩冉冉天仙人。廣場寒食風日好，", "重肩接立三四層，著屐背行仍應節。兩邊丸劍漸相迎，", "危機險勢無不有，倒掛纖腰學垂柳。下來一一芙蓉姿，"]'),
('yuding-9','買花謠','劉言史','唐','御定全唐诗','yuding','','[]','杜陵村人不田穡，入穀經溪複緣壁。每至南山草木春，',72,'御定全唐詩/json/468.json','["杜陵村人不田穡，入穀經溪複緣壁。每至南山草木春，", "蝶惜芳叢送下山，尋斷孤香始回去。豪少居連鳷鵲東，", "咸陽親戚長安裏，無限將金買花子。澆紅濕綠千萬家，"]'),
('yuding-10','王中丞宅夜觀舞胡騰','劉言史','唐','御定全唐诗','yuding','','[]','石國胡兒人見少，蹲舞尊前急如鳥。織成蕃帽虛頂尖，',64,'御定全唐詩/json/468.json','["石國胡兒人見少，蹲舞尊前急如鳥。織成蕃帽虛頂尖，", "跳身轉轂寶帶鳴，弄腳繽紛錦靴軟。四座無言皆瞪目，", "酒闌舞罷絲管絕，木槿花西見殘月。"]'),
('yuding-11','竹裏梅','劉言史','唐','御定全唐诗','yuding','','[]','竹裏梅花相並枝，梅花正發竹枝垂。',32,'御定全唐詩/json/468.json','["竹裏梅花相並枝，梅花正發竹枝垂。", "風吹總向竹枝上，直似王家雪下時。"]'),
('yuding-12','春過趙墟','劉言史','唐','御定全唐诗','yuding','','[]','下馬邯鄲陌頭歇，寂寥崩隧臨車轍。古柏重生枝亦幹，',24,'御定全唐詩/json/468.json','["下馬邯鄲陌頭歇，寂寥崩隧臨車轍。古柏重生枝亦幹，"]'),
('yuding-13','初下東周贈孟郊','劉言史','唐','御定全唐诗','yuding','','[]','鶴老身更b3，龜死殼亦靈。正信非外沿，終始全本情。',193,'御定全唐詩/json/468.json','["鶴老身更b3，龜死殼亦靈。正信非外沿，終始全本情。", "童子不戲塵，積書就岩扃。身著木葉衣，養鹿兼牸耕。", "偶隨下山雲，荏苒失故程。漸入機險中，危思難太行。", "十發九縷絲，悠然東周城。言詞野麋態，出口多累形。", "因依漢元寮，未似羈細輕。冷灶助新熱，靜砧與寒聲。", "斷蓬在門欄，豈當桃李榮。寄食若蠹蟲，侵損利微生。", "固非拙為強，懦劣外療並。素堅冰蘖心，潔持保堅貞。", "修文返正風，刊字齊古經。慚將衰末分，高棲喧世名。"]'),
('yuding-14','過春秋峽','劉言史','唐','御定全唐诗','yuding','','[]','峭壁蒼蒼苔色新，無風晴景自勝春。',32,'御定全唐詩/json/468.json','["峭壁蒼蒼苔色新，無風晴景自勝春。", "不知何樹幽崖裏，臘月開花似北人。"]'),
('yuding-15','長門怨','劉言史','唐','御定全唐诗','yuding','','[]','獨坐爐邊結夜愁，暫時思去亦難留。',32,'御定全唐詩/json/468.json','["獨坐爐邊結夜愁，暫時思去亦難留。", "手持金箸垂紅淚，亂撥寒灰不舉頭。"]'),
('yuding-16','春遊曲','劉言史','唐','御定全唐诗','yuding','','[]','花頷紅鬃一何偏，綠槐香陌欲朝天。',64,'御定全唐詩/json/468.json','["花頷紅鬃一何偏，綠槐香陌欲朝天。", "仍嫌眾裏嬌行疾，傍鐙深藏白玉鞭。", "噴沫團香小桂條，玉鞭兼賜霍嫖姚。", "弄影便從天禁出，碧蹄聲碎五門橋。"]'),
('yuding-17','廣州王園寺伏日即事寄北中親友','劉言史','唐','御定全唐诗','yuding','','[]','南越逢初伏，東林度一朝。曲池煎畏景，高閣絕微飆。',120,'御定全唐詩/json/468.json','["南越逢初伏，東林度一朝。曲池煎畏景，高閣絕微飆。", "竹簟移先灑，蒲葵破複搖。地偏毛瘴近，山毒火威饒。", "裛汗絺如濯，親床枕並燒。墜枝傷翠羽，萎葉惜紅蕉。", "且困流金熾，難成獨酌謠。望霖窺潤礎，思吹候生條。", "旅恨生烏滸，鄉心系洛橋。誰憐在炎客，一夕壯容銷。"]'),
('yuding-18','立秋','劉言史','唐','御定全唐诗','yuding','','[]','茲晨戒流火，商飆早已驚。雲天收夏色，木葉動秋聲。',24,'御定全唐詩/json/468.json','["茲晨戒流火，商飆早已驚。雲天收夏色，木葉動秋聲。"]'),
('yuding-19','別落花','劉言史','唐','御定全唐诗','yuding','','[]','風豔霏霏去，羈人處處遊。明年縱相見，不在此枝頭。',24,'御定全唐詩/json/468.json','["風豔霏霏去，羈人處處遊。明年縱相見，不在此枝頭。"]'),
('yuding-20','登甘露台','劉言史','唐','御定全唐诗','yuding','','[]','偶至無塵空翠間，雨花甘露境閑閑。',32,'御定全唐詩/json/468.json','["偶至無塵空翠間，雨花甘露境閑閑。", "身心未寂終為累，非想天中獨退還。"]'),
('yuding-21','夜泊潤州江口','劉言史','唐','御定全唐诗','yuding','','[]','秋江欲起白頭波，賈客瞻風無渡河。',32,'御定全唐詩/json/468.json','["秋江欲起白頭波，賈客瞻風無渡河。", "千船火絕寒宵半，獨聽鐘聲覺寺多。"]'),
('yuding-22','看山木瓜花二首','劉言史','唐','御定全唐诗','yuding','','[]','裛露凝氛紫豔新，千般婉娜不勝春。',64,'御定全唐詩/json/468.json','["裛露凝氛紫豔新，千般婉娜不勝春。", "年年此樹花開日，出盡丹陽郭裏人。", "柔枝濕豔亞朱欄，暫作庭芳便欲殘。", "深藏數片將歸去，紅縷金針繡取看。"]'),
('yuding-23','題十三弟竹園','劉言史','唐','御定全唐诗','yuding','','[]','繞屋扶疏聳翠莖，苔滋粉漾有幽情。',32,'御定全唐詩/json/468.json','["繞屋扶疏聳翠莖，苔滋粉漾有幽情。", "丹陽萬戶春光靜，獨自君家秋雨聲。"]'),
('yuding-24','樂府雜詞三首','劉言史','唐','御定全唐诗','yuding','','[]','紫禁梨花飛雪毛，春風絲管翠樓高。',96,'御定全唐詩/json/468.json','["紫禁梨花飛雪毛，春風絲管翠樓高。", "城裏萬家聞不見，君王試舞鄭櫻桃。", "蟬鬢紅冠粉黛輕，雲和新教羽衣成。", "月光如雪金階上，迸卻頗梨義甲聲。", "不耐簷前紅槿枝，薄妝春寢覺仍遲。", "夢中無限風流事，夫婿多情亦未知。"]'),
('yuding-25','歲暮題楊錄事江亭','劉言史','唐','御定全唐诗','yuding','','[]','垂絲蜀客涕濡衣，歲盡長沙未得歸。',32,'御定全唐詩/json/468.json','["垂絲蜀客涕濡衣，歲盡長沙未得歸。", "腸斷錦帆風日好，可憐桐鳥出花飛。"]'),
('yuding-26','冬日峽中旅泊','劉言史','唐','御定全唐诗','yuding','','[]','霜月明明雪複殘，孤舟夜泊使君灘。',32,'御定全唐詩/json/468.json','["霜月明明雪複殘，孤舟夜泊使君灘。", "一聲鐘出遠山裏，暗想雪窗僧起寒。"]'),
('yuding-27','泊花石浦','劉言史','唐','御定全唐诗','yuding','','[]','舊業叢台廢苑東，幾年為梗複為蓬。',32,'御定全唐詩/json/468.json','["舊業叢台廢苑東，幾年為梗複為蓬。", "杜鵑啼斷回家夢，半在邯鄲驛樹中。"]'),
('yuding-28','聞崔倚旅葬','劉言史','唐','御定全唐诗','yuding','','[]','遠客那能返故廬，蒼梧埋骨痛何如。',32,'御定全唐詩/json/468.json','["遠客那能返故廬，蒼梧埋骨痛何如。", "他時親戚空相憶，席上同悲一紙書。"]'),
('yuding-29','賦蕃子牧馬','劉言史','唐','御定全唐诗','yuding','','[]','磧淨山高見極邊，孤烽引上一條煙。',32,'御定全唐詩/json/468.json','["磧淨山高見極邊，孤烽引上一條煙。", "蕃落多晴塵擾擾，天軍獵到鸊鵜泉。"]'),
('yuding-30','牧馬泉','劉言史','唐','御定全唐诗','yuding','','[]','平沙漫漫馬悠悠，弓箭閑拋郊水頭。',32,'御定全唐詩/json/468.json','["平沙漫漫馬悠悠，弓箭閑拋郊水頭。", "鼠毛衣裏取羌笛，吹向秋天眉眼愁。"]');
